// ─── Session 382 Phase 2 — Avatar Glow-Up Studio ───
// Two endpoints under /api/glowup:
//   POST /api/glowup/generate     — vibe + (optional) username → asset pack
//                                   (shirt.png, pants.png, decal.png, preview.png)
//                                   stored in Firebase Storage with 7-day signed
//                                   URLs. Requires Firebase auth (req.userId).
//   POST /api/glowup/upload-decal — push a decal PNG to the user's Roblox
//                                   account via OAuth Open Cloud assets API.
//                                   Returns { assetId }. Requires OAuth scope
//                                   asset:write (already in our scope list).

function parseGender(raw: unknown): GlowupGender {
  if (raw === 'boys' || raw === 'girls' || raw === 'neutral') return raw;
  return 'neutral';
}
function parseIntensity(raw: unknown): GlowupIntensity {
  if (raw === 'scary' || raw === 'clean') return raw;
  return 'clean';
}

app.post('/api/glowup/generate', async (req: AuthedRequest, res) => {
  const firebaseUid = req.userId;
  const generationId = mintGlowupGenerationId();
  let resolvedVibeId: GlowupVibeId | undefined;
  try {
    const body = (req.body ?? {}) as {
      vibeId?: unknown;
      gender?: unknown;
      intensity?: unknown;
      robloxUsername?: unknown;
      autoUploadDecal?: unknown;
    };
    if (!isGlowupVibeId(body.vibeId)) {
      return res.status(400).json({ error: 'Invalid or missing vibeId', generationId });
    }
    resolvedVibeId = body.vibeId;
    if (!firebaseUid) {
      return res.status(401).json({ error: 'Authentication required', generationId });
    }

    // Per-IP cooldown (defense vs TikTok-raid / scraper / bot pointing at
    // a single endpoint). Distinct from the per-firebaseUid Firestore limit.
    const clientIp = extractClientIp(req);
    const ipVerdict = checkIpRateLimit(clientIp, '/glowup/generate');
    if (!ipVerdict.allowed) {
      return res.status(429).json({
        error: 'ip_rate_limited',
        retryAfterMs: ipVerdict.retryAfterMs,
        generationId,
      });
    }

    const gender = parseGender(body.gender);
    const intensity = parseIntensity(body.intensity);

    // Rate limit BEFORE we spend any provider $ or Storage writes.
    const verdict = await checkAndConsumeGlowupRateLimit(firebaseUid);
    if (!verdict.allowed) {
      return res.status(429).json({
        error: 'rate_limited',
        reason: verdict.reason,
        retryAfterMs: verdict.retryAfterMs,
        hourlyRemaining: verdict.hourlyRemaining,
        dailyRemaining: verdict.dailyRemaining,
      });
    }

    recordGlowupEvent({
      type: 'generation_started',
      firebaseUid,
      vibeId: body.vibeId,
      gender,
      intensity,
    });

    // Resolve robloxUserId: prefer OAuth-connected userId, else look up by username.
    let robloxUserId: string | undefined;
    try {
      const tok = await getRobloxUserToken(firebaseUid);
      if (tok?.robloxUserId) robloxUserId = tok.robloxUserId;
    } catch (err) {
      logger.warn('[glowup] OAuth token lookup non-fatal', err);
    }
    if (!robloxUserId && typeof body.robloxUsername === 'string') {
      const resolved = await resolveRobloxUsername(body.robloxUsername);
      if (resolved) robloxUserId = resolved.robloxUserId;
    }

    // Cache lookup. Hit → skip flux-pro + sharp + 4 Storage uploads entirely.
    const cacheKey = computeGlowupCacheKey({ vibeId: body.vibeId, gender, intensity, robloxUserId });
    const cached = await getCachedGlowup(cacheKey);
    let result: GlowupGenerateResult;
    if (cached) {
      result = cached;
      recordGlowupEvent({
        type: 'generation_cached',
        firebaseUid,
        vibeId: body.vibeId,
        gender,
        intensity,
        fitOnUser: cached.fitOnUser,
      });
    } else {
      result = await generateGlowup({
        vibeId: body.vibeId,
        gender,
        intensity,
        robloxUserId,
        firebaseUid,
      });
      // Fire-and-forget cache write (don't block response on it).
      void setCachedGlowup({ key: cacheKey, result, firebaseUid, vibeId: body.vibeId });
      recordGlowupEvent({
        type: 'generation_success',
        firebaseUid,
        vibeId: body.vibeId,
        gender,
        intensity,
        fitOnUser: result.fitOnUser,
      });
    }

    // Optional inline decal upload — best-effort, doesn't fail the response.
    let decalAssetId: string | undefined;
    if (body.autoUploadDecal === true) {
      try {
        const decalResp = await fetch(result.assetPack.decalUrl, { signal: AbortSignal.timeout(15_000) });
        if (decalResp.ok) {
          const ab = await decalResp.arrayBuffer();
          const upload = await uploadDecalForUser({
            firebaseUid,
            pngBuffer: Buffer.from(ab),
            displayName: `${result.title} Glow-Up`,
            description: `${result.pitch} — Generated via Kami Gold AI.`,
          });
          decalAssetId = upload.assetId;
          recordGlowupEvent({ type: 'upload_success', firebaseUid, vibeId: body.vibeId, meta: { inline: true } });
        }
      } catch (err) {
        if (err instanceof DecalUploadNotConnectedError) {
          logger.info('[glowup] autoUploadDecal skipped — Roblox not connected', { firebaseUid });
        } else {
          logger.warn('[glowup] inline decal upload failed (non-fatal)', err);
          recordGlowupEvent({
            type: 'upload_failed',
            firebaseUid,
            vibeId: body.vibeId,
            errorCode: err instanceof Error ? err.message.slice(0, 200) : 'unknown',
            meta: { inline: true },
          });
        }
      }
    }

    // Persist generation by ID (best-effort) for retry-by-ID + abuse logs.
    void persistGlowupGeneration({
      generationId,
      firebaseUid,
      vibeId: body.vibeId,
      gender,
      intensity,
      robloxUserId,
      fromCache: !!cached,
      result,
      decalAssetId,
      status: 'ready',
      createdAtMs: Date.now(),
    });

    return res.json({
      ...result,
      generationId,
      generationStatus: 'ready' as const,
      decalAssetId,
      cached: !!cached,
      rateLimit: {
        hourlyRemaining: verdict.hourlyRemaining,
        dailyRemaining: verdict.dailyRemaining,
        ipRemaining: ipVerdict.remaining,
      },
    });
  } catch (err) {
    logger.error('[glowup] generate failed', { generationId, err });
    if (firebaseUid) {
      recordGlowupEvent({
        type: 'generation_failed',
        firebaseUid,
        vibeId: resolvedVibeId,
        errorCode: err instanceof Error ? err.message.slice(0, 200) : 'unknown',
        meta: { generationId },
      });
    }
    return res.status(500).json({
      error: 'Failed to generate glow-up',
      generationId,
      generationStatus: 'failed' as const,
    });
  }
});

// Retrieve a previously persisted generation by its short ID. Lets the iOS
// app re-fetch an old result without rerunning the pipeline (cheap, no
// flux-pro / Storage / Roblox API hit). Returns 404 if not found, 403 if
// the caller is not the original owner.
app.get('/api/glowup/generations/:id', async (req: AuthedRequest, res) => {
  try {
    const firebaseUid = req.userId;
    if (!firebaseUid) return res.status(401).json({ error: 'Authentication required' });
    const id = req.params.id;
    if (!isGlowupGenerationId(id)) return res.status(400).json({ error: 'Invalid generationId' });
    const doc = await fetchPersistedGeneration(id);
    if (!doc) return res.status(404).json({ error: 'not_found' });
    if (doc.firebaseUid !== firebaseUid) return res.status(403).json({ error: 'forbidden' });
    return res.json({
      ...doc.result,
      generationId: doc.generationId,
      generationStatus: doc.status,
      decalAssetId: doc.decalAssetId,
      cached: true,
    });
  } catch (err) {
    logger.error('[glowup] fetch by id failed', err);
    return res.status(500).json({ error: 'Failed to fetch generation' });
  }
});

// Client-fired analytics events (vibe_selected, share_clicked, upload_clicked).
// Server-fired events are emitted directly from /generate and /upload-decal.
app.post('/api/glowup/event', async (req: AuthedRequest, res) => {
  try {
    const firebaseUid = req.userId;
    if (!firebaseUid) return res.status(401).json({ error: 'Authentication required' });
    // Per-IP cooldown lets analytics events flow at 10/min — plenty for
    // organic taps; blocks bots looking to fill the events collection.
    const ipVerdict = checkIpRateLimit(extractClientIp(req), '/glowup/event');
    if (!ipVerdict.allowed) {
      return res.status(429).json({ error: 'ip_rate_limited', retryAfterMs: ipVerdict.retryAfterMs });
    }
    const body = (req.body ?? {}) as { type?: unknown; vibeId?: unknown; meta?: unknown };
    const type = parseGlowupEventType(body.type);
    if (!type) return res.status(400).json({ error: 'Invalid event type' });
    recordGlowupEvent({
      type,
      firebaseUid,
      vibeId: typeof body.vibeId === 'string' ? body.vibeId : undefined,
      meta: typeof body.meta === 'object' && body.meta !== null
        ? body.meta as Record<string, string | number | boolean | null>
        : undefined,
    });
    return res.json({ recorded: true });
  } catch (err) {
    logger.warn('[glowup] event endpoint error (non-fatal)', err);
    return res.status(200).json({ recorded: false });  // never fail client on analytics
  }
});

app.post('/api/glowup/upload-decal', async (req: AuthedRequest, res) => {
  try {
    const firebaseUid = req.userId;
    if (!firebaseUid) return res.status(401).json({ error: 'Authentication required' });
    const ipVerdict = checkIpRateLimit(extractClientIp(req), '/glowup/upload-decal');
    if (!ipVerdict.allowed) {
      return res.status(429).json({ error: 'ip_rate_limited', retryAfterMs: ipVerdict.retryAfterMs });
    }
    const body = (req.body ?? {}) as { decalUrl?: unknown; displayName?: unknown };
    if (typeof body.decalUrl !== 'string') {
      return res.status(400).json({ error: 'Missing decalUrl' });
    }
    const displayName = typeof body.displayName === 'string' ? body.displayName : 'Kami Gold Glow-Up Decal';
    const dl = await fetch(body.decalUrl, { signal: AbortSignal.timeout(15_000) });
    if (!dl.ok) return res.status(400).json({ error: `Failed to fetch decalUrl: HTTP ${dl.status}` });
    const ab = await dl.arrayBuffer();
    const upload = await uploadDecalForUser({
      firebaseUid,
      pngBuffer: Buffer.from(ab),
      displayName,
    });
    recordGlowupEvent({ type: 'upload_success', firebaseUid, meta: { inline: false } });
    return res.json(upload);
  } catch (err) {
    if (err instanceof DecalUploadNotConnectedError) {
      if (req.userId) {
        recordGlowupEvent({ type: 'upload_failed', firebaseUid: req.userId, errorCode: 'not_connected', meta: { inline: false } });
      }
      return res.status(409).json({ error: 'roblox_not_connected', message: 'Connect Roblox via OAuth first.' });
    }
    logger.error('[glowup] decal upload failed', err);
    if (req.userId) {
      recordGlowupEvent({
        type: 'upload_failed',
        firebaseUid: req.userId,
        errorCode: err instanceof Error ? err.message.slice(0, 200) : 'unknown',
        meta: { inline: false },
      });
    }
    return res.status(500).json({ error: 'Failed to upload decal' });
  }
});

