app.put('/api/chat/threads/:threadId', async (req: AuthedRequest, res) => {
  try {
    const threadId = req.params.threadId;
    const title = (req.body as { title?: string })?.title?.trim();

    if (!title || title.length === 0) {
      return res.status(400).json({ error: 'Title is required' });
    }
    if (title.length > 120) {
      return res.status(400).json({ error: 'Title must be 120 characters or fewer' });
    }

    const threadRef = db.collection('threads').doc(threadId);
    const threadDoc = await threadRef.get();

    if (!threadDoc.exists || threadDoc.data()?.userId !== req.userId) {
      return res.status(404).json({ error: 'Thread not found' });
    }

    await threadRef.update({ title, updatedAt: FieldValue.serverTimestamp() });

    res.json({ id: threadId, title });
  } catch (error) {
    logger.error('Rename thread failed', error);
    res.status(500).json({ error: errorMessage(error) });
  }
});

app.get('/api/chat/threads/:threadId/messages', async (req: AuthedRequest, res) => {
  try {
    const threadId = req.params.threadId;
    const threadRef = db.collection('threads').doc(threadId);
    const threadDoc = await threadRef.get();
    if (!threadDoc.exists || threadDoc.data()?.userId !== req.userId) {
      return res.status(404).json({ error: 'Thread not found' });
    }

    const limit = Math.min(Number(req.query.limit) || 200, 500);
    const before = typeof req.query.before === 'string' ? req.query.before : undefined;

    let query: FirebaseFirestore.Query = threadRef.collection('messages');
    if (before) {
      query = query.orderBy('createdAt', 'desc').startAfter(before).limit(limit + 1);
    } else {
      query = query.orderBy('createdAt', 'desc').limit(limit + 1);
    }
    const messagesSnap = await query.get();
    const docs = messagesSnap.docs;
    const hasMore = docs.length > limit;
    const pageDocs = hasMore ? docs.slice(0, limit) : docs;
    pageDocs.reverse();

    const messages = pageDocs.map((doc) => {
      const data = doc.data();
      return {
        id: doc.id,
        role: data.role,
        content: data.content,
        quickReplies: data.quickReplies ?? null,
        gddRows: data.gddRows ?? null,
        createdAt: timestampToIso(data.createdAt),
      };
    });

    const threadData = threadDoc.data() ?? {};
    const projectMemory = threadProjectMemoryResponse(threadData);
    res.json({
      messages,
      hasMore,
      oldestCursor: messages.length > 0 ? messages[0].createdAt : undefined,
      interviewTurn: threadData.interviewTurn ?? 0,
      lastAction: threadData.lastAction ?? null,
      projectMemory,
    });
  } catch (error) {
    logger.error('Fetch thread messages failed', error);
    res.status(500).json({ error: errorMessage(error) });
  }
});

app.post('/api/chat/threads/:threadId/messages', async (req: AuthedRequest, res) => {
  try {
    const body = req.body as ChatTurnRequest | undefined;
    const threadId = req.params.threadId;
    const messageText = body?.message?.trim() || body?.quickReply?.trim();

    if (!messageText) {
      return res.status(400).json({ error: 'Message is required' });
    }

    const moderation = await runModerationPipeline({
      userId: req.userId ?? 'unknown-user',
      text: messageText,
      stage: 'input',
      metadata: body?.metadata as Record<string, unknown> | undefined,
    });
    if (!moderation.allowed) {
      return res.status(400).json({ error: moderation.reason, moderation });
    }

    const safeMessageText = moderation.rewrittenText?.trim() || messageText;

    const threadRef = db.collection('threads').doc(threadId);
    const reqProjectKind = typeof body?.metadata?.projectKind === 'string' ? body.metadata.projectKind : undefined;
    const reqContentSubcategory = typeof body?.metadata?.contentSubcategory === 'string' ? body.metadata.contentSubcategory : undefined;
    await ensureThread(threadRef, req.userId ?? 'unknown-user', safeMessageText, reqProjectKind, reqContentSubcategory);

    const threadDoc = await threadRef.get();
    let threadData = threadDoc.data() ?? {};
    const memoryReset = isStartOverRequest(safeMessageText);
    if (memoryReset) {
      await threadRef.set({
        projectMemory: FieldValue.delete(),
        latestJobId: FieldValue.delete(),
        latestArtifactIds: FieldValue.delete(),
        contentSubcategory: reqContentSubcategory ?? FieldValue.delete(),
        updatedAt: FieldValue.serverTimestamp(),
        interviewTurn: 0,
        lastAction: null,
      }, { merge: true });
      threadData = { ...threadData, projectMemory: undefined, latestJobId: undefined, contentSubcategory: reqContentSubcategory, interviewTurn: 0 };
    }
    const existingProjectMemory = memoryReset ? undefined : normalizeProjectMemory(threadData.projectMemory);
    let interviewTurn: number = typeof threadData.interviewTurn === 'number' ? threadData.interviewTurn : 0;

    const userMessage = buildChatMessage('user', safeMessageText);
    await threadRef.collection('messages').doc(userMessage.id).set(userMessage);

    const recentMessages = await threadRef.collection('messages').orderBy('createdAt', 'desc').limit(16).get();
    const transcript = recentMessages.docs
      .map((doc) => doc.data() as ChatMessage)
      .reverse()
      .map((item) => {
        let line = `${item.role}: ${item.content}`;
        if (item.role === 'assistant' && item.gddRows?.length) {
          const gddSummary = item.gddRows.map((r: { key: string; value: string }) => `${r.key}: ${r.value}`).join('; ');
          line += `\n[Current GDD: ${gddSummary}]`;
        }
        return line;
      })
      .join('\n');

    const provider = (body?.provider ?? defaults.chatProvider) as AIProvider;

    // Reference image (vision) — if the user attached an image, run Gemini Vision
    // to extract a structured visual brief and inject it into the prompt so the
    // chat model can act on the actual picture, not just the metadata flag.
    const attachmentKind = typeof body?.metadata?.attachmentKind === 'string'
      ? body.metadata.attachmentKind : undefined;
    const attachmentImageUrl = typeof body?.metadata?.attachmentImageUrl === 'string'
      ? body.metadata.attachmentImageUrl : undefined;
    let referenceImageSummary: string | undefined;
    if (attachmentKind === 'image' && attachmentImageUrl) {
      try {
        referenceImageSummary = await Promise.race<string>([
          describeReferenceImage(attachmentImageUrl),
          new Promise<string>((resolve) => setTimeout(() => resolve(''), 6000)),
        ]);
      } catch (error) {
        logger.warn('describeReferenceImage threw, continuing without vision summary', error);
        referenceImageSummary = undefined;
      }
    }

    // Live Roblox catalog trends: inject only when the user asks for them.
    let trendsContext: string | undefined;
    if (detectRobloxTrendsRequest(safeMessageText, body?.metadata as Record<string, unknown> | undefined)) {
      try {
        const category: CatalogCategory = 'Featured';
        const sort: CatalogSort = 'Sales';
        const period: CatalogPeriod = 'PastWeek';
        const trends = await Promise.race<{ source: 'roblox' | 'apify'; fetchedAt: number; items: Array<{ id: number; name: string; itemType: 'Asset' | 'Bundle'; creatorName: string; price: number | null; favoriteCount: number; url: string; thumbnailUrl: string | null; creatorType: string }>; cached: boolean } | null>([
          fetchTrendingCatalog({ category, sort, period, limit: 10 }),
          new Promise((resolve) => setTimeout(() => resolve(null), 6000)),
        ]);
        if (trends && trends.items.length > 0) {
          trendsContext = formatTrendsContextForPrompt(trends, { category, sort, period });
        }
      } catch (error) {
        logger.warn('fetchTrendingCatalog threw, continuing without trends context', error);
      }
    }

    const prompt = buildChatPrompt({
      transcript,
      latestMessage: safeMessageText,
      metadata: body?.metadata,
      skipInterview: body?.skipInterview,
      interviewTurn,
      expertiseLevel: typeof body?.metadata?.expertiseLevel === 'string' ? body.metadata.expertiseLevel : undefined,
      referenceImageSummary,
      projectMemory: existingProjectMemory,
      trendsContext,
    });
    const rawResponse = await runChatProvider(
      provider,
      prompt,
      undefined,
      {
        timeoutMs: interactiveChatProviderTimeoutMs,
        providerModels: interactiveChatProviderModels,
      },
    );

    const planPayload = parseAssistantPayload(rawResponse.text, safeMessageText, body?.metadata);
    const assistantMessage = buildChatMessage(
      'assistant',
      planPayload.assistantMessage,
      planPayload.quickReplies,
      gddToRows(planPayload.gdd, body?.metadata),
    );

    const nextInterviewTurn = planPayload.action === 'interview' ? interviewTurn + 1 : interviewTurn;
    const updatedProjectMemory = memoryReset
      ? undefined
      : mergeProjectMemoryFromChat({
          existing: existingProjectMemory,
          title: planPayload.threadTitle,
          gdd: planPayload.gdd,
          gddRows: assistantMessage.gddRows,
          metadata: body?.metadata as Record<string, unknown> | undefined,
          latestMessage: safeMessageText,
        });

    await threadRef.set(
      {
        title: planPayload.threadTitle,
        promptHint: planPayload.gdd.genre,
        userId: req.userId,
        updatedAt: new Date(),
        interviewTurn: nextInterviewTurn,
        lastAction: planPayload.action,
        ...(reqProjectKind ? { projectKind: reqProjectKind } : {}),
        ...(reqContentSubcategory ? { contentSubcategory: reqContentSubcategory } : {}),
        projectMemory: updatedProjectMemory ?? FieldValue.delete(),
        latestJobId: updatedProjectMemory?.latestJobId ?? FieldValue.delete(),
      },
      { merge: true },
    );
    await threadRef.collection('messages').doc(assistantMessage.id).set(assistantMessage);

    const response: ChatTurnResponse = {
      action: planPayload.action,
      provider,
      threadTitle: planPayload.threadTitle,
      message: {
        id: assistantMessage.id,
        role: 'assistant',
        content: assistantMessage.content,
        quickReplies: assistantMessage.quickReplies,
        createdAt: assistantMessage.createdAt.toISOString(),
        gdd: planPayload.gdd,
        gddRows: assistantMessage.gddRows,
      },
      quickReplies: assistantMessage.quickReplies,
      gdd: planPayload.gdd,
      projectMemory: updatedProjectMemory,
    };

    res.json(response);
  } catch (error) {
    logger.error('Chat message failed', error);
    res.status(500).json({ error: errorMessage(error) });
  }
});

interface ViralStyleInjection {
  mode: 'cursed_room' | 'meme_item' | 'viral_content';
  hooks: string[];
  promptBlock: string;
}

function buildDefaultViralStyleInjection(prompt: string, metadata: Record<string, unknown>): ViralStyleInjection | null {
  if (metadata.disableViralStyleHooks === true || metadata.disableDefaultViralHooks === true) return null;
  const contentCategory = typeof metadata.contentCategory === 'string' ? metadata.contentCategory.toLowerCase() : '';
  const contentSubcategory = typeof metadata.contentSubcategory === 'string' ? metadata.contentSubcategory.toLowerCase() : '';
  const haystack = `${prompt} ${metadata.title ?? ''} ${metadata.genre ?? ''} ${metadata.theme ?? ''} ${metadata.style ?? ''} ${contentCategory} ${contentSubcategory}`.toLowerCase();
  if (/\b(no\s+meme|no\s+brainrot|no\s+viral|plain\s+only|minimal\s+only|clean\s+only)\b|без\s+мем|без\s+брейнрот|без\s+вирусн|только\s+минимал/.test(haystack)) {
    return null;
  }

  const isContentGeneration = [
    'item_tool',
    'map_environment',
    'building',
    'furniture_prop',
    'weapon',
    'game_system',
    'script',
  ].includes(contentCategory) || ['items', 'maps', 'buildings', 'furniture', 'weapons', 'anime_skills'].includes(contentSubcategory);
  if (!isContentGeneration) return null;

  const isCursedRoom = /\b(cursed\s+rooms?|haunted\s+rooms?|backrooms?|liminal\s+rooms?|weird\s+rooms?|horror\s+rooms?)\b|проклят[а-яё\s-]*комнат|страшн[а-яё\s-]*комнат|бекрум|закулись/i.test(haystack);
  const isItem = contentCategory === 'item_tool' || contentSubcategory === 'items';
  const mode: ViralStyleInjection['mode'] = isCursedRoom ? 'cursed_room' : isItem ? 'meme_item' : 'viral_content';
  const hooks = mode === 'cursed_room'
    ? ['weird colored lighting', 'ambient brainrot/meme sound cue', 'glitch particles/fog', 'reaction-bait room signage']
    : mode === 'meme_item'
      ? ['brainrot sound pop', 'strange glow/aura', 'meme effect text', 'emotion-first use feedback']
      : ['unexpected lighting accent', 'short meme/brainrot audio cue', 'visible particle burst', 'reaction-bait detail'];

  return {
    mode,
    hooks,
    promptBlock: `DEFAULT VIRAL STYLE INJECTION (authoritative unless the user explicitly asked for no memes/no viral styling):
- Do not output sterile/basic content. Add at least 3 emotion hooks that can survive into Roblox export: ${hooks.join(', ')}.
- Keep it Roblox-safe and performant: bounded particles, readable colors, no one-note neon wash, no copyrighted characters.
- For items/potions: even a normal item should get a strange glow, short meme/brainrot pop sound, and playful feedback text by default.
- For rooms/maps/buildings: include lighting mood, fog/atmosphere, weird props/signage, and positional ambience so the result provokes a reaction in Studio.`
  };
}

app.post('/api/content/generate', async (req: AuthedRequest, res) => {
  try {
    const body = (req.body ?? {}) as ContentGenerateRequest;
    const prompt = body.prompt?.trim();

    if (!prompt) {
      return res.status(400).json({ error: 'Prompt is required' });
    }

    const normalizedPrompt = truncatePrompt(prompt, 8000);
    const moderation = await runModerationPipeline({
      userId: req.userId ?? 'unknown-user',
      text: normalizedPrompt,
      stage: 'input',
      metadata: body.metadata as Record<string, unknown> | undefined,
    });
    if (!moderation.allowed) {
      return res.status(400).json({ error: moderation.reason, moderation });
    }

    const safePrompt = truncatePrompt(moderation.rewrittenText?.trim() || normalizedPrompt, 8000);
    const effectiveMetadata: PromptContextMetadata = { ...(body.metadata ?? {}) };
    const shouldResetMemory = isStartOverRequest(safePrompt);
    let projectMemory: ProjectMemory | undefined;
    if (body.threadId) {
      const threadRef = db.collection('threads').doc(body.threadId);
      const reqProjectKind = typeof effectiveMetadata.projectKind === 'string' ? effectiveMetadata.projectKind : undefined;
      const reqContentSubcategory = typeof effectiveMetadata.contentSubcategory === 'string' ? effectiveMetadata.contentSubcategory : undefined;
      await ensureThread(threadRef, req.userId ?? 'unknown-user', safePrompt, reqProjectKind, reqContentSubcategory);
      const threadDoc = await threadRef.get();
      const threadData = threadDoc.exists ? threadDoc.data() ?? {} : {};
      if (threadData.userId === req.userId) {
        if (shouldResetMemory) {
          await threadRef.set({
            projectMemory: FieldValue.delete(),
            latestJobId: FieldValue.delete(),
            latestArtifactIds: FieldValue.delete(),
            contentSubcategory: reqContentSubcategory ?? FieldValue.delete(),
            updatedAt: FieldValue.serverTimestamp(),
          }, { merge: true });
        } else {
          projectMemory = normalizeProjectMemory(threadData.projectMemory);
        }
      }
    }

    if (projectMemory) {
      if (projectMemory.projectKind && !effectiveMetadata.projectKind) effectiveMetadata.projectKind = projectMemory.projectKind;
      if (projectMemory.contentSubcategory && typeof effectiveMetadata.contentSubcategory !== 'string') {
        effectiveMetadata.contentSubcategory = projectMemory.contentSubcategory;
      }
      if (projectMemory.title && typeof effectiveMetadata.title !== 'string') effectiveMetadata.title = projectMemory.title;
      if (projectMemory.genre && typeof effectiveMetadata.genre !== 'string') effectiveMetadata.genre = projectMemory.genre;
      if (projectMemory.theme && typeof effectiveMetadata.theme !== 'string') effectiveMetadata.theme = projectMemory.theme;
      effectiveMetadata.hasExistingProject = true;
      effectiveMetadata.projectMemorySummary = projectMemorySummary(projectMemory);
      effectiveMetadata.requestedChangePrompt = safePrompt;
    }
    const metadataIndicatesObby = OBBY_PATTERN.test([
      effectiveMetadata.contentSubcategory,
      effectiveMetadata.genre,
      projectMemory?.contentSubcategory,
      projectMemory?.genre,
    ].filter(Boolean).join(' '));
    if (shouldAddObbyShop(projectMemory, safePrompt) || (metadataIndicatesObby && SHOP_REQUEST_PATTERN.test(safePrompt))) {
      effectiveMetadata.hasObbyShop = true;
    }
    const referenceAttachmentKind = typeof effectiveMetadata.attachmentKind === 'string'
      ? effectiveMetadata.attachmentKind : undefined;
    const referenceAttachmentImageUrl = typeof effectiveMetadata.attachmentImageUrl === 'string'
      ? effectiveMetadata.attachmentImageUrl : undefined;
    let generationReferenceImageSummary = typeof effectiveMetadata.referenceImageSummary === 'string'
      ? effectiveMetadata.referenceImageSummary.trim() : '';
    if (referenceAttachmentKind === 'image' && referenceAttachmentImageUrl && !generationReferenceImageSummary) {
      try {
        generationReferenceImageSummary = await Promise.race<string>([
          describeReferenceImage(referenceAttachmentImageUrl),
          new Promise<string>((resolve) => setTimeout(() => resolve(''), 6000)),
        ]);
      } catch (error) {
        logger.warn('content-generate describeReferenceImage threw, continuing without vision summary', error);
        generationReferenceImageSummary = '';
      }
    }
    if (generationReferenceImageSummary) {
      effectiveMetadata.referenceImageSummary = generationReferenceImageSummary.slice(0, 1000);
    }

    const baseGenerationPrompt = projectMemory
      ? truncatePrompt(buildIterativeGenerationPrompt(projectMemory, safePrompt), 8000)
      : safePrompt;
    let generationPrompt = generationReferenceImageSummary
      ? truncatePrompt(`${baseGenerationPrompt}

Reference image visual brief (vision-extracted, authoritative for this generation):
${generationReferenceImageSummary}

If the reference is a UI screenshot, preserve layout hierarchy, spacing, palette, component density, and interaction intent while creating original Roblox-safe assets. If it is a character/object concept, preserve silhouette, colors, materials, and visible accessories as generation constraints.`, 8000)
      : baseGenerationPrompt;

    const viralStyleInjection = buildDefaultViralStyleInjection(generationPrompt, effectiveMetadata as Record<string, unknown>);
    if (viralStyleInjection) {
      effectiveMetadata.viralStyleMode = viralStyleInjection.mode;
      effectiveMetadata.viralStyleHooks = viralStyleInjection.hooks;
      generationPrompt = truncatePrompt(`${generationPrompt}

${viralStyleInjection.promptBlock}`, 8000);
    }

    const vehicleRoutingReason = shouldPromoteVehicleRequest(body.kind, generationPrompt, effectiveMetadata);
    if (vehicleRoutingReason) {
      effectiveMetadata.contentCategory = 'vehicle';
      effectiveMetadata.contentSubcategory = 'vehicles';
      effectiveMetadata.requestedKind = 'vehicle_3d';
      effectiveMetadata.vehicleRoutingReason = vehicleRoutingReason;
      logger.info('[Vehicles] Promoted request to vehicle_3d', {
        bodyKind: body.kind,
        vehicleRoutingReason,
      });
    }

    // ── Smart Stubs: 3-tier classification before heavy generation ──
    const stubCheck = await runSmartStubsClassification(
      req.userId ?? 'unknown-user',
      generationPrompt,
      effectiveMetadata as Record<string, unknown>,
      body.kind,
    );
    if (stubCheck.blocked) {
      logger.info('Smart Stubs: generation blocked', {
        userId: req.userId,
        tier: stubCheck.stub?.tier,
        category: stubCheck.stub?.unsupportedCategory,
        hardPivot: stubCheck.hardPivot ?? false,
      });
      return res.status(200).json({
        blocked: true,
        tokensCharged: false,
        hardPivot: stubCheck.hardPivot ?? false,
        stub: {
          message: stubCheck.stub?.stubMessage ?? stubCheck.hardPivotMessage,
          scenario: stubCheck.stub?.stubScenario,
          unsupportedCategory: stubCheck.stub?.unsupportedCategory,
          alternativeActions: stubCheck.stub?.alternativeActions ?? [],
        },
      });
    }

    // Successful generation path — reset anti-fatigue counter
    resetConsecutiveStubs(req.userId ?? 'unknown-user').catch(() => {});

    const requestedKind = resolveRequestedGenerationKind(body.kind, effectiveMetadata);
    const kindRequiresProvider = providerForKind(requestedKind, effectiveMetadata);
    // Session 376: clothing_3d / vehicle_3d added — they hit the same image-to-3d
    // executeProvider path as character_3d, so allowing body.provider override would
    // route them to 'openai' (returns text, not glb) and fail mesh_3d stage.
    const kindsWithFixedProvider: GenerationJob['kind'][] = ['character_3d', 'clothing_3d', 'vehicle_3d', 'image', 'search'];
    const provider = kindsWithFixedProvider.includes(requestedKind)
      ? kindRequiresProvider
      : (body.provider ?? kindRequiresProvider);

    logger.info('Generation routing', {
      bodyKind: body.kind,
      bodyProvider: body.provider,
      requestedKind,
      kindRequiresProvider,
      resolvedProvider: provider,
      isFixedProvider: kindsWithFixedProvider.includes(requestedKind),
    });

    try {
      const enrichment = await buildLiveGenerationEnrichmentContext({
        prompt: generationPrompt,
        kind: requestedKind,
        metadata: effectiveMetadata,
      });
      if (enrichment) {
        effectiveMetadata.generationEnrichmentContext = enrichment.context;
        effectiveMetadata.generationEnrichmentSources = enrichment.sources;
        effectiveMetadata.generationEnrichmentItemCount = enrichment.itemCount;
        logger.info('Live generation enrichment attached', {
          requestedKind,
          contentCategory: effectiveMetadata.contentCategory,
          contentSubcategory: effectiveMetadata.contentSubcategory,
          sources: enrichment.sources,
          itemCount: enrichment.itemCount,
        });
      }

      // Master Plan Phase 0+A (session 219): also stash STRUCTURED items so
      // genre game-builders can weld a `rbxthumb://` BillboardGui showcase
      // directly into the generated map. Same Firestore cache, no extra
      // Roblox API hit if the LLM enrichment already warmed it.
      const isGameKind = requestedKind === 'game_package' || requestedKind === 'rbxl_build' || requestedKind === 'rbxm_build';
      if (isGameKind) {
        try {
          // Phase E (session 219): per-subcategory category selection so the
          // showcase wall fits the game's aesthetic. brainrot_sim → Decals
          // (top decals are more meme/sticker-flavoured than generic
          // Featured bundles); horror → Decals (poster motifs); pvp_arena →
          // Animations (sponsor banners cycle emotes). Default Featured.
          const subcategoryForShowcase = typeof effectiveMetadata.contentSubcategory === 'string'
            ? effectiveMetadata.contentSubcategory.toLowerCase()
            : '';
          let showcaseCategory: 'Featured' | 'Decals' | 'Animations' | 'Collectibles' = 'Featured';
          if (subcategoryForShowcase === 'brainrot_sim' || subcategoryForShowcase === 'horror_escape' || subcategoryForShowcase === 'horror') {
            showcaseCategory = 'Decals';
          } else if (subcategoryForShowcase === 'pvp_arena' || subcategoryForShowcase === 'pvp') {
            showcaseCategory = 'Animations';
          }
          // Phase A (session 225): extract keyword from prompt → showcase wall
          // показывает thematic items, не generic Featured. Failsafe: если
          // keyword не извлёк или search вернул empty — fallback на trending.
          const promptKeyword = extractKeywordFromBrief(generationPrompt, effectiveMetadata as Record<string, unknown>);
          const showcaseItems = await fetchTrendingShowcaseItems({
            category: showcaseCategory,
            limit: 6,
            keyword: promptKeyword,
          });
          if (showcaseItems && showcaseItems.length > 0) {
            (effectiveMetadata as Record<string, unknown>).trendingShowcaseItems = showcaseItems;
            (effectiveMetadata as Record<string, unknown>).trendingShowcaseCategory = showcaseCategory;
            if (promptKeyword) {
              (effectiveMetadata as Record<string, unknown>).trendingShowcaseKeyword = promptKeyword;
            }
            logger.info('Trending showcase items attached for in-game weld', {
              requestedKind,
              subcategory: subcategoryForShowcase || undefined,
              category: showcaseCategory,
              keyword: promptKeyword || undefined,
              count: showcaseItems.length,
            });
          }

          // Phase D (session 225): live brainrot pool — fetch top Decals per
          // meme keyword in parallel, store as { skibidi: [id1,id2], ... }
          // map. buildBrainrotConveyorScript prefers these over 18 hardcoded
          // IDs. Brainrot pool stays meme-fresh forever без redeploy.
          if (subcategoryForShowcase === 'brainrot_sim') {
            try {
              const BRAINROT_KEYWORDS: Array<{ subTheme: string; keyword: string }> = [
                { subTheme: 'skibidi',   keyword: 'skibidi toilet' },
                { subTheme: 'tralalero', keyword: 'tralalero tralala' },
                { subTheme: 'bombardir', keyword: 'bombardiro crocodilo' },
                { subTheme: 'sigma',     keyword: 'cappuccino assassino' },
                { subTheme: 'generic',   keyword: 'italian brainrot' },
              ];
              const fetched = await Promise.all(
                BRAINROT_KEYWORDS.map(async ({ subTheme, keyword }) => {
                  try {
                    const r = await fetchCatalogByKeyword({ keyword, category: 'Decals', limit: 6 });
                    return { subTheme, ids: r.items.map((it) => it.id).filter((id) => typeof id === 'number' && id > 0) };
                  } catch {
                    return { subTheme, ids: [] as number[] };
                  }
                }),
              );
              const liveMap: Record<string, number[]> = {};
              let totalLive = 0;
              for (const { subTheme, ids } of fetched) {
                if (ids.length > 0) {
                  liveMap[subTheme] = ids;
                  totalLive += ids.length;
                }
              }
              if (totalLive > 0) {
                (effectiveMetadata as Record<string, unknown>).brainrotLiveDecalsBySubTheme = liveMap;
                logger.info('brainrot live decals attached', {
                  totalLive,
                  perSubTheme: Object.fromEntries(Object.entries(liveMap).map(([k, v]) => [k, v.length])),
                });
              } else {
                logger.info('brainrot live decals: all keywords returned 0 — falling back to 18 hardcoded IDs');
              }
            } catch (poolErr) {
              logger.warn('brainrot live pool fetch failed; using 18 hardcoded IDs', {
                error: poolErr instanceof Error ? poolErr.message : String(poolErr),
              });
            }
          }
        } catch (showcaseErr) {
          logger.warn('fetchTrendingShowcaseItems failed; in-game showcase will be skipped', {
            requestedKind, error: showcaseErr instanceof Error ? showcaseErr.message : String(showcaseErr),
          });
        }
      }
    } catch (enrichmentErr) {
      logger.warn('Live generation enrichment failed; continuing without it', {
        requestedKind,
        error: enrichmentErr instanceof Error ? enrichmentErr.message : String(enrichmentErr),
      });
    }

    const generationAcceptanceCriteria = buildGenerationAcceptanceCriteria({
      prompt: generationPrompt,
      kind: requestedKind,
      metadata: effectiveMetadata as Record<string, unknown>,
    });
    (effectiveMetadata as Record<string, unknown>).generationAcceptanceCriteria = generationAcceptanceCriteria;
    logger.info('[GenerationQualityGate] acceptance criteria attached', {
      requestedKind,
      target: generationAcceptanceCriteria.target,
      requiredVisualCues: generationAcceptanceCriteria.requiredVisualCues,
      requiredAccessoryKeys: generationAcceptanceCriteria.requiredAccessoryKeys,
      requiredBehaviorCues: generationAcceptanceCriteria.requiredBehaviorCues,
      apifySignalCount: generationAcceptanceCriteria.apifySignals.length,
    });

    const jobId = uuidv4();
    const now = new Date().toISOString();
    const job: GenerationJob = {
      id: jobId,
      userId: req.userId ?? 'unknown-user',
      threadId: body.threadId,
      prompt: generationPrompt,
      provider,
      kind: requestedKind,
      status: 'queued',
      createdAt: now,
      updatedAt: now,
      artifacts: [],
      history: ['Queued generation job', `Selected provider: ${provider}`],
      stages: (() => {
        if (requestedKind === 'clothing_3d') return createLayeredClothingPipelineStages();
        if (requestedKind === 'pet_3d') {
          // Track 3 Phase 2 (Blocky Pet): user picked blocky mode in iOS chat;
          // we still keep the pet_3d kind for backward compat with downstream
          // consumers, but route to the 6-stage blocky pipeline instead of
          // the 14-stage Tripo/Meshy mesh chain.
          if (effectiveMetadata.petMode === 'blocky') return createBlockyPetPipelineStages();
          return createPetEvolutionPipelineStages();
        }
        if (requestedKind === 'vehicle_3d' || isVehicleGenerationMetadata(effectiveMetadata)) return createVehiclePipelineStages();
        if (requestedKind === 'animation') return createAnimationPipelineStages();
        if (requestedKind === 'decal_texture') return createDecalTexturePipelineStages();
        if (effectiveMetadata.contentCategory === 'gamepass') return createMonetizationPipelineStages();
        if (effectiveMetadata.contentCategory === 'map_environment') return createMapEnvironmentPipelineStages();
        if (effectiveMetadata.contentCategory === 'building') return createBuildingPipelineStages();
        if (requestedKind !== 'character_3d') return undefined;
        if (effectiveMetadata.contentCategory === 'weapon') return createWeaponPipelineStages();
        if (effectiveMetadata.contentCategory === 'item_tool') return createItemPipelineStages();
        if (effectiveMetadata.contentCategory === 'furniture_prop') return createFurniturePipelineStages(resolveFurnitureBuildMode(generationPrompt, effectiveMetadata));
        if (effectiveMetadata.contentCategory === 'npc_ai') return createNpcPipelineStages(resolveNpcVisualPipelineMode(effectiveMetadata));
        // Session 001 (Track 1) — T-Shirt has its own 2-stage pipeline (graphic + RBXM),
        // no concept_image because Flux generates the 512x512 directly from the prompt.
        // Checked BEFORE isTextureClothing(): the latter early-returns false for
        // clothingType === 't_shirt' (the routing guard) so we'd otherwise miss this branch.
        // Session 001 (Track 1): auto-detect T-Shirt if user didn't tap the iOS
        // welcome picker but typed "t-shirt" / "tshirt" / "футболка" directly into
        // the prompt while in the "clothing" subcategory. Without this fallback,
        // Quick Generate without explicit picker tap falls through to the 9-stage
        // character_3d default (the bug user kept seeing). The fallback only
        // activates inside the clothing subcategory, so it doesn't affect other flows.
        const inClothingSub = effectiveMetadata.contentSubcategory === 'clothing'
          || effectiveMetadata.contentCategory === 'ugc_clothing';
        const promptLooksLikeTShirt = /\b(t[-_ ]?shirt|tshirt|футболка|майка|майку|футболку)\b/i.test(generationPrompt);
        if (inClothingSub && promptLooksLikeTShirt && !effectiveMetadata.clothingType) {
          effectiveMetadata.clothingType = 't_shirt';
        }
        logger.info('Pipeline stage init for character_3d kind', {
          clothingType: effectiveMetadata.clothingType,
          clothingMode: effectiveMetadata.clothingMode,
          contentSubcategory: effectiveMetadata.contentSubcategory,
          autoDetectedTShirt: inClothingSub && promptLooksLikeTShirt,
        });
        if (effectiveMetadata.clothingType === 't_shirt') return createTShirtPipelineStages();
        const isTex = isTextureClothing(generationPrompt, effectiveMetadata);
        return isTex ? createClothingPipelineStages() : createCharacterPipelineStages();
      })(),
      dispatchMode: getJobDispatchMode() as JobDispatchMode,
      metadata: {
        ...effectiveMetadata,
        requestedKind,
        rawRequestedKind: body.kind,
        moderationEventId: moderation.eventId,
        // Preserve user-chosen chat provider (building Architect Agent reads this).
        chatProvider: typeof body.provider === 'string' ? body.provider : undefined,
      },
    };

    await db.collection('generationJobs').doc(jobId).set(job);

    const asyncKinds: GenerationJob['kind'][] = ['character_3d', 'clothing_3d', 'pet_3d', 'vehicle_3d', 'animation', 'game_package', 'rbxl_build', 'rbxm_build', 'code'];
    if (asyncKinds.includes(requestedKind)) {
      const selfHost = req.header('host') ?? 'api-z4yzt6dhjq-uc.a.run.app';
      const selfUrl = `https://${selfHost}/api/internal/run-3d-pipeline`;
      const internalToken = ROBLOX_WORKER_TOKEN.value();

      res.json({
        jobId,
        status: 'processing',
        provider,
      } satisfies ContentGenerateResponse);

      let dispatched = false;
      for (let attempt = 0; attempt < 2 && !dispatched; attempt++) {
        try {
          const resp = await fetch(selfUrl, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'x-internal-token': internalToken,
            },
            body: JSON.stringify({ jobId }),
            signal: AbortSignal.timeout(10_000),
          });
          if (resp.ok) dispatched = true;
        } catch (err) {
          logger.warn(`3D pipeline dispatch attempt ${attempt + 1} failed`, err);
        }
      }

      if (!dispatched) {
        logger.warn('Self-invoke failed after retries, running pipeline in-process', { jobId });
        runGenerationJobLifecycle(jobId, job).catch((err) => {
          logger.error('In-process 3D pipeline fallback failed', err);
        });
      } else {
        logger.info('character_3d dispatched to internal pipeline', { jobId, selfUrl });
      }

      return;
    }

    const completed = await runGenerationJobLifecycle(jobId, job);

    const response: ContentGenerateResponse = {
      jobId,
      status: completed.status,
      provider,
      artifactId: completed.artifacts[0]?.id,
      artifactIds: completed.artifacts.map((artifact) => artifact.id),
    };

    res.json(response);
  } catch (error) {
    logger.error('Content generation failed', error);
    res.status(500).json({ error: errorMessage(error) });
  }
});

// ── Smart Stubs: Feature Vote (CustDev analytics) ──
app.post('/api/smart-stubs/vote', async (req: AuthedRequest, res) => {
  try {
    const { feature, prompt } = req.body ?? {};
    if (!feature) return res.status(400).json({ error: 'feature is required' });
    await db.collection('analyticsEvents').add({
      type: 'feature_vote_clicked',
      userId: req.userId ?? 'unknown-user',
      timestamp: new Date().toISOString(),
      requestedFeature: typeof feature === 'string' ? feature.slice(0, 200) : '',
      userPrompt: typeof prompt === 'string' ? prompt.slice(0, 500) : '',
    });
    return res.json({ success: true });
  } catch (error) {
    logger.warn('Feature vote tracking failed', error);
    return res.status(500).json({ error: 'Failed to record vote' });
  }
});

app.get('/api/content/jobs/:jobId', async (req: AuthedRequest, res) => {
  const doc = await db.collection('generationJobs').doc(req.params.jobId).get();
  if (!doc.exists) {
    return res.status(404).json({ error: 'Job not found' });
  }

  const data = repairPostApprovalStageProgress(doc.data() as GenerationJob);
  if (data.userId !== req.userId) {
    return res.status(403).json({ error: 'Forbidden' });
  }

  return res.json(data);
});

// ── Run Phase 2 (3D generation) — called directly by iOS after concept approval ──
// This endpoint keeps the HTTP connection alive for the entire Phase 2 duration (5-7 min),
// preventing Cloud Run from throttling the CPU. iOS calls this in a background Task while
// polling for progress in parallel.
app.post('/api/content/jobs/:jobId/run-phase2', async (req: AuthedRequest, res) => {
  const { jobId } = req.params;
  const docRef = db.collection('generationJobs').doc(jobId);
  const doc = await docRef.get();
  if (!doc.exists) return res.status(404).json({ error: 'Job not found' });
  const job = doc.data() as GenerationJob;
  if (job.userId !== req.userId) return res.status(403).json({ error: 'Forbidden' });
  if (job.status !== 'processing') {
    return res.status(400).json({ error: `Job is not in processing state (status: ${job.status})` });
  }

  const isGamePackage = job.kind === 'game_package' || job.kind === 'rbxl_build' || job.kind === 'rbxm_build';
  logger.info(`run-phase2: starting Phase 2 via iOS direct call (kind=${job.kind})`, { jobId });

  try {
    if (isGamePackage) {
      // Game package hero assets Phase 2: re-enter buildGamePackageArtifacts
      const result = await continueGamePackagePhase2(jobId, job);
      await docRef.update({
        status: result.status,
        artifacts: result.artifacts,
        resultText: result.resultText ?? '',
        metadata: result.metadata ?? {},
        history: result.history,
        stages: result.stages ?? [],
        updatedAt: new Date().toISOString(),
      }).catch((e) => logger.error('run-phase2: failed to persist game package state', { error: errorMessage(e) }));
      syncThreadProjectMemoryFromJob(result).catch((e) => logger.error('run-phase2: failed to sync thread project memory', { error: errorMessage(e) }));
      logger.info('run-phase2: Game package Phase 2 completed', { jobId, status: result.status, artifactCount: result.artifacts.length });
      sendGenerationTerminalPush(result).catch((e) => logger.error('run-phase2: failed to send terminal push', {
        jobId,
        status: result.status,
        error: errorMessage(e),
      }));
      res.json({ status: result.status, jobId });
    } else if (job.kind === 'pet_3d') {
      // 2026-05-21 pet_3d resume after concept approval. processPet3DJob
      // reads metadata.pipelinePhase='pet_concept_approved' (stamped by
      // /approve-concept above), restores the cached classification +
      // approved concept URL, and runs mesh + rig + export. No separate
      // continuePet3DPhase2 closure needed — the function is idempotent
      // on resume.
      const result = await processPet3DJob(jobId, job);
      await docRef.update({
        status: result.status,
        artifacts: result.artifacts,
        resultText: result.resultText ?? '',
        metadata: result.metadata ?? {},
        history: result.history,
        stages: result.stages ?? [],
        updatedAt: new Date().toISOString(),
      }).catch((e) => logger.error('run-phase2: pet_3d persist failed', { error: errorMessage(e) }));
      syncThreadProjectMemoryFromJob(result).catch((e) => logger.error('run-phase2: failed to sync thread project memory', { error: errorMessage(e) }));
      logger.info('run-phase2: pet_3d Phase 2 completed', { jobId, status: result.status, artifactCount: result.artifacts.length });
      sendGenerationTerminalPush(result).catch((e) => logger.error('run-phase2: failed to send terminal push', {
        jobId,
        status: result.status,
        error: errorMessage(e),
      }));
      res.json({ status: result.status, jobId });
    } else {
      // Character 3D Phase 2 (existing NPC path)
      const result = await continueCharacter3DPhase2(jobId, job);
      await docRef.update({
        status: result.status,
        artifacts: result.artifacts,
        resultText: result.resultText ?? '',
        metadata: result.metadata ?? {},
        history: result.history,
        updatedAt: new Date().toISOString(),
      }).catch((e) => logger.error('run-phase2: failed to persist final state', { error: errorMessage(e) }));
      syncThreadProjectMemoryFromJob(result).catch((e) => logger.error('run-phase2: failed to sync thread project memory', { error: errorMessage(e) }));
      logger.info('run-phase2: Phase 2 completed and persisted', { jobId, status: result.status, artifactCount: result.artifacts.length });
      sendGenerationTerminalPush(result).catch((e) => logger.error('run-phase2: failed to send terminal push', {
        jobId,
        status: result.status,
        error: errorMessage(e),
      }));
      res.json({ status: result.status, jobId });
    }
  } catch (err) {
    logger.error('run-phase2: Phase 2 failed', { jobId, error: errorMessage(err) });
    const qualityMetadataPatch = err instanceof GenerationQualityRejectError ? err.metadataPatch : {};
    const failedStages = err instanceof GenerationQualityRejectError ? (err.stagesSnapshot ?? job.stages ?? []) : (job.stages ?? []);
    await docRef.update({
      status: 'failed',
      errorMessage: errorMessage(err),
      metadata: {
        ...(job.metadata ?? {}),
        ...qualityMetadataPatch,
      },
      stages: failedStages,
      updatedAt: new Date().toISOString(),
    }).catch(() => {});
    sendGenerationTerminalPush({
      ...job,
      status: 'failed',
      errorMessage: errorMessage(err),
      metadata: {
        ...(job.metadata ?? {}),
        ...qualityMetadataPatch,
      },
      stages: failedStages,
      updatedAt: new Date().toISOString(),
    }).catch((e) => logger.error('run-phase2: failed to send failure push', {
      jobId,
      error: errorMessage(e),
    }));
    res.status(500).json({ status: 'failed', error: errorMessage(err) });
  }
});

// ── Approve or regenerate concept image ──
app.post('/api/content/jobs/:jobId/approve-concept', async (req: AuthedRequest, res) => {
  try {
    const { jobId } = req.params;
    const { approved, feedback } = (req.body ?? {}) as { approved?: boolean; feedback?: string };
    const docRef = db.collection('generationJobs').doc(jobId);
    const doc = await docRef.get();
    if (!doc.exists) return res.status(404).json({ error: 'Job not found' });
    const job = doc.data() as GenerationJob;
    if (job.userId !== req.userId) return res.status(403).json({ error: 'Forbidden' });
    if (job.status !== 'awaiting_review') {
      return res.status(400).json({ error: `Job is not awaiting review (status: ${job.status})` });
    }

    if (approved) {
      // User approved → continue pipeline (Phase 2: 3D generation)
      // 2026-05-21 (pet_3d): stamp pipelinePhase so processPet3DJob skips
      // classify_pet + concept_stage1 on the next entry (Pet pipeline runs
      // a full inner function rather than a separate Phase 2 closure).
      const updatedMetadata: Record<string, unknown> = { ...(job.metadata ?? {}) };
      if (job.kind === 'pet_3d') {
        updatedMetadata.pipelinePhase = 'pet_concept_approved';
      }
      const updatedJob: Partial<GenerationJob> = {
        status: 'processing',
        updatedAt: new Date().toISOString(),
        metadata: updatedMetadata,
        stages: (job.stages ?? []).map((s) =>
          s.id === 'concept_image' || s.id === 'concept_approval'
            ? { ...s, status: 'completed' as const, completedAt: new Date().toISOString() }
            : s,
        ),
        history: [...job.history, 'User approved concept image — continuing to 3D generation'],
      };
      await docRef.update(updatedJob);

      // Phase 2 is NOT dispatched here — iOS calls /run-phase2 directly after
      // receiving this response. This avoids Cloud Run CPU throttling that killed
      // the old server-to-server dispatch pattern.
      logger.info('Concept approved, awaiting iOS run-phase2 call', { jobId });
      return res.json({ status: 'approved', message: '3D generation starting...' });
    } else {
      // User rejected → regenerate concept image with optional feedback.
      //
      // 2026-05-21 (pet_3d): two pet-specific quirks the generic flow misses:
      //   1) Pet's first concept stage is named `concept_stage1`, NOT
      //      `concept_image`. If we ship the new artifact with the generic
      //      stageId, the pet pipeline stage that drives the iOS approval
      //      UI loses its artifact link → iOS shows a stale image or no
      //      image at all.
      //   2) buildConceptImagePrompt() doesn't know about the pet's
      //      classification (species/element/rarity/evolution-arc) cached
      //      in metadata.petClassificationCache. Without that, the
      //      regenerated image is generic and looks nearly identical to
      //      the first one — user thinks "same PNG, regenerate broken".
      // So for pets we (a) use the stage1 prompt from the cached evolution
      // arc, and (b) attach the artifact with stageId='concept_stage1'.
      const isPetJob = job.kind === 'pet_3d';
      const petClassification = isPetJob
        && job.metadata?.petClassificationCache
        && typeof job.metadata.petClassificationCache === 'object'
        ? job.metadata.petClassificationCache as {
            evolutionArc?: { stage1?: { prompt?: string } };
            speciesType?: string; rarity?: string; element?: string;
          }
        : undefined;

      let alignedPrompt: string;
      if (isPetJob && petClassification?.evolutionArc?.stage1?.prompt) {
        // Pet: rebuild the same Stage-1 prompt the original generator used,
        // append explicit "different from previous attempt" + feedback.
        const stage1 = petClassification.evolutionArc.stage1.prompt;
        const flavor = `${petClassification.rarity ?? ''} ${petClassification.element ?? ''} ${petClassification.speciesType ?? ''}`.trim();
        alignedPrompt = `${stage1}. ${flavor ? `${flavor} pet baby stage. ` : ''}Different composition, different pose, different angle from any previous attempt.`;
      } else {
        alignedPrompt = buildConceptImagePrompt(job.prompt, job.metadata ?? {});
      }
      if (feedback && feedback.trim().length > 0) {
        alignedPrompt = `${alignedPrompt}. User correction: ${feedback.trim()}`;
      }
      const projectKind = typeof job.metadata?.projectKind === 'string' ? job.metadata.projectKind : 'content';
      const previewStyle = projectKind === 'ugc' ? 'ugc' : projectKind === 'content' ? 'pixel' : 'roblox';

      let newConceptUrl: string | undefined;
      try {
        // Pet regen also uses the sculpted-realism 'pet' context so the
        // new image matches the look of the original Stage-1 concept (and
        // doesn't suddenly snap back to the Roblox-toon cartoon style).
        const regenContext: 'character' | 'pet' = isPetJob ? 'pet' : 'character';
        newConceptUrl = await generatePreviewTexture(alignedPrompt, previewStyle, regenContext);
      } catch (err) {
        logger.warn('Concept regeneration failed', { error: errorMessage(err) });
      }

      // Update artifacts — replace old concept with new one. For pets we
      // also re-link the artifact to the concept_stage1 stage so iOS's
      // conceptStage lookup picks it up (otherwise stage.artifactIds is
      // empty after the old artifact is filtered out and the UI shows nothing).
      const conceptStageId: GenerationStageId = isPetJob
        ? ('concept_stage1' as GenerationStageId)
        : ('concept_image' as GenerationStageId);
      let artifacts = job.artifacts;
      let newConceptArtifactId: string | undefined;
      if (newConceptUrl) {
        const newConceptArtifact = await copyExternalArtifact(job, newConceptUrl, 'image/png', {
          name: isPetJob ? 'pet-concept-regenerated.png' : 'concept-regenerated.png',
          previewText: 'Regenerated concept image',
          stageId: conceptStageId,
          artifactRole: 'concept',
          metadata: {
            isPreviewTexture: true,
            isConcept: true,
            regenerated: true,
            ...(isPetJob ? { isPetConcept: true, petStageIndex: 1 } : {}),
          },
        });
        newConceptArtifactId = newConceptArtifact.id;
        // Remove old concept artifacts, add new one.
        artifacts = [
          ...artifacts.filter((a) => a.artifactRole !== 'concept'),
          newConceptArtifact,
        ];
      }

      // For pets: re-link the new artifact id onto the concept_stage1
      // stage's artifactIds so iOS's pipelineArtifactType resolver picks
      // it up regardless of stageId-based matching ordering.
      const updatedStages = (job.stages ?? []).map((s) => {
        if (isPetJob && s.id === 'concept_stage1' && newConceptArtifactId) {
          return { ...s, artifactIds: [newConceptArtifactId] };
        }
        return s;
      });

      await docRef.update({
        artifacts,
        stages: updatedStages,
        updatedAt: new Date().toISOString(),
        metadata: {
          ...(job.metadata ?? {}),
          conceptPreviewUrl: newConceptUrl,
          // Pet resume path reads approvedPetConceptUrl on /run-phase2.
          // Update the cache too so approval after a regen uses the NEW
          // image, not the stale original.
          ...(isPetJob && newConceptUrl ? { approvedPetConceptUrl: newConceptUrl } : {}),
        },
        history: [...job.history, `User requested concept regeneration${feedback ? ` (feedback: ${feedback.trim()})` : ''} — ${newConceptUrl ? 'new image generated' : 'generation failed'}`],
      });

      return res.json({
        status: 'regenerated',
        conceptUrl: newConceptUrl ?? null,
        message: newConceptUrl ? 'New concept image generated' : 'Regeneration failed — try a different description',
      });
    }
  } catch (err) {
    logger.error('approve-concept failed', { error: errorMessage(err) });
    return res.status(500).json({ error: 'Internal error' });
  }
});

// ── Approve / reject / regenerate hero concept images for game packages ──
app.post('/api/content/jobs/:jobId/approve-hero-assets', async (req: AuthedRequest, res) => {
  try {
    const { jobId } = req.params;
    const { decisions } = (req.body ?? {}) as {
      decisions?: Array<{ index: number; approved: boolean; feedback?: string }>;
    };
    if (!decisions || !Array.isArray(decisions) || decisions.length === 0) {
      return res.status(400).json({ error: 'decisions array is required' });
    }

    const docRef = db.collection('generationJobs').doc(jobId);
    const doc = await docRef.get();
    if (!doc.exists) return res.status(404).json({ error: 'Job not found' });
    const job = doc.data() as GenerationJob;
    if (job.userId !== req.userId) return res.status(403).json({ error: 'Forbidden' });
    if (job.status !== 'awaiting_review') {
      return res.status(400).json({ error: `Job is not awaiting review (status: ${job.status})` });
    }

    const heroConcepts = parseNpcAccessoryConcepts(job.metadata?.heroConcepts).length > 0
      ? parseNpcAccessoryConcepts(job.metadata?.heroConcepts)
      : ((job.metadata?.heroConcepts ?? []) as Array<{
        name: string; description: string; imageUrl: string; approved: boolean;
      }>).slice();
    const isNpcAccessoryApproval = job.metadata?.npcAccessoryApprovalKind === 'generated_accessories_v1';
    const npcAccessorySpecs = parseNpcAccessorySpecs(job.metadata?.npcAccessoryConceptSpecs);
    const historyLines: string[] = [];

    for (const d of decisions) {
      if (d.index < 0 || d.index >= heroConcepts.length) continue;
      if (d.approved) {
        heroConcepts[d.index].approved = true;
        historyLines.push(`Approved ${isNpcAccessoryApproval ? 'NPC accessory' : 'hero'} concept: "${heroConcepts[d.index].name}"`);
      } else {
        // Rejected → always regenerate (feedback is optional enhancement)
        const concept = heroConcepts[d.index];
        const feedbackTrimmed = (d.feedback ?? '').trim();
        const accessorySpec = isNpcAccessoryApproval
          ? npcAccessorySpecs.find((spec) => spec.key === concept.name || spec.displayName === concept.name)
          : undefined;
        const basePrompt = accessorySpec
          ? buildNpcGeneratedAccessoryConceptPrompt(
              accessorySpec,
              typeof job.metadata?.title === 'string' ? job.metadata.title : summarizeTitle(job.prompt),
              job.prompt,
              Number(job.metadata?.visualVariantSeed ?? 0) + accessorySpec.priority + d.index,
            )
          : `single isolated 3D character figurine, "${concept.name}", ${concept.description}, centered on plain white background, full body front view, cute cartoon Roblox style, no environment no scenery no platform`;
        const regenerateDesc = feedbackTrimmed ? `${basePrompt}. User correction: ${feedbackTrimmed}` : basePrompt;
        try {
          const newUrl = await generatePreviewTexture(regenerateDesc, 'roblox', accessorySpec ? 'prop' : 'character');
          if (newUrl) {
            heroConcepts[d.index].imageUrl = newUrl;
            heroConcepts[d.index].approved = false;
            historyLines.push(`Regenerated ${isNpcAccessoryApproval ? 'NPC accessory' : 'hero'} concept "${concept.name}"${feedbackTrimmed ? ` with feedback: ${feedbackTrimmed}` : ''}`);
          } else {
            historyLines.push(`Regeneration failed for "${concept.name}" — keeping original`);
          }
        } catch (e) {
          logger.warn(`[ApproveHeroAssets] regen failed for "${concept.name}"`, { error: (e as Error).message });
          historyLines.push(`Regeneration failed for "${concept.name}": ${(e as Error).message}`);
        }
      }
    }

    const approvedCount = heroConcepts.filter(c => c.approved).length;
    const hasRejections = decisions.some(d => !d.approved);

    // Two distinct flows:
    // 1) Finalization: all decisions are approved → transition to 'processing' (Phase 2)
    // 2) Regeneration: any decision is rejected → regenerate those, stay 'awaiting_review'
    const nextStatus = (!hasRejections && approvedCount > 0) ? 'processing' : 'awaiting_review';

    await docRef.update({
      status: nextStatus,
      metadata: {
        ...(job.metadata ?? {}),
        heroConcepts,
        ...(isNpcAccessoryApproval ? { npcAccessoryConcepts: heroConcepts } : {}),
      },
      history: [...job.history, ...historyLines],
      updatedAt: new Date().toISOString(),
    });

    logger.info('[ApproveHeroAssets] decisions applied', { jobId, approvedCount, nextStatus, total: heroConcepts.length, isNpcAccessoryApproval });
    return res.json({
      status: nextStatus === 'processing' ? 'approved' : 'awaiting_review',
      approvedCount,
      totalConcepts: heroConcepts.length,
      heroConcepts,
      message: nextStatus === 'processing'
        ? `${approvedCount} ${isNpcAccessoryApproval ? 'NPC accessories' : 'hero assets'} approved — ready for 3D generation`
        : 'Updated — review remaining concepts',
    });
  } catch (err) {
    logger.error('approve-hero-assets failed', { error: errorMessage(err) });
    return res.status(500).json({ error: 'Internal error' });
  }
});

// ── Approve / reject AI-generated 2D images before they upload as Roblox Decals ──
// Session 231 — gate for Roblox moderation. The pipeline pauses with
// status='awaiting_review' + metadata.approvalKind='decal_upload' +
// metadata.pendingDecalApprovals (public candidates) +
// metadata.pendingDecalApprovalsInternal (storagePaths for resume upload).
// iOS submits the slotIds the user kept checked. Anything missing from
// approvedSlotIds is dropped — its texture slot ends up empty/default in-game.
app.post('/api/content/jobs/:jobId/approve-decals', async (req: AuthedRequest, res) => {
  try {
    const { jobId } = req.params;
    const { approvedSlotIds } = (req.body ?? {}) as { approvedSlotIds?: string[] };
    if (!Array.isArray(approvedSlotIds)) {
      return res.status(400).json({ error: 'approvedSlotIds (string[]) is required' });
    }

    const docRef = db.collection('generationJobs').doc(jobId);
    const doc = await docRef.get();
    if (!doc.exists) return res.status(404).json({ error: 'Job not found' });
    const job = doc.data() as GenerationJob;
    if (job.userId !== req.userId) return res.status(403).json({ error: 'Forbidden' });
    if (job.status !== 'awaiting_review') {
      return res.status(400).json({ error: `Job is not awaiting review (status: ${job.status})` });
    }
    if (job.metadata?.approvalKind !== 'decal_upload') {
      return res.status(400).json({ error: 'Job is not waiting on decal approval' });
    }

    const candidates = parseInternalCandidates(job.metadata?.pendingDecalApprovalsInternal);
    const candidateIds = new Set(candidates.map((c) => c.slotId));
    const sanitizedApproved = approvedSlotIds.filter((id) => typeof id === 'string' && candidateIds.has(id));
    const skipped = candidates
      .map((c) => c.slotId)
      .filter((id) => !sanitizedApproved.includes(id));

    await docRef.update({
      status: 'processing',
      metadata: {
        ...(job.metadata ?? {}),
        approvedDecalSlotIds: sanitizedApproved,
        skippedDecalSlots: skipped,
        approvalPhase: 'decal_approved',
      },
      history: [
        ...job.history,
        `User approved ${sanitizedApproved.length}/${candidates.length} decal previews — uploading to Roblox`,
      ],
      updatedAt: new Date().toISOString(),
    });

    logger.info('[ApproveDecals] decisions applied', {
      jobId,
      approved: sanitizedApproved.length,
      skipped: skipped.length,
      total: candidates.length,
    });

    return res.json({
      status: 'approved',
      approvedCount: sanitizedApproved.length,
      skippedCount: skipped.length,
      totalCandidates: candidates.length,
      message: sanitizedApproved.length === 0
        ? 'No decals approved — game will use default textures.'
        : `${sanitizedApproved.length} decal(s) approved — uploading to Roblox.`,
    });
  } catch (err) {
    logger.error('approve-decals failed', { error: errorMessage(err) });
    return res.status(500).json({ error: 'Internal error' });
  }
});

app.post('/api/voice/transcriptions', async (req: AuthedRequest, res) => {
  try {
    const body = (req.body ?? {}) as TranscriptionRequest;
    if (typeof body.audioBase64 !== 'string' || !body.audioBase64.trim()) {
      return res.status(400).json({ error: 'audioBase64 is required' });
    }

    const audioAsset = await ingestAttachment(req.userId ?? 'unknown-user', {
      type: 'audio',
      name: body.fileName ?? 'voice-note.m4a',
      mimeType: body.mimeType ?? 'audio/m4a',
      contentBase64: body.audioBase64,
      metadata: body.metadata,
    });

    const jobId = uuidv4();
    const now = new Date().toISOString();
    const job: GenerationJob = {
      id: jobId,
      userId: req.userId ?? 'unknown-user',
      prompt: 'Transcribe uploaded audio',
      provider: 'deepgram',
      kind: 'transcription',
      status: 'queued',
      createdAt: now,
      updatedAt: now,
      artifacts: [],
      history: ['Queued transcription job', `Audio asset: ${audioAsset.id}`],
      dispatchMode: getJobDispatchMode() as JobDispatchMode,
      metadata: {
        ...(body.metadata ?? {}),
        audioAssetId: audioAsset.id,
        audioUrl: audioAsset.downloadUrl,
        audioMimeType: audioAsset.mimeType,
        audioName: audioAsset.name,
      },
    };

    await db.collection('generationJobs').doc(jobId).set(job);
    const completed = await runGenerationJobLifecycle(jobId, job);
    const transcriptArtifact = completed.artifacts.find((artifact) => artifact.type === 'text');
    const response: TranscriptionResponse = {
      jobId,
      status: completed.status,
      transcript: transcriptArtifact?.content ?? completed.resultText,
      confidence: typeof completed.metadata?.transcriptionConfidence === 'number'
        ? completed.metadata.transcriptionConfidence as number
        : undefined,
      locale: typeof completed.metadata?.transcriptionLocale === 'string'
        ? completed.metadata.transcriptionLocale as string
        : undefined,
      artifact: transcriptArtifact,
    };
    return res.json(response);
  } catch (error) {
    logger.error('Transcription failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

