app.get('/api/export/artifact/:id', async (req: AuthedRequest, res) => {
  const doc = await db.collection('artifacts').doc(req.params.id).get();
  if (!doc.exists) {
    return res.status(404).json({ error: 'Artifact not found' });
  }

  const data = doc.data() as { userId: string; downloadUrl?: string };
  if (data.userId !== req.userId) {
    return res.status(403).json({ error: 'Forbidden' });
  }

  if (!data.downloadUrl) {
    return res.status(409).json({ error: 'Artifact does not have a download URL yet' });
  }

  return res.redirect(302, data.downloadUrl);
});

app.post('/api/export/zip', async (req: AuthedRequest, res) => {
  const body = (req.body ?? {}) as { jobId?: string; artifactIds?: string[] };
  const jobId = typeof body.jobId === 'string' ? body.jobId.trim() : '';
  if (!jobId) {
    return res.status(400).json({ error: 'jobId is required' });
  }

  const jobDoc = await db.collection('generationJobs').doc(jobId).get();
  if (!jobDoc.exists) {
    return res.status(404).json({ error: 'Job not found' });
  }
  const jobData = jobDoc.data() as GenerationJob;
  if (jobData.userId !== req.userId) {
    return res.status(403).json({ error: 'Forbidden' });
  }

  const artifactIds = Array.isArray(body.artifactIds) && body.artifactIds.length > 0
    ? body.artifactIds
    : jobData.artifacts.map((a) => a.id);

  const artifacts = jobData.artifacts.filter((a) => artifactIds.includes(a.id) && (a.downloadUrl || a.url));
  if (artifacts.length === 0) {
    return res.status(409).json({ error: 'No downloadable artifacts found' });
  }

  const title = typeof jobData.metadata?.title === 'string' ? jobData.metadata.title.trim() : 'project';
  const safeName = title.replace(/[^a-zA-Z0-9_-]/g, '_').slice(0, 50) || 'project';
  const zipFileName = `${safeName}-export.zip`;

  try {
    const zipBuffer = await new Promise<Buffer>((resolve, reject) => {
      const chunks: Buffer[] = [];
      const archive = archiver('zip', { zlib: { level: 6 } });
      archive.on('data', (chunk: Buffer) => chunks.push(chunk));
      archive.on('end', () => resolve(Buffer.concat(chunks)));
      archive.on('error', reject);

      const fetches = artifacts.map(async (artifact) => {
        const artifactUrl = artifact.downloadUrl || artifact.url || '';
        try {
          const response = await fetch(artifactUrl);
          if (!response.ok) return;
          const buffer = Buffer.from(await response.arrayBuffer());
          const ext = artifact.type === 'project_bundle' ? 'json'
            : typeof artifact.type === 'string' ? artifact.type : 'bin';
          const name = artifact.name || `${artifact.id}.${ext}`;
          archive.append(buffer, { name });
        } catch (e) {
          logger.warn('Failed to fetch artifact for ZIP', { artifactId: artifact.id, error: errorMessage(e) });
        }
      });

      Promise.all(fetches).then(() => archive.finalize()).catch(reject);
    });

    const bucket = await resolvedBucket();
    const zipPath = `exports/${req.userId}/${jobId}/${zipFileName}`;
    const file = bucket.file(zipPath);
    await file.save(zipBuffer, { contentType: 'application/zip', resumable: false });
    const [signedUrl] = await file.getSignedUrl({
      action: 'read',
      expires: Date.now() + 7 * 24 * 60 * 60 * 1000,
    });

    return res.json({
      downloadUrl: signedUrl,
      fileName: zipFileName,
      sizeBytes: zipBuffer.length,
      artifactCount: artifacts.length,
    });
  } catch (zipError) {
    logger.error('ZIP export failed', { jobId, error: errorMessage(zipError) });
    return res.status(500).json({ error: 'Failed to create ZIP export' });
  }
});

// ──────────────────────────────────────────────
// Push Notifications — infrastructure
// ──────────────────────────────────────────────

type NotificationType = 'likes' | 'comments' | 'followers' | 'generations' | 'challenges';

interface NotificationPreferences {
  likes: boolean;
  comments: boolean;
  followers: boolean;
  generations: boolean;
  challenges: boolean;
}

const DEFAULT_NOTIFICATION_PREFS: NotificationPreferences = {
  likes: true,
  comments: true,
  followers: true,
  generations: true,
  challenges: true,
};

function notificationCategoryForPushData(data?: Record<string, string>): string | undefined {
  const type = data?.type;
  const suffix = data?.language === 'ru' ? 'RU' : 'EN';
  if (type === 'generation_review_needed') return `GENERATION_REVIEW_${suffix}`;
  if (type === 'generation_completed') return `GENERATION_READY_${suffix}`;
  if (type === 'generation_failed') return `GENERATION_FAILED_${suffix}`;
  if (type === 'generation_stage_completed') return `GENERATION_PROGRESS_${suffix}`;
  if (type === 'challenge_retention' || data?.route === 'challenges') return `CHALLENGE_RETENTION_${suffix}`;
  return undefined;
}

function shouldPruneFailedFcmToken(code = '', message = ''): boolean {
  if (
    code === 'messaging/registration-token-not-registered' ||
    code === 'messaging/invalid-registration-token' ||
    code === 'messaging/invalid-recipient' ||
    code === 'messaging/mismatched-credential' ||
    code === 'messaging/invalid-package-name'
  ) {
    return true;
  }
  return code === 'messaging/invalid-argument' && /registration token|not a valid fcm|invalid token/i.test(message);
}

async function sendPushNotification(
  targetUserId: string,
  notification: { title: string; body: string },
  data?: Record<string, string>,
  notificationType?: NotificationType,
): Promise<void> {
  try {
    const pushType = data?.type;
    const pushJobId = data?.jobId;
    const isGenerationPush = typeof pushType === 'string' && pushType.startsWith('generation_');
    const deviceDoc = await db.collection('deviceTokens').doc(targetUserId).get();
    if (!deviceDoc.exists) {
      if (isGenerationPush) {
        logger.warn('sendPushNotification skipped: no device token doc', { targetUserId, pushType, jobId: pushJobId });
      }
      return;
    }

    const deviceData = deviceDoc.data() ?? {};
    const tokens: string[] = Array.isArray(deviceData.tokens) ? deviceData.tokens : [];
    if (tokens.length === 0) {
      if (isGenerationPush) {
        logger.warn('sendPushNotification skipped: no device tokens', { targetUserId, pushType, jobId: pushJobId });
      }
      return;
    }

    if (notificationType) {
      const prefs: NotificationPreferences = {
        ...DEFAULT_NOTIFICATION_PREFS,
        ...(typeof deviceData.preferences === 'object' && deviceData.preferences !== null
          ? deviceData.preferences as Partial<NotificationPreferences>
          : {}),
      };
      if (!prefs[notificationType]) {
        if (isGenerationPush) {
          logger.warn('sendPushNotification skipped: notification preference disabled', {
            targetUserId,
            notificationType,
            pushType,
            jobId: pushJobId,
          });
        }
        return;
      }
    }

    const pushKeySource = isGenerationPush && pushJobId
      ? `${pushType}:${pushJobId}`
      : notificationType ?? 'default';
    const lastPushAtByKey: Record<string, string> =
      typeof deviceData.lastPushAtByKey === 'object' && deviceData.lastPushAtByKey !== null
        ? deviceData.lastPushAtByKey as Record<string, string>
        : {};
    const lastPushAtRaw = typeof lastPushAtByKey[pushKeySource] === 'string'
      ? lastPushAtByKey[pushKeySource]
      : (pushKeySource === 'default' && typeof deviceData.lastPushAt === 'string' ? deviceData.lastPushAt : '');
    const lastPushAt = lastPushAtRaw ? new Date(lastPushAtRaw).getTime() : 0;
    if (lastPushAt > 0 && Date.now() - lastPushAt < 60_000) {
      if (isGenerationPush) {
        logger.info('sendPushNotification skipped: throttled', {
          targetUserId,
          pushType,
          jobId: pushJobId,
          pushKeySource,
        });
      }
      return;
    }

    const apnsCategory = notificationCategoryForPushData(data);
    // Session 338 round 10: explicit `alert` object inside `apns.payload.aps`.
    // The FCM Admin SDK does NOT always merge top-level `notification.{title,
    // body}` into `apns.payload.aps.alert` when an `apns.payload.aps` block
    // already exists (e.g. when we set `sound`/`category`) — the resulting
    // push becomes silent on iOS (no banner, no willPresent) and only the
    // data payload reaches the app. iOS then drops the entry straight into
    // Notification Center, which matched the user's symptom exactly.
    const message = {
      notification: { title: notification.title, body: notification.body },
      data: data ?? {},
      apns: {
        headers: {
          'apns-push-type': 'alert',
          'apns-priority': '10',
        },
        payload: {
          aps: {
            alert: {
              title: notification.title,
              body: notification.body,
            },
            sound: 'default',
            ...(apnsCategory ? { category: apnsCategory } : {}),
          },
        },
      },
      tokens,
    };

    const response = await getMessaging().sendEachForMulticast(message);
    const failureDiagnostics = response.responses.flatMap((resp, idx) => {
      if (resp.success) return [];
      const code = resp.error?.code ?? 'unknown';
      const messageText = resp.error?.message ?? '';
      return [{
        code,
        message: messageText.slice(0, 240),
        tokenIndex: idx,
        tokenSuffix: tokens[idx]?.slice(-10) ?? '',
      }];
    });
    if (isGenerationPush) {
      logger.info('sendPushNotification FCM multicast completed', {
        targetUserId,
        pushType,
        jobId: pushJobId,
        successCount: response.successCount,
        failureCount: response.failureCount,
        tokenCount: tokens.length,
      });
      if (failureDiagnostics.length > 0) {
        logger.warn('sendPushNotification FCM multicast failures', {
          targetUserId,
          pushType,
          jobId: pushJobId,
          failureCodes: Array.from(new Set(failureDiagnostics.map((item) => item.code))),
          failures: failureDiagnostics.slice(0, 5),
        });
      }
    }

    const invalidTokens: string[] = [];
    response.responses.forEach((resp, idx) => {
      if (!resp.success && resp.error && shouldPruneFailedFcmToken(resp.error.code, resp.error.message)) {
        invalidTokens.push(tokens[idx]);
      }
    });

    const pushedAt = new Date().toISOString();
    const updates: Record<string, unknown> = response.successCount > 0
      ? {
          lastPushAt: pushedAt,
          lastPushAtByKey: {
            ...lastPushAtByKey,
            [pushKeySource]: pushedAt,
          },
        }
      : {
          lastPushFailureAt: pushedAt,
          lastPushFailureByKey: {
            ...(typeof deviceData.lastPushFailureByKey === 'object' && deviceData.lastPushFailureByKey !== null
              ? deviceData.lastPushFailureByKey as Record<string, string>
              : {}),
            [pushKeySource]: pushedAt,
          },
          ...(failureDiagnostics.length > 0
            ? {
                lastPushFailureCodes: Array.from(new Set(failureDiagnostics.map((item) => item.code))),
              }
            : {}),
        };
    if (invalidTokens.length > 0) {
      const validTokens = tokens.filter((t) => !invalidTokens.includes(t));
      updates.tokens = validTokens;
      if (isGenerationPush) {
        logger.warn('sendPushNotification pruned invalid FCM tokens', {
          targetUserId,
          pushType,
          jobId: pushJobId,
          prunedCount: invalidTokens.length,
          remainingCount: validTokens.length,
        });
      }
    }
    await db.collection('deviceTokens').doc(targetUserId).set(updates, { merge: true });
  } catch (err) {
    logger.warn('sendPushNotification failed', { targetUserId, error: errorMessage(err) });
  }
}

app.post('/api/notifications/register-device', async (req: AuthedRequest, res) => {
  try {
    const userId = req.userId ?? 'unknown-user';
    const token = typeof req.body?.token === 'string' ? req.body.token.trim() : '';
    const platform = typeof req.body?.platform === 'string' ? req.body.platform : 'ios';
    if (!token) {
      return res.status(400).json({ error: 'token is required' });
    }

    const docRef = db.collection('deviceTokens').doc(userId);
    const doc = await docRef.get();
    const existing = doc.exists ? doc.data() : {};
    const tokens: string[] = Array.isArray(existing?.tokens) ? existing.tokens : [];
    if (!tokens.includes(token)) {
      tokens.push(token);
    }

    await docRef.set({
      tokens,
      platform,
      lastSeen: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    }, { merge: true });

    return res.json({ registered: true });
  } catch (error) {
    logger.error('Register device token failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

