app.post('/api/moderation/check', async (req: AuthedRequest, res) => {
  const body = (req.body ?? {}) as ModerationCheckRequest & { imageUrl?: string };
  const text = typeof body.text === 'string' ? body.text : '';
  const imageUrl = typeof body.imageUrl === 'string' ? body.imageUrl.trim() : '';

  const moderation = await runModerationPipeline({
    userId: req.userId ?? 'unknown-user',
    text: text || (imageUrl ? '[image moderation]' : ''),
    stage: body.stage ?? 'input',
    requestedProvider: body.provider,
    artifactType: body.artifactType,
    metadata: body.metadata,
  });

  if (imageUrl) {
    const imageResult = await moderateImage(imageUrl);
    const combinedSeverity: ModerationCheckResponse['severity'] =
      imageResult.severity === 'blocked' ? 'blocked'
        : moderation.severity === 'blocked' ? 'blocked'
          : imageResult.severity === 'review' || moderation.severity === 'review' ? 'review'
            : 'safe';
    const combinedAllowed = combinedSeverity !== 'blocked';
    res.json({
      ...moderation,
      allowed: combinedAllowed,
      severity: combinedSeverity,
      action: combinedSeverity === 'blocked' ? 'block' : combinedSeverity === 'review' ? 'review' : moderation.action,
      imageModeration: imageResult,
    });
    return;
  }

  res.json(moderation);
});

