app.post('/api/social/projects/publish', async (req: AuthedRequest, res) => {
  try {
    const userId = req.userId ?? 'unknown-user';
    const profile = await ensureSocialProfile(userId, req.authToken);
    const title = typeof req.body?.title === 'string' ? req.body.title.trim() : '';
    const description = typeof req.body?.description === 'string' ? req.body.description.trim() : '';
    const projectKind = normalizeProjectKind(req.body?.projectKind);
    const artifactIds = Array.isArray(req.body?.artifactIds)
      ? req.body.artifactIds.filter((item: unknown): item is string => typeof item === 'string' && item.trim().length > 0)
      : [];
    const tags = parseTags(req.body?.tags);
    const screenshotUrls: string[] = Array.isArray(req.body?.screenshotUrls)
      ? req.body.screenshotUrls.filter((u: unknown): u is string => typeof u === 'string' && u.trim().length > 0).slice(0, 5)
      : [];
    const category = typeof req.body?.category === 'string' ? req.body.category.trim() : undefined;
    const moderation = await runModerationPipeline({
      userId,
      text: [title, description, tags.join(', ')].filter(Boolean).join('\n'),
      stage: 'publication',
      metadata: { projectKind, artifactIds },
    });

    if (!title || !description || artifactIds.length === 0) {
      return res.status(400).json({ error: 'title, description, and artifactIds are required' });
    }
    if (!moderation.allowed) {
      return res.status(400).json({ error: moderation.reason, moderation });
    }

    const artifactPreviewUrls = await resolveArtifactPreviewUrls(userId, artifactIds);
    const allPreviewUrls = [...artifactPreviewUrls, ...screenshotUrls];
    const now = new Date().toISOString();
    const projectId = uuidv4();
    const postId = uuidv4();

    const imageModeration = await moderateImageUrls(userId, allPreviewUrls, 'project', projectId);
    if (!imageModeration.allowed) {
      return res.status(400).json({ error: imageModeration.reason, moderation: imageModeration });
    }

    const effectiveSeverity: ModerationCheckResponse['severity'] =
      moderation.severity === 'review' || imageModeration.severity === 'review' ? 'review' : moderation.severity;

    const project: SocialProject = {
      id: projectId,
      authorId: userId,
      title,
      description: moderation.rewrittenText?.trim() || description,
      projectKind,
      artifactIds,
      artifactTypes: await resolveArtifactTypes(userId, artifactIds),
      coverImageUrl: allPreviewUrls[0],
      tags,
      ...(screenshotUrls.length > 0 ? { screenshotUrls } : {}),
      ...(category ? { category: category as ContentCategory } : {}),
      moderationStatus: effectiveSeverity === 'review' ? 'review' : 'approved',
      publicationState: effectiveSeverity === 'review' ? 'review' : 'published',
      saveCount: 0,
      downloadCount: 0,
      createdAt: now,
      updatedAt: now,
    };
    const post: SocialPost = {
      id: postId,
      projectId,
      authorId: userId,
      authorName: profile.displayName,
      authorAvatarUrl: profile.avatarUrl,
      title,
      description: project.description,
      projectKind,
      tags,
      previewUrls: allPreviewUrls,
      artifactSummary: await summarizeArtifacts(userId, artifactIds),
      moderationStatus: project.moderationStatus,
      publicationState: project.publicationState,
      likes: 0,
      likedByViewer: false,
      savedByViewer: false,
      commentCount: 0,
      downloadCount: 0,
      authorHeadline: profile.headline,
      artifactTypes: project.artifactTypes,
      createdAt: now,
    };

    if (effectiveSeverity === 'review') {
      const reviewReason = [moderation.reason, imageModeration.reason].filter(Boolean).join('; ');
      const moderationCase = await ensureModerationCase({
        eventId: moderation.eventId ?? imageModeration.eventId ?? uuidv4(),
        userId,
        entityType: 'project',
        entityId: projectId,
        severity: effectiveSeverity,
        reason: reviewReason || moderation.reason,
        evidence: { title, description, tags, imageModeration: imageModeration.severity !== 'safe' ? imageModeration : undefined },
      });
      project.moderationCaseId = moderationCase.id;
    }

    await db.collection('socialProjects').doc(projectId).set(project);
    await db.collection('socialPosts').doc(postId).set(post);
    await db.collection('socialProfiles').doc(userId).set({
      publishedProjectCount: profile.publishedProjectCount + 1,
      updatedAt: now,
    }, { merge: true });

    // Index to Algolia for full-text search (non-blocking)
    if (post.publicationState === 'published') {
      indexPostToAlgolia(post).catch(() => {});
    }

    computeAndAssignBadges(userId).catch(() => {});

    return res.json({ project, post, moderation, imageModeration: imageModeration.severity !== 'safe' ? imageModeration : undefined });
  } catch (error) {
    logger.error('Publish project failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.post('/api/social/posts/:postId/like', async (req: AuthedRequest, res) => {
  const userId = req.userId ?? 'unknown-user';
  const postId = req.params.postId;
  const postRef = db.collection('socialPosts').doc(postId);
  const likeRef = db.collection('socialProfiles').doc(userId).collection('likes').doc(postId);
  const dislikeRef = db.collection('socialProfiles').doc(userId).collection('dislikes').doc(postId);
  const [postDoc, likeDoc, dislikeDoc] = await Promise.all([postRef.get(), likeRef.get(), dislikeRef.get()]);
  if (!postDoc.exists) {
    return res.status(404).json({ error: 'Post not found' });
  }

  const current = postDoc.data() as SocialPost;
  const isLiked = likeDoc.exists;
  const updates: Record<string, unknown> = {};
  const ops: Promise<unknown>[] = [];
  if (isLiked) {
    ops.push(likeRef.delete());
    updates.likes = Math.max(0, (current.likes ?? 0) - 1);
  } else {
    ops.push(likeRef.set({ createdAt: new Date().toISOString() }));
    updates.likes = (current.likes ?? 0) + 1;
    if (dislikeDoc.exists) {
      ops.push(dislikeRef.delete());
      updates.dislikes = Math.max(0, (current.dislikes ?? 0) - 1);
    }
  }
  ops.push(postRef.set(updates, { merge: true }));
  await Promise.all(ops);

  if (!isLiked && current.authorId && current.authorId !== userId) {
    const likerProfile = await ensureSocialProfile(userId, req.authToken);
    const postTitle = typeof current.title === 'string' ? current.title.slice(0, 40) : 'your post';
    sendPushNotification(
      current.authorId,
      { title: 'New Like', body: `${likerProfile.displayName} liked "${postTitle}"` },
      { type: 'like', postId },
      'likes',
    ).catch(() => {});
  }

  return res.json({ liked: !isLiked, likes: updates.likes });
});

