app.post('/api/social/posts/:postId/download', async (req: AuthedRequest, res) => {
  try {
    const postId = req.params.postId;
    const postRef = db.collection('socialPosts').doc(postId);
    const postDoc = await postRef.get();
    if (!postDoc.exists) {
      return res.status(404).json({ error: 'Post not found' });
    }
    const post = postDoc.data() as SocialPost;
    await postRef.set({ downloadCount: (post.downloadCount ?? 0) + 1 }, { merge: true });

    const projectRef = db.collection('socialProjects').doc(post.projectId);
    const projectDoc = await projectRef.get();
    if (projectDoc.exists) {
      await projectRef.set({ downloadCount: FieldValue.increment(1) }, { merge: true });
    }

    const authorId = post.authorId;
    await db.collection('socialProfiles').doc(authorId).set(
      { totalDownloads: FieldValue.increment(1) },
      { merge: true },
    );

    computeAndAssignBadges(authorId).catch(() => {});

    return res.json({ downloaded: true, downloadCount: (post.downloadCount ?? 0) + 1 });
  } catch (error) {
    logger.error('Download tracking failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.get('/api/social/posts/:postId/comments', async (req: AuthedRequest, res) => {
  const userId = req.userId ?? 'unknown-user';
  const postId = req.params.postId;
  const snapshot = await db.collection('socialPosts').doc(postId).collection('comments').orderBy('createdAt', 'asc').get();
  // Bug 20: fetch this user's like docs for these comments in one query so UI can render filled hearts.
  const likedSnapshot = await db
    .collection('socialProfiles').doc(userId).collection('commentLikes')
    .where('postId', '==', postId)
    .get();
  const likedIds = new Set(likedSnapshot.docs.map((d) => (d.data() as { commentId?: string }).commentId).filter(Boolean));
  const comments = snapshot.docs.map((doc) => ({
    ...(doc.data() as SocialComment),
    likeCount: (doc.data() as Partial<SocialComment>).likeCount ?? 0,
    moderationStatus: (doc.data() as Partial<SocialComment>).moderationStatus ?? 'approved',
    id: doc.id,
    likedByViewer: likedIds.has(doc.id),
  }));
  return res.json({ comments });
});

app.post('/api/social/posts/:postId/comments', async (req: AuthedRequest, res) => {
  try {
    const userId = req.userId ?? 'unknown-user';
    const profile = await ensureSocialProfile(userId, req.authToken);
    const content = typeof req.body?.content === 'string' ? req.body.content.trim() : '';
    if (!content) {
      return res.status(400).json({ error: 'Comment content is required' });
    }

    const moderation = await runModerationPipeline({
      userId,
      text: content,
      stage: 'publication',
      metadata: { postId: req.params.postId, entity: 'comment' },
    });
    if (!moderation.allowed) {
      return res.status(400).json({ error: moderation.reason, moderation });
    }

    const commentId = uuidv4();
    const createdAt = new Date().toISOString();
    const comment: SocialComment = {
      id: commentId,
      postId: req.params.postId,
      authorId: userId,
      authorName: profile.displayName,
      content: moderation.rewrittenText?.trim() || content,
      parentCommentId: typeof req.body?.parentCommentId === 'string' ? req.body.parentCommentId : undefined,
      likeCount: 0,
      moderationStatus: moderation.severity === 'review' ? 'review' : 'approved',
      createdAt,
    };

    await db.collection('socialPosts').doc(req.params.postId).collection('comments').doc(commentId).set(comment);
    const postDoc = await db.collection('socialPosts').doc(req.params.postId).get();
    const postData = postDoc.data() as SocialPost | undefined;
    const commentCount = postData?.commentCount ?? 0;
    await db.collection('socialPosts').doc(req.params.postId).set({ commentCount: commentCount + 1 }, { merge: true });

    if (postData?.authorId && postData.authorId !== userId) {
      const postTitle = typeof postData.title === 'string' ? postData.title.slice(0, 40) : 'your post';
      sendPushNotification(
        postData.authorId,
        { title: 'New Comment', body: `${profile.displayName} commented on "${postTitle}"` },
        { type: 'comment', postId: req.params.postId, commentId },
        'comments',
      ).catch(() => {});
    }

    if (comment.parentCommentId) {
      const parentDoc = await db.collection('socialPosts').doc(req.params.postId)
        .collection('comments').doc(comment.parentCommentId).get();
      const parentComment = parentDoc.data() as SocialComment | undefined;
      if (parentComment?.authorId && parentComment.authorId !== userId) {
        sendPushNotification(
          parentComment.authorId,
          { title: 'New Reply', body: `${profile.displayName} replied to your comment` },
          { type: 'comment_reply', postId: req.params.postId, commentId },
          'comments',
        ).catch(() => {});
      }
    }

    return res.json({ comment, moderation });
  } catch (error) {
    logger.error('Create comment failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.post('/api/social/posts/:postId/comments/:commentId/like', async (req: AuthedRequest, res) => {
  try {
    const userId = req.userId ?? 'unknown-user';
    const { postId, commentId } = req.params;
    const commentRef = db.collection('socialPosts').doc(postId).collection('comments').doc(commentId);
    // Bug 20: per-user like doc so repeated taps toggle instead of infinite +1.
    // Mirrors the existing post-like pattern (socialProfiles/{uid}/likes/{postId}).
    const likeRef = db.collection('socialProfiles').doc(userId).collection('commentLikes').doc(`${postId}_${commentId}`);
    const [commentDoc, likeDoc] = await Promise.all([commentRef.get(), likeRef.get()]);
    if (!commentDoc.exists) {
      return res.status(404).json({ error: 'Comment not found' });
    }
    const current = commentDoc.data() as SocialComment;
    const wasLiked = likeDoc.exists;
    const newCount = wasLiked
      ? Math.max(0, (current.likeCount ?? 0) - 1)
      : (current.likeCount ?? 0) + 1;
    const ops: Promise<unknown>[] = [commentRef.update({ likeCount: newCount })];
    if (wasLiked) {
      ops.push(likeRef.delete());
    } else {
      ops.push(likeRef.set({ postId, commentId, createdAt: new Date().toISOString() }));
    }
    await Promise.all(ops);
    return res.json({ liked: !wasLiked, likeCount: newCount });
  } catch (error) {
    logger.error('Like comment failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

