app.put('/api/social/projects/:projectId', async (req: AuthedRequest, res) => {
  try {
    const userId = req.userId ?? 'unknown-user';
    const projectId = req.params.projectId;
    const projectRef = db.collection('socialProjects').doc(projectId);
    const projectDoc = await projectRef.get();
    if (!projectDoc.exists) {
      return res.status(404).json({ error: 'Project not found' });
    }
    const project = projectDoc.data() as SocialProject;
    if (project.authorId !== userId) {
      return res.status(403).json({ error: 'Not authorized' });
    }
    const body = req.body ?? {};
    const now = new Date().toISOString();
    const updates: Record<string, unknown> = { updatedAt: now };
    if (typeof body.title === 'string' && body.title.trim()) updates.title = body.title.trim();
    if (typeof body.description === 'string') updates.description = body.description.trim();
    if (Array.isArray(body.tags)) updates.tags = parseTags(body.tags);
    if (Array.isArray(body.screenshotUrls)) updates.screenshotUrls = body.screenshotUrls.filter((u: unknown) => typeof u === 'string').slice(0, 5);
    if (typeof body.category === 'string' && body.category.trim()) updates.category = body.category.trim();
    if (typeof body.changelog === 'string' && body.changelog.trim()) {
      const existing = project.changelog ?? [];
      const version = `${existing.length + 1}.0`;
      existing.push({ version, date: now, changes: body.changelog.trim().split('\n').filter(Boolean) });
      updates.changelog = existing;
      updates.version = version;
    }
    await projectRef.set(updates, { merge: true });
    const postSnapshot = await db.collection('socialPosts').where('projectId', '==', projectId).limit(1).get();
    if (!postSnapshot.empty) {
      const postUpdates: Record<string, unknown> = {};
      if (updates.title) postUpdates.title = updates.title;
      if (updates.description) postUpdates.description = updates.description;
      if (updates.tags) postUpdates.tags = updates.tags;
      if (updates.screenshotUrls) {
        const existingPost = postSnapshot.docs[0].data() as SocialPost;
        const oldScreenshots = project.screenshotUrls ?? [];
        const artifactUrls = existingPost.previewUrls.filter((u) => !oldScreenshots.includes(u));
        postUpdates.previewUrls = [...artifactUrls, ...(updates.screenshotUrls as string[])];
      }
      if (Object.keys(postUpdates).length > 0) {
        await postSnapshot.docs[0].ref.set(postUpdates, { merge: true });
        // Re-index updated post to Algolia
        const updatedPost = { ...(postSnapshot.docs[0].data() as SocialPost), ...postUpdates, id: postSnapshot.docs[0].id };
        indexPostToAlgolia(updatedPost as SocialPost).catch(() => {});
      }
    }
    const updated = { ...project, ...updates } as SocialProject;
    return res.json({ project: updated });
  } catch (error) {
    logger.error('Update project failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

