app.get('/api/social/profiles/:profileId/portfolio', async (req: AuthedRequest, res) => {
  try {
    const profileId = req.params.profileId;
    const profile = await ensureSocialProfile(profileId);
    const limit = Math.min(Number(req.query.limit) || 50, 200);
    const cursor = typeof req.query.cursor === 'string' ? req.query.cursor : undefined;
    let query: FirebaseFirestore.Query = db.collection('socialPosts')
      .where('authorId', '==', profileId)
      .where('publicationState', '==', 'published')
      .orderBy('createdAt', 'desc');
    if (cursor) query = query.startAfter(cursor);
    const postsSnapshot = await query.limit(limit + 1).get();
    const docs = postsSnapshot.docs;
    const hasMore = docs.length > limit;
    const pageDocs = hasMore ? docs.slice(0, limit) : docs;
    const posts = pageDocs.map((doc) => normalizeSocialPost({ ...(doc.data() as SocialPost), id: doc.id }));
    return res.json({
      profile,
      publishedPosts: posts,
      totalCount: profile.publishedProjectCount,
      nextCursor: hasMore ? posts[posts.length - 1]?.createdAt : undefined,
    });
  } catch (error) {
    logger.error('Portfolio fetch failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.get('/api/social/leaderboard', async (req: AuthedRequest, res) => {
  try {
    const period = (req.query.period === 'day' || req.query.period === 'week' || req.query.period === 'month') ? req.query.period : 'all';
    const limit = Math.min(Number(req.query.limit) || 50, 200);
    const profilesSnapshot = await db.collection('socialProfiles').orderBy('totalLikes', 'desc').limit(limit * 3).get();
    const creators = profilesSnapshot.docs.map((doc, idx) => {
      const p = doc.data() as SocialProfile;
      return {
        profile: { ...p, id: doc.id },
        rank: idx + 1,
        totalScore: (p.totalLikes ?? 0) + (p.totalDownloads ?? 0) * 2 + (p.followerCount ?? 0) * 3,
        period: period as 'day' | 'week' | 'month' | 'all',
      };
    }).sort((a, b) => b.totalScore - a.totalScore).slice(0, limit).map((c, idx) => ({ ...c, rank: idx + 1 }));
    return res.json({ creators, period });
  } catch (error) {
    logger.error('Leaderboard fetch failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.get('/api/social/leaderboards', async (req: AuthedRequest, res) => {
  try {
    const type = (req.query.type === 'authors' || req.query.type === 'games' || req.query.type === 'content')
      ? req.query.type : 'authors';
    const period = (req.query.period === 'day' || req.query.period === 'week' || req.query.period === 'month')
      ? req.query.period : 'all';
    const category = typeof req.query.category === 'string' ? req.query.category : undefined;
    const limit = Math.min(Number(req.query.limit) || 50, 200);

    const periodStart = leaderboardPeriodStart(period);

    if (type === 'authors') {
      let entries: { rank: number; score: number; profile: SocialProfile }[];

      if (period === 'all') {
        const profilesSnapshot = await db.collection('socialProfiles')
          .orderBy('totalLikes', 'desc').limit(limit * 3).get();
        entries = profilesSnapshot.docs
          .map((doc) => {
            const p = doc.data() as SocialProfile;
            return {
              rank: 0,
              score: (p.totalLikes ?? 0) * 3 + (p.totalDownloads ?? 0) * 2 + (p.followerCount ?? 0) * 5,
              profile: { ...p, id: doc.id },
            };
          })
          .sort((a, b) => b.score - a.score)
          .slice(0, limit)
          .map((e, idx) => ({ ...e, rank: idx + 1 }));
      } else {
        const postsSnapshot = await db.collection('socialPosts')
          .orderBy('createdAt', 'desc').limit(1000).get();
        const authorAgg = new Map<string, { likes: number; downloads: number; comments: number }>();
        for (const doc of postsSnapshot.docs) {
          const post = doc.data() as SocialPost;
          if (periodStart && Date.parse(post.createdAt) < periodStart) continue;
          if (post.publicationState === 'deleted' || post.moderationStatus !== 'approved') continue;
          const prev = authorAgg.get(post.authorId) ?? { likes: 0, downloads: 0, comments: 0 };
          prev.likes += post.likes ?? 0;
          prev.downloads += post.downloadCount ?? 0;
          prev.comments += post.commentCount ?? 0;
          authorAgg.set(post.authorId, prev);
        }
        const topAuthorIds = [...authorAgg.entries()]
          .map(([id, s]) => ({ id, score: s.likes * 3 + s.downloads * 2 + s.comments }))
          .sort((a, b) => b.score - a.score)
          .slice(0, limit);
        entries = [];
        for (const { id, score } of topAuthorIds) {
          const profileDoc = await db.collection('socialProfiles').doc(id).get();
          if (profileDoc.exists) {
            entries.push({
              rank: entries.length + 1,
              score,
              profile: { ...(profileDoc.data() as SocialProfile), id: profileDoc.id },
            });
          }
        }
      }

      const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
      let risingStars: { rank: number; score: number; profile: SocialProfile }[] = [];
      try {
        const risingSnapshot = await db.collection('socialProfiles')
          .where('createdAt', '>=', thirtyDaysAgo)
          .orderBy('createdAt', 'desc')
          .limit(200)
          .get();
        risingStars = risingSnapshot.docs
          .map((doc) => {
            const p = doc.data() as SocialProfile;
            return {
              rank: 0,
              score: (p.totalDownloads ?? 0) * 2 + (p.totalLikes ?? 0) * 3 + (p.followerCount ?? 0) * 5,
              profile: { ...p, id: doc.id },
            };
          })
          .filter((e) => e.score > 0)
          .sort((a, b) => b.score - a.score)
          .slice(0, 10)
          .map((e, idx) => ({ ...e, rank: idx + 1 }));
      } catch (risingErr) {
        logger.warn('Rising stars query failed (index may be missing)', risingErr);
      }

      return res.json({ type, period, entries, risingStars });
    }

    const postsSnapshot = await db.collection('socialPosts')
      .orderBy('createdAt', 'desc').limit(1000).get();
    let posts = postsSnapshot.docs
      .map((doc) => normalizeSocialPost({ ...(doc.data() as SocialPost), id: doc.id }))
      .filter((p) => p.publicationState !== 'deleted' && p.moderationStatus === 'approved');

    if (periodStart) {
      posts = posts.filter((p) => Date.parse(p.createdAt) >= periodStart);
    }
    if (type === 'games') {
      posts = posts.filter((p) => p.projectKind === 'game' || p.projectKind === 'clone');
    } else {
      posts = posts.filter((p) => p.projectKind !== 'game' && p.projectKind !== 'clone');
    }
    if (category) {
      posts = posts.filter((p) => p.tags.includes(category) || p.projectKind === category);
    }

    const entries = posts
      .map((post) => ({ post, score: computeFeedScore(post) }))
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)
      .map((e, idx) => ({ rank: idx + 1, score: e.score, post: e.post }));

    return res.json({ type, period, entries });
  } catch (error) {
    logger.error('Leaderboards fetch failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.get('/api/social/staff-picks', async (req, res) => {
  try {
    const limit = Math.min(Number(req.query.limit) || 50, 200);

    const staffPicksSnapshot = await db.collection('staffPicks')
      .orderBy('createdAt', 'desc').limit(limit).get();

    if (!staffPicksSnapshot.empty) {
      const postIds = staffPicksSnapshot.docs
        .map((doc) => (doc.data() as { postId?: string }).postId)
        .filter((id): id is string => Boolean(id));
      const posts: SocialPost[] = [];
      for (const postId of postIds) {
        const postDoc = await db.collection('socialPosts').doc(postId).get();
        if (postDoc.exists) {
          posts.push(normalizeSocialPost({ ...(postDoc.data() as SocialPost), id: postDoc.id }));
        }
      }
      return res.json({ posts, source: 'staffPicks' });
    }

    const collectionsSnapshot = await db.collection('socialCollections')
      .where('collectionType', '==', 'staff_picks')
      .orderBy('updatedAt', 'desc')
      .limit(5)
      .get();
    const collections = collectionsSnapshot.docs.map((doc) => ({
      ...(doc.data() as CuratedCollection), id: doc.id,
    }));
    const allPostIds = collections.flatMap((c) => c.postIds ?? []);
    const posts: SocialPost[] = [];
    for (const postId of allPostIds.slice(0, limit)) {
      const postDoc = await db.collection('socialPosts').doc(postId).get();
      if (postDoc.exists) {
        posts.push(normalizeSocialPost({ ...(postDoc.data() as SocialPost), id: postDoc.id }));
      }
    }
    return res.json({ posts, collections, source: 'collections' });
  } catch (error) {
    logger.error('Staff picks fetch failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

