app.get('/api/social/search', async (req: AuthedRequest, res) => {
  try {
    const query = typeof req.query.q === 'string' ? req.query.q : '';
    const contentType = req.query.contentType === 'game' || req.query.contentType === 'content' ? req.query.contentType : undefined;
    const category = typeof req.query.category === 'string' ? req.query.category : undefined;
    const sortBy = typeof req.query.sortBy === 'string' ? req.query.sortBy : 'newest';
    const limit = Math.min(Number(req.query.limit) || 50, 200);
    const cursor = typeof req.query.cursor === 'string' ? req.query.cursor : undefined;

    // Try Algolia first for text search, fall back to Firestore
    let postIds: string[] | null = null;
    if (query.trim()) {
      try {
        const filters: string[] = [];
        if (contentType) filters.push(`contentType:${contentType}`);
        if (category) filters.push(`category:${category} OR tags:${category}`);
        const hits = await algoliaSearch(query, filters.length > 0 ? filters.join(' AND ') : undefined, limit);
        if (hits.length > 0) {
          postIds = hits.map((h) => h.objectID);
        }
      } catch (err) {
        logger.warn('Algolia search failed, falling back to Firestore', err);
      }
    }

    let posts: SocialPost[];

    if (postIds !== null) {
      // Algolia returned results — fetch full docs from Firestore
      const chunks: string[][] = [];
      for (let i = 0; i < postIds.length; i += 10) {
        chunks.push(postIds.slice(i, i + 10));
      }
      const allDocs = (await Promise.all(
        chunks.map((ids) => db.collection('socialPosts').where('__name__', 'in', ids).get()),
      )).flatMap((snap) => snap.docs);
      const docMap = new Map(allDocs.map((doc) => [doc.id, doc]));
      posts = postIds
        .filter((id) => docMap.has(id))
        .map((id) => {
          const doc = docMap.get(id)!;
          return normalizeSocialPost({ ...(doc.data() as SocialPost), id: doc.id });
        })
        .filter((p) => p.publicationState !== 'deleted' && p.moderationStatus === 'approved');
    } else {
      // Firestore fallback (no query or Algolia unavailable)
      let dbQuery: FirebaseFirestore.Query = db.collection('socialPosts').orderBy('createdAt', 'desc');
      if (cursor) dbQuery = dbQuery.startAfter(cursor);
      const postsSnapshot = await dbQuery.limit(Math.min(limit * 4, 1000)).get();
      posts = postsSnapshot.docs
        .map((doc) => normalizeSocialPost({ ...(doc.data() as SocialPost), id: doc.id }))
        .filter((p) => p.publicationState !== 'deleted' && p.moderationStatus === 'approved');
      if (query) {
        const q = query.toLowerCase();
        posts = posts.filter((p) =>
          p.title.toLowerCase().includes(q) ||
          p.description.toLowerCase().includes(q) ||
          p.tags.some((t) => t.toLowerCase().includes(q)) ||
          p.authorName.toLowerCase().includes(q),
        );
      }
      if (contentType) {
        posts = posts.filter((p) => (p.contentType ?? inferContentType(p.projectKind)) === contentType);
      }
      if (category) {
        posts = posts.filter((p) => p.category === category || p.tags.includes(category));
      }
    }

    switch (sortBy) {
      case 'popular': posts.sort((a, b) => (b.score ?? 0) - (a.score ?? 0)); break;
      case 'most_downloaded': posts.sort((a, b) => b.downloadCount - a.downloadCount); break;
      case 'most_liked': posts.sort((a, b) => b.likes - a.likes); break;
      default: break;
    }
    const page = posts.slice(0, limit);
    const hasMore = posts.length > limit;
    return res.json({ posts: page, query, contentType, category, sortBy, nextCursor: hasMore ? page[page.length - 1]?.createdAt : undefined });
  } catch (error) {
    logger.error('Search failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

