function buildChatMessage(
  role: 'user' | 'assistant',
  content: string,
  quickReplies?: string[],
  gddRows?: Array<[string, string]>,
): {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  quickReplies?: string[];
  gddRows?: Array<{ key: string; value: string }>;
  createdAt: Date;
} {
  return {
    id: uuidv4(),
    role,
    content,
    quickReplies,
    gddRows: gddRows?.map(([key, value]) => ({ key, value })),
    createdAt: new Date(),
  };
}

const PROJECT_MEMORY_VERSION = 1 as const;
const PROJECT_KIND_VALUES = new Set(['game', 'content', 'fix', 'clone', 'ugc', 'analyze']);
const SHOP_REQUEST_PATTERN = /(shop|store|магазин|лавк|маркет|economy|экономик|upgrade|улучшен|speed boost|jump boost|skip stage|checkpoint helper|пропуск|скип|буст)/i;
const OBBY_PATTERN = /(obby|obstacle course|parkour|обби|паркур|полоса препятств)/i;
const START_OVER_PATTERN = /(start over|new project|new game|from scratch|reset project|clear project|начать заново|новый проект|новая игра|с нуля|сбрось проект|забудь проект)/i;

function isRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function memoryString(value: unknown, maxLength = 280): string | undefined {
  if (typeof value !== 'string') return undefined;
  const cleaned = value.trim().replace(/\s+/g, ' ');
  return cleaned ? cleaned.slice(0, maxLength) : undefined;
}

function memoryStringArray(value: unknown, maxItems = 12): string[] | undefined {
  if (!Array.isArray(value)) return undefined;
  const items = value
    .map((item) => memoryString(item, 120))
    .filter((item): item is string => Boolean(item))
    .slice(0, maxItems);
  return items.length ? items : undefined;
}

function normalizeMemoryProjectKind(value: unknown): ProjectMemory['projectKind'] | undefined {
  const kind = memoryString(value, 24);
  return kind && PROJECT_KIND_VALUES.has(kind) ? kind as ProjectMemory['projectKind'] : undefined;
}

function normalizeGddRows(value: unknown): Array<{ key: string; value: string }> | undefined {
  if (!Array.isArray(value)) return undefined;
  const rows = value.flatMap((row) => {
    if (Array.isArray(row) && row.length >= 2) {
      const key = memoryString(row[0], 80);
      const val = memoryString(row[1], 400);
      return key && val ? [{ key, value: val }] : [];
    }
    if (isRecord(row)) {
      const key = memoryString(row.key, 80);
      const val = memoryString(row.value, 400);
      return key && val ? [{ key, value: val }] : [];
    }
    return [];
  }).slice(0, 24);
  return rows.length ? rows : undefined;
}

function normalizeProjectMemory(value: unknown): ProjectMemory | undefined {
  if (!isRecord(value)) return undefined;
  const iteration = typeof value.iteration === 'number' && Number.isFinite(value.iteration)
    ? Math.max(0, Math.floor(value.iteration))
    : 0;
  const updatedAt = memoryString(value.updatedAt, 40) ?? timestampToIso(value.updatedAt);
  return {
    version: PROJECT_MEMORY_VERSION,
    title: memoryString(value.title, 120),
    projectKind: normalizeMemoryProjectKind(value.projectKind),
    contentSubcategory: memoryString(value.contentSubcategory, 80),
    genre: memoryString(value.genre, 80),
    theme: memoryString(value.theme, 160),
    currentBrief: memoryString(value.currentBrief, 1200),
    latestGddRows: normalizeGddRows(value.latestGddRows),
    latestJobId: memoryString(value.latestJobId, 80),
    latestArtifactIds: memoryStringArray(value.latestArtifactIds, 24),
    iteration,
    updatedAt,
  };
}

function rowsToProjectMemoryRows(rows?: Array<{ key: string; value: string }>): Array<{ key: string; value: string }> | undefined {
  return normalizeGddRows(rows);
}

function findGddRow(rows: Array<{ key: string; value: string }> | undefined, pattern: RegExp): string | undefined {
  return rows?.find((row) => pattern.test(row.key))?.value;
}

function inferMemorySubcategory(metadata?: Record<string, unknown>, gdd?: GameDesignDoc, existing?: ProjectMemory, latestText?: string): string | undefined {
  const direct = memoryString(metadata?.contentSubcategory, 80) ?? memoryString(metadata?.subcategory, 80);
  if (direct) return direct;
  if (existing?.contentSubcategory) return existing.contentSubcategory;
  const haystack = [
    gdd?.genre,
    gdd?.title,
    gdd?.theme,
    latestText,
    memoryString(metadata?.intent, 80),
  ].filter(Boolean).join(' ').toLowerCase();
  if (/(brainrot|steal).*(sim)|brainrot_sim/.test(haystack)) return 'brainrot_sim';
  if (/troll.*obby|obby_troll/.test(haystack)) return 'obby_troll';
  if (OBBY_PATTERN.test(haystack)) return 'obby';
  if (/(tycoon|тайкун|factory|фабрик|завод)/i.test(haystack)) return 'tycoon';
  if (/(simulator|симулятор|clicker|кликер|pet sim)/i.test(haystack)) return 'simulator';
  if (/(rpg|quest|dungeon|рпг|квест)/i.test(haystack)) return 'rpg';
  if (/(horror|escape|scary|хоррор|страшн)/i.test(haystack)) return 'horror';
  if (/(pvp|arena|арен)/i.test(haystack)) return 'pvp_arena';
  return undefined;
}

function buildMemoryBrief(gdd?: GameDesignDoc, rows?: Array<{ key: string; value: string }>, latestText?: string, existing?: ProjectMemory): string | undefined {
  const parts = [
    gdd?.title ? `Title: ${gdd.title}` : undefined,
    gdd?.genre ? `Genre: ${gdd.genre}` : undefined,
    gdd?.theme ? `Theme: ${gdd.theme}` : undefined,
    gdd?.coreLoop ? `Core loop: ${gdd.coreLoop}` : undefined,
    gdd?.mechanics?.length ? `Mechanics: ${gdd.mechanics.join(', ')}` : undefined,
    gdd?.economy?.length ? `Economy: ${gdd.economy.join(', ')}` : undefined,
    rows?.length ? `GDD rows: ${rows.slice(0, 10).map((row) => `${row.key}: ${row.value}`).join('; ')}` : undefined,
    latestText ? `Latest request: ${latestText}` : undefined,
  ].filter(Boolean);
  return memoryString(parts.join('\n') || existing?.currentBrief, 1200);
}

function mergeProjectMemoryFromChat(args: {
  existing?: ProjectMemory;
  title?: string;
  gdd?: GameDesignDoc;
  gddRows?: Array<{ key: string; value: string }>;
  metadata?: Record<string, unknown>;
  latestMessage: string;
}): ProjectMemory {
  const rows = rowsToProjectMemoryRows(args.gddRows) ?? args.existing?.latestGddRows;
  const genre = memoryString(args.gdd?.genre, 80)
    ?? findGddRow(rows, /^(genre|жанр)$/i)
    ?? memoryString(args.metadata?.genre, 80)
    ?? args.existing?.genre;
  const theme = memoryString(args.gdd?.theme, 160)
    ?? findGddRow(rows, /^(theme|тема)$/i)
    ?? memoryString(args.metadata?.theme, 160)
    ?? args.existing?.theme;
  const title = memoryString(args.title, 120)
    ?? memoryString(args.gdd?.title, 120)
    ?? findGddRow(rows, /^(title|название)$/i)
    ?? memoryString(args.metadata?.title, 120)
    ?? args.existing?.title
    ?? summarizeTitle(args.latestMessage);
  const projectKind = normalizeMemoryProjectKind(args.metadata?.projectKind) ?? args.existing?.projectKind ?? 'game';
  const contentSubcategory = inferMemorySubcategory(args.metadata, args.gdd, args.existing, args.latestMessage);
  return {
    version: PROJECT_MEMORY_VERSION,
    title,
    projectKind,
    contentSubcategory,
    genre,
    theme,
    currentBrief: buildMemoryBrief(args.gdd, rows, args.latestMessage, args.existing),
    latestGddRows: rows,
    latestJobId: args.existing?.latestJobId,
    latestArtifactIds: args.existing?.latestArtifactIds,
    iteration: args.existing?.iteration ?? 0,
    updatedAt: new Date().toISOString(),
  };
}

function projectMemorySummary(memory?: ProjectMemory): string {
  if (!memory) return 'No existing project memory.';
  const rows = memory.latestGddRows?.slice(0, 16).map((row) => `- ${row.key}: ${row.value}`).join('\n');
  return [
    memory.title ? `Title: ${memory.title}` : undefined,
    memory.projectKind ? `Project kind: ${memory.projectKind}` : undefined,
    memory.contentSubcategory ? `Content subcategory: ${memory.contentSubcategory}` : undefined,
    memory.genre ? `Genre: ${memory.genre}` : undefined,
    memory.theme ? `Theme: ${memory.theme}` : undefined,
    memory.currentBrief ? `Current brief: ${memory.currentBrief}` : undefined,
    rows ? `Latest GDD:\n${rows}` : undefined,
    memory.latestJobId ? `Latest job id: ${memory.latestJobId}` : undefined,
    memory.latestArtifactIds?.length ? `Latest artifact ids: ${memory.latestArtifactIds.join(', ')}` : undefined,
    `Iteration: ${memory.iteration}`,
  ].filter(Boolean).join('\n');
}

function isStartOverRequest(text: string): boolean {
  return START_OVER_PATTERN.test(text);
}

function shouldAddObbyShop(memory: ProjectMemory | undefined, prompt: string): boolean {
  const latestPrompt = stripGenerationServiceContext(prompt);
  const isObby = OBBY_PATTERN.test(`${memory?.contentSubcategory ?? ''} ${memory?.genre ?? ''} ${latestPrompt}`);
  const wantsShop = SHOP_REQUEST_PATTERN.test(latestPrompt);
  return isObby && wantsShop;
}

function buildIterativeGenerationPrompt(memory: ProjectMemory, requestedChange: string): string {
  return [
    'Existing project context (authoritative baseline for this same chat/thread):',
    projectMemorySummary(memory),
    '',
    'Requested change (highest priority):',
    requestedChange,
    '',
    'Generate a complete new Roblox package version. Preserve the existing genre, theme, core GDD, and unchanged systems from the baseline. Apply the requested change as the new delta. Do not patch or diff a previous .rbxl/.rbxm binary in v1.',
  ].join('\n');
}

function threadProjectMemoryResponse(data: FirebaseFirestore.DocumentData): ProjectMemory | null {
  return normalizeProjectMemory(data.projectMemory) ?? null;
}

function contentSubcategoryFromThreadData(data: FirebaseFirestore.DocumentData, memory: ProjectMemory | null): string | null {
  return memory?.contentSubcategory ?? memoryString(data.contentSubcategory, 80) ?? null;
}

function latestJobIdFromThreadData(data: FirebaseFirestore.DocumentData, memory: ProjectMemory | null): string | null {
  return memory?.latestJobId ?? memoryString(data.latestJobId, 80) ?? null;
}

async function syncThreadProjectMemoryFromJob(job: GenerationJob): Promise<void> {
  if (!job.threadId) return;
  const threadRef = db.collection('threads').doc(job.threadId);
  const threadDoc = await threadRef.get();
  if (!threadDoc.exists) return;
  const threadData = threadDoc.data() ?? {};
  if (threadData.userId !== job.userId) return;

  const existing = normalizeProjectMemory(threadData.projectMemory);
  const metadata = isRecord(job.metadata) ? job.metadata : {};
  const requestedChange = memoryString(metadata.requestedChangePrompt, 800);
  const contentSubcategory = memoryString(metadata.contentSubcategory, 80)
    ?? inferMemorySubcategory(metadata, undefined, existing, `${job.prompt} ${job.resultText ?? ''}`);
  const artifactIds = job.artifacts.map((artifact) => artifact.id).filter(Boolean);
  const currentBrief = memoryString([
    existing?.currentBrief,
    requestedChange ? `Latest change: ${requestedChange}` : undefined,
    !existing?.currentBrief ? job.prompt : undefined,
  ].filter(Boolean).join('\n'), 1200);

  const memory: ProjectMemory = {
    version: PROJECT_MEMORY_VERSION,
    title: memoryString(metadata.title, 120) ?? existing?.title ?? summarizeTitle(requestedChange ?? job.prompt),
    projectKind: normalizeMemoryProjectKind(metadata.projectKind) ?? existing?.projectKind ?? 'game',
    contentSubcategory,
    genre: memoryString(metadata.genre, 80) ?? existing?.genre ?? contentSubcategory,
    theme: memoryString(metadata.theme, 160) ?? existing?.theme,
    currentBrief,
    latestGddRows: existing?.latestGddRows,
    latestJobId: job.id,
    latestArtifactIds: artifactIds.length ? artifactIds : existing?.latestArtifactIds,
    iteration: existing?.latestJobId === job.id ? existing.iteration : (existing?.iteration ?? 0) + 1,
    updatedAt: new Date().toISOString(),
  };

  await threadRef.collection('versions').doc(job.id).set({
    jobId: job.id,
    status: job.status,
    provider: job.provider,
    kind: job.kind,
    prompt: job.prompt,
    requestedChange: requestedChange ?? null,
    artifactIds,
    projectMemory: memory,
    createdAt: job.createdAt,
    updatedAt: memory.updatedAt,
  }, { merge: true });

  await threadRef.set({
    projectMemory: memory,
    latestJobId: job.id,
    latestArtifactIds: memory.latestArtifactIds ?? [],
    contentSubcategory: memory.contentSubcategory ?? FieldValue.delete(),
    projectKind: memory.projectKind ?? FieldValue.delete(),
    updatedAt: FieldValue.serverTimestamp(),
  }, { merge: true });
}

async function ensureThread(
  threadRef: FirebaseFirestore.DocumentReference,
  userId: string,
  seedText: string,
  projectKind?: string,
  contentSubcategory?: string,
): Promise<void> {
  const existing = await threadRef.get();
  if (existing.exists) {
    const data = existing.data() ?? {};
    const patch: Record<string, unknown> = {};
    if (projectKind && !data.projectKind) {
      patch.projectKind = projectKind;
    }
    if (contentSubcategory && !data.contentSubcategory) {
      patch.contentSubcategory = contentSubcategory;
    }
    if (Object.keys(patch).length) {
      await threadRef.update(patch);
    }
    return;
  }

  await threadRef.set({
    userId,
    title: summarizeTitle(seedText),
    promptHint: 'Planning',
    projectKind: projectKind ?? 'game',
    ...(contentSubcategory ? { contentSubcategory } : {}),
    createdAt: new Date(),
    updatedAt: new Date(),
  });
}

function summarizeTitle(text: string): string {
  const cleaned = text.trim().replace(/\s+/g, ' ');
  if (!cleaned) {
    return 'AI Workspace';
  }
  return cleaned.split(' ').slice(0, 4).join(' ');
}

function stripGenerationServiceContext(text?: string): string {
  if (!text) return '';
  let s = text.replace(/\r/g, '\n');
  const marker = /(requested\s+change|latest\s+user\s+intent)\s*(?:\([^)]*\))?\s*:/gi;
  let lastMarkerEnd = -1;
  let match: RegExpExecArray | null;
  while ((match = marker.exec(s)) !== null) {
    lastMarkerEnd = match.index + match[0].length;
  }
  if (lastMarkerEnd >= 0) {
    s = s.slice(lastMarkerEnd);
  }
  s = s
    .replace(/Existing project context[\s\S]*?(?=(Requested change|Latest user intent)\s*(?:\([^)]*\))?\s*:|$)/gi, '')
    .replace(/Generate a complete new Roblox package version[\s\S]*$/gi, '')
    .replace(/Preserve the existing genre[\s\S]*$/gi, '')
    .replace(/^\s*[-•]\s*/gm, '')
    .replace(/\s+/g, ' ')
    .trim();
  return s;
}

function containsGenerationServiceContext(text?: string): boolean {
  return /Existing project context|authoritative baseline|Requested change|Latest user intent|projectMemorySummary|Generate a complete new Roblox package version/i.test(text ?? '');
}

function cleanGameDisplayTitle(raw?: string, fallback = 'Roblox Game'): string {
  let s = stripGenerationServiceContext(raw) || (raw ?? '');
  s = s
    .replace(/^generate\s+a\s+game\s+package\s*(brief\s*)?(for\s+)?/i, '')
    .replace(/^(please\s+)?(generate|create|make|build)\b[^.]*?\bfor\s+/i, '')
    .replace(/\.\s*(genre|scale|style|monetization|theme|gameplay)\s*:.*$/is, '')
    .replace(/["'“”`]/g, '')
    .trim();
  if (!s || containsGenerationServiceContext(s)) return fallback;
  if (s.length > 80) s = summarizeTitle(s);
  return s || fallback;
}

function extractGameTitleFromBrief(gameBrief?: string): string | undefined {
  if (!gameBrief) return undefined;
  const text = gameBrief.trim();
  try {
    const first = text.indexOf('{');
    const last = text.lastIndexOf('}');
    if (first >= 0 && last > first) {
      const parsed = JSON.parse(text.slice(first, last + 1)) as Record<string, unknown>;
      const title = typeof parsed.title === 'string' ? parsed.title : typeof parsed.name === 'string' ? parsed.name : '';
      const cleaned = cleanGameDisplayTitle(title, '');
      if (cleaned) return cleaned;
    }
  } catch {
    // GDDs are often Markdown; fall through to regex extraction.
  }
  const candidates = [
    /^#{1,3}\s+(.{3,100})$/im,
    /\*\*([^*\n]{3,100})\*\*/,
    /\b(?:title|name)\s*:\s*["“]?([^"\n”]{3,100})/i,
    /\b([A-Z][A-Za-z0-9 '\-]{0,80}(?:Obby|School|Hospital|Tycoon|Simulator|Game World)[A-Za-z0-9 '\-]{0,40})\b/,
  ];
  for (const rx of candidates) {
    const m = text.match(rx);
    const cleaned = cleanGameDisplayTitle(m?.[1], '');
    if (cleaned) return cleaned;
  }
  return undefined;
}

function latestUserIntentForJob(job: GenerationJob): string {
  const metadata = job.metadata as Record<string, unknown> | undefined;
  const requested = typeof metadata?.requestedChangePrompt === 'string' ? metadata.requestedChangePrompt : '';
  const latest = typeof metadata?.latestUserIntent === 'string' ? metadata.latestUserIntent : '';
  return stripGenerationServiceContext(requested || latest || job.prompt) || job.prompt || '';
}

function summarizeGamePackageTitle(job: GenerationJob, gameBrief?: string): string {
  const metadata = job.metadata as Record<string, unknown> | undefined;
  const fromBrief = extractGameTitleFromBrief(gameBrief);
  if (fromBrief) return fromBrief;
  const metadataTitle = typeof metadata?.title === 'string' ? cleanGameDisplayTitle(metadata.title, '') : '';
  if (metadataTitle && !containsGenerationServiceContext(metadataTitle)) return metadataTitle;
  const latestIntent = latestUserIntentForJob(job);
  return cleanGameDisplayTitle(latestIntent, summarizeTitle(latestIntent || job.prompt || 'Roblox Game'));
}

function buildGamePackageResultMetadata(job: GenerationJob, gameBrief?: string): Record<string, string> {
  if (job.kind !== 'game_package' && job.kind !== 'rbxl_build' && job.kind !== 'rbxm_build') return {};
  const latestIntent = latestUserIntentForJob(job);
  const title = summarizeGamePackageTitle(job, gameBrief);
  const brief = stripGenerationServiceContext(gameBrief).slice(0, 320);
  const themeKey = detectObbyThemeKey(`${gameBrief ?? ''} ${latestIntent}`);
  const subcategory = String((job.metadata as Record<string, unknown> | undefined)?.contentSubcategory ?? '').toLowerCase();
  const isObby = subcategory === 'obby' || /\bobby\b|parkour|obstacle|обби|паркур|полоса препятств/i.test(`${gameBrief ?? ''} ${latestIntent}`);
  const obbyDescription = isObby
    ? themeKey === 'school_horror'
      ? `${title}: haunted school obby with classrooms, lockers, chalkboards, detention hallways, an overhead entrance banner, checkpoints, and rare side-placed ghost NPCs when the prompt allows characters.`
      : themeKey === 'hospital_horror'
        ? `${title}: hospital horror obby with ruined wards, tiled corridors, toxic spills, flickering lights, an overhead emergency banner, checkpoints, and a rescue finish.`
        : `${title}: obby generated from the latest prompt. ${brief}`.slice(0, 360)
    : `${title}: generated Roblox package. ${brief}`.slice(0, 360);
  const regenerateHint = isObby
    ? themeKey === 'school_horror'
      ? 'Send what to change, for example: regenerate with more classrooms/lockers, fewer NPCs, banner above the start, no shop.'
      : themeKey === 'hospital_horror'
        ? 'Send what to change, for example: regenerate with clearer hospital rooms, fewer NPCs, banner above the start, no shop.'
        : 'Send what to change, for example: regenerate closer to my prompt, fewer NPCs, clearer theme props, no shop.'
    : 'Send what to change in chat to regenerate a new version.';
  return {
    displayTitle: title,
    obbyDescription,
    regenerateHint,
  };
}

async function buildVoiceSession(userId: string, request: VoiceSessionCreateRequest): Promise<VoiceSession> {
  const now = new Date().toISOString();
  const session: VoiceSession = {
    id: uuidv4(),
    userId,
    status: 'recording',
    locale: typeof request.locale === 'string' ? request.locale : undefined,
    chunkCount: 0,
    partialTranscript: undefined,
    finalTranscript: undefined,
    finalJobId: undefined,
    createdAt: now,
    updatedAt: now,
  };
  await db.collection('voiceSessions').doc(session.id).set({
    ...session,
    metadata: request.metadata ?? {},
  });
  return session;
}

async function transcribeChunkViaDeepgram(
  audioBase64: string,
  mimeType: string,
  locale?: string,
): Promise<string | undefined> {
  try {
    const rawMime = mimeType === 'audio/m4a' ? 'audio/mp4' : mimeType;
    const language = mapLocaleToDeepgramLanguage(locale);
    const payload: Record<string, unknown> = {
      audioBase64,
      audioMimeType: rawMime,
      smart_format: true,
      punctuate: true,
      model: 'nova-2',
    };
    if (language) {
      payload.language = language;
    } else {
      payload.detect_language = true;
    }
    const result = await executeProvider({
      provider: 'deepgram',
      operation: 'listen',
      prompt: 'Transcribe audio chunk',
      input: { payload },
      kind: 'transcription',
    });
    return result.text?.trim() || undefined;
  } catch (err) {
    logger.warn('Chunk-level Deepgram transcription failed; partial transcript will lag', err);
    return undefined;
  }
}

async function appendVoiceSessionChunk(
  userId: string,
  sessionId: string,
  request: VoiceSessionChunkUploadRequest,
): Promise<VoiceSessionChunkUploadResponse> {
  const sessionRef = db.collection('voiceSessions').doc(sessionId);
  const sessionDoc = await sessionRef.get();
  if (!sessionDoc.exists) {
    throw new Error('Voice session not found');
  }

  const session = sessionDoc.data() as VoiceSession;
  if (session.userId !== userId) {
    throw new Error('Forbidden');
  }
  if (!request.audioBase64?.trim()) {
    throw new Error('audioBase64 is required');
  }
  const audioSizeBytes = Buffer.from(request.audioBase64, 'base64').length;
  logger.info('Voice chunk received', { audioSizeBytes, mimeType: request.mimeType, sessionId });
  if (audioSizeBytes < 2000) {
    throw new Error(`Audio too short (${audioSizeBytes} bytes). Please record for at least 1 second.`);
  }

  const asset = await ingestAttachment(userId, {
    type: 'audio',
    name: request.fileName ?? `voice-chunk-${session.chunkCount + 1}.m4a`,
    mimeType: request.mimeType ?? 'audio/m4a',
    contentBase64: request.audioBase64,
    metadata: { sessionId, durationMs: request.durationMs },
  });
  const chunk: VoiceSessionChunk = {
    id: asset.id,
    sessionId,
    order: session.chunkCount + 1,
    mimeType: asset.mimeType ?? 'audio/m4a',
    durationMs: request.durationMs,
    storagePath: asset.storagePath,
    downloadUrl: asset.downloadUrl,
    createdAt: asset.createdAt,
    audioBase64Fallback: request.audioBase64,
  };

  await sessionRef.collection('chunks').doc(chunk.id).set(chunk);

  const chunkTranscript = await transcribeChunkViaDeepgram(
    request.audioBase64,
    request.mimeType ?? 'audio/m4a',
    session.locale,
  );

  const previousPartial = session.partialTranscript ?? '';
  const combinedPartial = chunkTranscript
    ? (previousPartial ? `${previousPartial} ${chunkTranscript}` : chunkTranscript)
    : previousPartial || `Uploaded ${chunk.order} chunk(s).`;

  const updatedSession: VoiceSession = {
    ...session,
    status: request.isLastChunk ? 'uploaded' : 'recording',
    chunkCount: chunk.order,
    partialTranscript: combinedPartial,
    updatedAt: new Date().toISOString(),
  };
  await sessionRef.set(updatedSession, { merge: true });
  return {
    session: updatedSession,
    chunk,
  };
}

async function finalizeVoiceSession(
  userId: string,
  sessionId: string,
  request: VoiceSessionFinalizeRequest,
): Promise<VoiceSessionFinalizeResponse> {
  const sessionRef = db.collection('voiceSessions').doc(sessionId);
  const sessionDoc = await sessionRef.get();
  if (!sessionDoc.exists) {
    throw new Error('Voice session not found');
  }
  const session = sessionDoc.data() as VoiceSession;
  if (session.userId !== userId) {
    throw new Error('Forbidden');
  }

  const chunkSnapshot = await sessionRef.collection('chunks').orderBy('order', 'asc').get();
  if (chunkSnapshot.empty) {
    throw new Error('Voice session has no uploaded chunks');
  }
  const chunks = chunkSnapshot.docs.map((doc) => doc.data() as VoiceSessionChunk);
  const lastChunk = chunks[chunks.length - 1];
  const now = new Date().toISOString();
  const jobId = uuidv4();
  const job: GenerationJob = {
    id: jobId,
    userId,
    prompt: 'Finalize voice transcription from uploaded session chunks.',
    provider: 'deepgram',
    kind: 'voice_stream_finalize',
    status: 'queued',
    createdAt: now,
    updatedAt: now,
    artifacts: [],
    history: ['Queued voice session finalize job', `Session: ${sessionId}`, `Chunks: ${chunks.length}`],
    dispatchMode: getJobDispatchMode() as JobDispatchMode,
    metadata: {
      ...(request.metadata ?? {}),
      language: (request.metadata as Record<string, unknown>)?.language ?? session.locale,
      sessionId,
      chunkCount: chunks.length,
      audioUrl: lastChunk.downloadUrl,
      audioBase64: lastChunk.audioBase64Fallback,
      audioAssetId: lastChunk.id,
      audioMimeType: lastChunk.mimeType,
      finalizeMode: chunks.length > 1 ? 'last_chunk_fallback' : 'single_chunk',
    },
  };

  // Short-circuit: if a single chunk already produced a real transcript at
  // chunk-upload time, reuse it instead of running Deepgram a second time.
  // The chunk fallback marker "Uploaded N chunk(s)." is set when chunk
  // transcription failed, so we treat it as "no transcript yet" here.
  const chunkPartial = (session.partialTranscript ?? '').trim();
  const chunkPartialLooksReal = chunkPartial.length > 0 && !/^Uploaded \d+ chunk\(s\)\.$/.test(chunkPartial);
  if (chunks.length === 1 && chunkPartialLooksReal) {
    const fastArtifact: GenerationArtifact = {
      id: uuidv4(),
      type: 'text',
      name: 'transcript.txt',
      content: chunkPartial,
    };
    const fastJob: GenerationJob = {
      ...job,
      status: 'completed',
      artifacts: [fastArtifact],
      resultText: chunkPartial,
      history: [...job.history ?? [], 'Reused chunk-pass transcript; skipped duplicate Deepgram call'],
      metadata: {
        ...job.metadata,
        finalizeMode: 'chunk_short_circuit',
      },
      updatedAt: now,
    };
    await db.collection('generationJobs').doc(jobId).set(fastJob);
    const fastSession: VoiceSession = {
      ...session,
      status: 'completed',
      chunkCount: chunks.length,
      finalTranscript: chunkPartial,
      finalJobId: jobId,
      lastError: undefined,
      updatedAt: new Date().toISOString(),
    };
    await sessionRef.set(fastSession, { merge: true });
    return {
      session: fastSession,
      jobId,
      status: 'completed',
      transcript: chunkPartial,
      locale: session.locale,
      artifact: fastArtifact,
    };
  }

  await db.collection('generationJobs').doc(jobId).set(job);
  await sessionRef.set({
    status: 'processing',
    finalJobId: jobId,
    updatedAt: now,
  }, { merge: true });

  const completed = await runGenerationJobLifecycle(jobId, job);
  const transcriptArtifact = completed.artifacts.find((artifact) => artifact.type === 'text');
  const updatedSession: VoiceSession = {
    ...session,
    status: completed.status === 'completed' ? 'completed' : 'failed',
    chunkCount: chunks.length,
    partialTranscript: chunks.length > 1
      ? 'Multiple chunks uploaded. Finalized using the current fallback path until merge worker is configured.'
      : undefined,
    finalTranscript: transcriptArtifact?.content ?? completed.resultText,
    finalJobId: jobId,
    lastError: completed.errorMessage,
    updatedAt: new Date().toISOString(),
  };
  await sessionRef.set(updatedSession, { merge: true });
  return {
    session: updatedSession,
    jobId,
    status: completed.status,
    transcript: updatedSession.finalTranscript,
    confidence: typeof completed.metadata?.transcriptionConfidence === 'number'
      ? completed.metadata.transcriptionConfidence as number
      : undefined,
    locale: typeof completed.metadata?.transcriptionLocale === 'string'
      ? completed.metadata.transcriptionLocale as string
      : updatedSession.locale,
    artifact: transcriptArtifact,
  };
}

async function loadOwnedAsset(userId: string, assetId: string): Promise<IngestionAsset | null> {
  const doc = await db.collection('ingestionAssets').doc(assetId).get();
  if (!doc.exists) {
    return null;
  }
  const asset = doc.data() as IngestionAsset;
  return asset.userId === userId ? { ...asset, id: assetId } : null;
}

async function ensureAssetAnalysis(asset: IngestionAsset, inlineText?: string): Promise<ProjectAnalysis> {
  const analysisRef = db.collection('assetAnalyses').doc(asset.id);
  const existing = await analysisRef.get();
  if (existing.exists) {
    return existing.data() as ProjectAnalysis;
  }

  const assetFormat = inferAssetFormat(asset);
  const text = inlineText ?? asset.extractedText ?? asset.previewText ?? '';
  const workerAnalysis = (assetFormat === 'rbxl' || assetFormat === 'rbxm')
    ? await loadRobloxWorkerAnalysis(asset)
    : null;
  const scriptAnalysis = assetFormat === 'lua' || looksLikeLua(text)
    ? [analyzeLuauSource(text, asset.name)]
    : [];
  const nodes = workerAnalysis
    ? workerAnalysis.nodes.map((node) => ({
      id: `${asset.id}:${node.path}`,
      path: node.path,
      name: node.name,
      className: node.className,
      childCount: node.childCount,
      details: undefined,
    }))
    : buildAnalysisNodes(asset, assetFormat, text);
  const externalLinks = asset.sourceUrl ? [asset.sourceUrl] : extractUrls(text);
  const now = new Date().toISOString();
  const analysis: ProjectAnalysis = {
    id: asset.id,
    assetId: asset.id,
    userId: asset.userId,
    kind: assetFormat,
    status: 'completed',
    summary: summarizeAnalysis(asset, assetFormat, scriptAnalysis, nodes, text, workerAnalysis?.totalInstances),
    nodes,
    scripts: scriptAnalysis,
    externalLinks,
    metadata: {
      assetFormat,
      hasStructuredWorker: Boolean(getRobloxWorkerCommand() || getRobloxWorkerUrl()),
    },
    createdAt: now,
    updatedAt: now,
  };
  await analysisRef.set(analysis);
  await db.collection('ingestionAssets').doc(asset.id).set({
    assetFormat,
    analysisJobId: analysis.id,
    analysisStatus: analysis.status,
    analysisSummary: analysis.summary,
  }, { merge: true });
  return analysis;
}

async function loadRobloxWorkerAnalysis(asset: IngestionAsset) {
  try {
    const bytes = await readAssetBytes(asset);
    if (!bytes) {
      return null;
    }
    return await maybeAnalyzeRobloxAsset(bytes, asset.assetFormat === 'rbxm' ? 'model' : 'place');
  } catch {
    return null;
  }
}

async function readAssetBytes(asset: IngestionAsset): Promise<Buffer | null> {
  if (asset.storagePath) {
    const activeBucket = await resolvedBucket();
    const [buffer] = await activeBucket.file(asset.storagePath).download();
    return buffer;
  }
  if (asset.downloadUrl) {
    const response = await fetch(asset.downloadUrl);
    if (!response.ok) {
      return null;
    }
    return Buffer.from(await response.arrayBuffer());
  }
  return null;
}

async function previewAssetEdit(asset: IngestionAsset, instruction: string): Promise<ProjectAnalysis> {
  if (!instruction.trim()) {
    throw new Error('instruction is required');
  }
  const analysis = await ensureAssetAnalysis(asset);
  const source = asset.extractedText ?? asset.previewText ?? '';
  const diffPreview: ProjectAnalysis['diffPreview'] = {
    summary: `Planned edit for ${asset.name}: ${instruction.trim()}`,
    operations: [
      {
        op: analysis.kind === 'lua' ? 'replace_script' : 'update',
        targetPath: asset.name,
        description: instruction.trim(),
        beforeText: source.slice(0, 500),
        afterText: buildEditedPreview(source, instruction),
      },
    ],
  };
  const updatedAnalysis: ProjectAnalysis = {
    ...analysis,
    diffPreview,
    updatedAt: new Date().toISOString(),
  };
  await db.collection('assetAnalyses').doc(asset.id).set(updatedAnalysis, { merge: true });
  return updatedAnalysis;
}

async function applyAssetEdit(userId: string, asset: IngestionAsset, instruction: string): Promise<AttachmentApplyResponse> {
  const analysis = await previewAssetEdit(asset, instruction);
  const source = asset.extractedText ?? asset.previewText ?? '';
  const rewritten = await rewriteAttachmentText(source, instruction, asset.name);
  const jobId = uuidv4();
  const now = new Date().toISOString();
  const job: GenerationJob = {
    id: jobId,
    userId,
    prompt: `Apply the following edit to ${asset.name}:\n${instruction}\n\nSource:\n${source}`,
    provider: defaults.chatProvider as AIProvider,
    kind: analysis.kind === 'lua' ? 'code' : 'project_parse',
    status: 'completed',
    createdAt: now,
    updatedAt: now,
    artifacts: [],
    history: ['Attachment edit applied', `Asset: ${asset.id}`],
    dispatchMode: 'embedded',
    metadata: {
      sourceAssetId: asset.id,
      editInstruction: instruction,
    },
  };
  const artifact = await uploadTextArtifact(job, rewritten, {
    type: analysis.kind === 'lua' ? 'lua' : 'text',
    extension: analysis.kind === 'lua' ? 'lua' : 'txt',
    mimeType: 'text/plain',
    name: `${asset.name.replace(/\.[^.]+$/, '')}-edited.${analysis.kind === 'lua' ? 'lua' : 'txt'}`,
    previewText: rewritten.slice(0, 1200),
    inlineCode: analysis.kind === 'lua',
    metadata: {
      sourceAssetId: asset.id,
      analysisId: analysis.id,
    },
  });
  job.artifacts = [artifact];
  await db.collection('generationJobs').doc(jobId).set(job);
  return {
    job,
    analysis,
  };
}

function socialFeedModeFromQuery(value: unknown): SocialFeedMode | undefined {
  return value === 'top' || value === 'trending' || value === 'following' || value === 'recommended' || value === 'saved' || value === 'rising' || value === 'staff_picks'
    ? value
    : value === 'new'
      ? 'new'
      : undefined;
}

// ── Algolia social posts index ───────────────────────────────────────────────

const ALGOLIA_INDEX_SOCIAL_POSTS = 'social_posts';

async function algoliaRequest(method: string, path: string, body?: unknown): Promise<Record<string, unknown>> {
  const appId = ALGOLIA_APP_ID.value();
  const writeKey = ALGOLIA_WRITE_API_KEY.value();
  if (!appId || !writeKey) return {};
  const url = `https://${appId}.algolia.net/1/indexes/${ALGOLIA_INDEX_SOCIAL_POSTS}${path}`;
  const res = await fetch(url, {
    method,
    headers: {
      'Content-Type': 'application/json',
      'X-Algolia-API-Key': writeKey,
      'X-Algolia-Application-Id': appId,
    },
    ...(body ? { body: JSON.stringify(body) } : {}),
  });
  return (await res.json()) as Record<string, unknown>;
}

async function algoliaSearch(query: string, filters?: string, hitsPerPage = 50): Promise<{ objectID: string }[]> {
  const appId = ALGOLIA_APP_ID.value();
  const searchKey = ALGOLIA_SEARCH_API_KEY.value();
  if (!appId || !searchKey) return [];
  const url = `https://${appId}-dsn.algolia.net/1/indexes/${ALGOLIA_INDEX_SOCIAL_POSTS}/query`;
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Algolia-API-Key': searchKey,
      'X-Algolia-Application-Id': appId,
    },
    body: JSON.stringify({
      query,
      hitsPerPage,
      ...(filters ? { filters } : {}),
      attributesToRetrieve: ['objectID'],
    }),
  });
  const data = (await res.json()) as { hits?: { objectID: string }[] };
  return data.hits ?? [];
}

function algoliaPostRecord(post: SocialPost) {
  return {
    objectID: post.id,
    title: post.title,
    description: post.description.slice(0, 500),
    authorName: post.authorName,
    authorId: post.authorId,
    tags: post.tags,
    category: post.category ?? '',
    projectKind: post.projectKind,
    contentType: post.contentType ?? inferContentType(post.projectKind),
    likes: post.likes,
    downloadCount: post.downloadCount,
    commentCount: post.commentCount,
    score: post.score ?? 0,
    createdAt: post.createdAt,
    createdAtTimestamp: new Date(post.createdAt).getTime(),
  };
}

async function indexPostToAlgolia(post: SocialPost): Promise<void> {
  try {
    await algoliaRequest('PUT', `/${post.id}`, algoliaPostRecord(post));
  } catch (err) {
    logger.warn('Algolia index failed (non-blocking)', err);
  }
}

async function removePostFromAlgolia(postId: string): Promise<void> {
  try {
    await algoliaRequest('DELETE', `/${postId}`);
  } catch (err) {
    logger.warn('Algolia delete failed (non-blocking)', err);
  }
}

async function loadSocialFeed(
  userId: string,
  authToken: DecodedIdToken | null | undefined,
  request: SocialFeedRequest,
): Promise<SocialFeedResponse> {
  const profile = await ensureSocialProfile(userId, authToken);
  const [likesSnapshot, dislikesSnapshot, savedSnapshot, followingSnapshot] = await Promise.all([
    db.collection('socialProfiles').doc(profile.id).collection('likes').get(),
    db.collection('socialProfiles').doc(profile.id).collection('dislikes').get(),
    db.collection('socialProfiles').doc(profile.id).collection('savedPosts').get(),
    db.collection('socialProfiles').doc(profile.id).collection('following').get(),
  ]);
  const likedPostIds = new Set(likesSnapshot.docs.map((doc) => doc.id));
  const dislikedPostIds = new Set(dislikesSnapshot.docs.map((doc) => doc.id));
  const savedPostIds = new Set(savedSnapshot.docs.map((doc) => doc.id));
  const followingIds = new Set(followingSnapshot.docs.map((doc) => doc.id));
  const limit = Math.min(Math.max(request.limit ?? 50, 1), 200);

  let query: FirebaseFirestore.Query = db.collection('socialPosts').orderBy('createdAt', 'desc');
  if (request.cursor) {
    query = query.startAfter(request.cursor);
  }
  const fetchSize = Math.min(limit * 4, 1000);
  const postsSnapshot = await query.limit(fetchSize).get();

  let posts = postsSnapshot.docs.map((doc) => {
    const data = normalizeSocialPost({ ...(doc.data() as SocialPost), id: doc.id });
    const score = computeFeedScore(data);
    return {
      ...data,
      likedByViewer: likedPostIds.has(doc.id),
      dislikedByViewer: dislikedPostIds.has(doc.id),
      savedByViewer: savedPostIds.has(doc.id),
      score,
    } satisfies SocialPost;
  }).filter((post) => post.publicationState !== 'deleted' && (post.moderationStatus === 'approved' || post.moderationStatus === 'review'));

  if (request.contentType === 'game') {
    posts = posts.filter((post) => post.projectKind === 'game' || post.projectKind === 'clone');
  } else if (request.contentType === 'content') {
    posts = posts.filter((post) => post.projectKind === 'content' || post.projectKind === 'ugc');
  }
  if (request.category) {
    const catLower = request.category.toLowerCase();
    posts = posts.filter((post) => post.tags.some((t) => t.toLowerCase() === catLower) || (post.category ?? '').toLowerCase() === catLower);
  }
  if (request.tag) {
    const tagLower = request.tag.toLowerCase();
    posts = posts.filter((post) => post.tags.some((t) => t.toLowerCase() === tagLower));
  }
  if (request.authorId) {
    posts = posts.filter((post) => post.authorId === request.authorId);
  }
  if (request.search) {
    // Try Algolia for better full-text search, fall back to in-memory
    let algoliaPostIds: Set<string> | null = null;
    try {
      const hits = await algoliaSearch(request.search, undefined, 200);
      if (hits.length > 0) {
        algoliaPostIds = new Set(hits.map((h) => h.objectID));
      }
    } catch { /* Algolia unavailable — fallback below */ }

    if (algoliaPostIds !== null) {
      posts = posts.filter((post) => algoliaPostIds!.has(post.id));
    } else {
      const q = request.search.toLowerCase();
      posts = posts.filter((post) =>
        post.title.toLowerCase().includes(q) ||
        post.description.toLowerCase().includes(q) ||
        post.authorName.toLowerCase().includes(q) ||
        post.tags.some((tag) => tag.toLowerCase().includes(q)),
      );
    }
  }

  switch (request.mode) {
    case 'saved':
      posts = posts.filter((post) => savedPostIds.has(post.id));
      break;
    case 'following':
      posts = posts.filter((post) => followingIds.has(post.authorId));
      break;
    case 'top':
    case 'trending':
    case 'recommended':
      posts = posts.sort((a, b) => (b.score ?? 0) - (a.score ?? 0));
      break;
    case 'rising': {
      const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
      posts = posts
        .filter((p) => p.createdAt >= oneDayAgo)
        .sort((a, b) => (b.score ?? 0) - (a.score ?? 0));
      break;
    }
    case 'staff_picks':
      posts = posts.filter((p) => (p as SocialPost & { staffPick?: boolean }).staffPick === true || (p as SocialPost & { featured?: boolean }).featured === true);
      break;
    case 'new':
    default:
      break;
  }

  if (request.sortBy) {
    switch (request.sortBy) {
      case 'popular': posts.sort((a, b) => (b.score ?? 0) - (a.score ?? 0)); break;
      case 'most_downloaded': posts.sort((a, b) => b.downloadCount - a.downloadCount); break;
      case 'most_liked': posts.sort((a, b) => b.likes - a.likes); break;
      case 'newest': break;
      default: break;
    }
  }

  const page = posts.slice(0, limit);
  const hasMore = posts.length > limit;
  return {
    posts: page,
    nextCursor: hasMore ? page[page.length - 1]?.createdAt : undefined,
    mode: request.mode ?? 'new',
  };
}

