const COLLECTION_TAG_HINTS: Record<string, string[]> = {
  'best-obby-games': ['obby', 'obstacle', 'parkour'],
  'top-combat-systems': ['combat', 'fighting', 'pvp', 'weapon', 'sword'],
  'rpg-starter-packs': ['rpg', 'roleplay', 'quest', 'inventory', 'leveling'],
  'ugc-marketplace-templates': ['ugc', 'marketplace', 'clothing', 'accessory', 'avatar'],
};

async function loadCuratedCollections(
  userId: string,
  authToken: DecodedIdToken | null | undefined,
): Promise<{ collections: CuratedCollection[] }> {
  const firestoreSnap = await db.collection('curatedCollections').get();
  let collections: CuratedCollection[];

  if (!firestoreSnap.empty) {
    collections = firestoreSnap.docs.map((doc) => ({ ...(doc.data() as CuratedCollection), id: doc.id }));
  } else {
    collections = HARDCODED_CURATED_COLLECTIONS.map((c) => ({ ...c, posts: [] }));
  }

  const postsSnapshot = await db.collection('socialPosts').orderBy('createdAt', 'desc').limit(500).get();
  const allPosts = postsSnapshot.docs
    .map((doc) => normalizeSocialPost({ ...(doc.data() as SocialPost), id: doc.id }))
    .filter((p) => p.publicationState !== 'deleted' && (p.moderationStatus === 'approved' || p.moderationStatus === 'review'));

  for (const collection of collections) {
    if (collection.postIds && collection.postIds.length > 0) {
      collection.posts = allPosts.filter((p) => collection.postIds.includes(p.id)).slice(0, 10);
    } else {
      const hints = COLLECTION_TAG_HINTS[collection.id] ?? [];
      if (hints.length > 0) {
        collection.posts = allPosts
          .filter((p) => p.tags.some((tag) => hints.some((h) => tag.toLowerCase().includes(h))))
          .slice(0, 10);
      } else {
        collection.posts = [];
      }
    }
  }

  return { collections };
}

async function updateSocialProfile(
  userId: string,
  authToken: DecodedIdToken | null | undefined,
  body: Record<string, unknown> | undefined,
): Promise<SocialProfileUpdateResponse> {
  const existing = await ensureSocialProfile(userId, authToken);

  const newAvatarUrl = typeof body?.avatarUrl === 'string' && body.avatarUrl.trim()
    ? body.avatarUrl.trim()
    : undefined;

  if (newAvatarUrl && newAvatarUrl !== existing.avatarUrl) {
    const avatarModeration = await moderateImage(newAvatarUrl);
    if (avatarModeration.severity === 'blocked') {
      throw new Error(avatarModeration.reason ?? 'Avatar image rejected by moderation');
    }
    if (avatarModeration.severity === 'review') {
      await ensureModerationCase({
        eventId: uuidv4(),
        userId,
        entityType: 'profile',
        entityId: userId,
        severity: 'review',
        reason: avatarModeration.reason ?? 'Avatar image flagged for review',
        evidence: { avatarUrl: newAvatarUrl },
      });
    }
  }

  // Bug 24: socialLinks приходили в body, но полностью игнорировались здесь —
  // в итоге на клиенте sheet "Social Links" сохранял локально, а на сервере
  // ничего не менялось. Парсим массив с валидацией платформы и URL.
  const allowedPlatforms = new Set(['roblox', 'youtube', 'twitter', 'discord', 'tiktok', 'website', 'other']);
  let nextSocialLinks: SocialLink[] | undefined = existing.socialLinks;
  if (Array.isArray(body?.socialLinks)) {
    nextSocialLinks = (body?.socialLinks as unknown[])
      .map((raw): SocialLink | null => {
        if (!raw || typeof raw !== 'object') return null;
        const r = raw as Record<string, unknown>;
        const platform = typeof r.platform === 'string' ? r.platform.trim().toLowerCase() : '';
        const url = typeof r.url === 'string' ? r.url.trim() : '';
        if (!allowedPlatforms.has(platform) || !url) return null;
        const label = typeof r.label === 'string' ? r.label.trim().slice(0, 40) : undefined;
        return { platform: platform as SocialLink['platform'], url: url.slice(0, 300), label };
      })
      .filter((v): v is SocialLink => v !== null)
      .slice(0, 10);
  }

  const profile: SocialProfile = {
    ...existing,
    displayName: typeof body?.displayName === 'string' && body.displayName.trim()
      ? body.displayName.trim().slice(0, 40)
      : existing.displayName,
    bio: typeof body?.bio === 'string' ? body.bio.trim().slice(0, 240) : existing.bio,
    robloxUsername: typeof body?.robloxUsername === 'string' ? body.robloxUsername.trim().slice(0, 40) : existing.robloxUsername,
    headline: typeof body?.headline === 'string' ? body.headline.trim().slice(0, 80) : existing.headline,
    websiteUrl: typeof body?.websiteUrl === 'string' ? body.websiteUrl.trim().slice(0, 160) : existing.websiteUrl,
    avatarUrl: newAvatarUrl ?? existing.avatarUrl,
    socialLinks: nextSocialLinks,
  };
  await db.collection('socialProfiles').doc(userId).set(profile, { merge: true });
  return { profile };
}

async function toggleFollow(
  userId: string,
  targetProfileId: string,
  authToken: DecodedIdToken | null | undefined,
): Promise<SocialFollowResponse> {
  if (userId === targetProfileId) {
    throw new Error('Cannot follow your own profile');
  }
  const viewerProfile = await ensureSocialProfile(userId, authToken);
  const targetProfile = await ensureSocialProfile(targetProfileId);
  const followingRef = db.collection('socialProfiles').doc(userId).collection('following').doc(targetProfileId);
  const followerRef = db.collection('socialProfiles').doc(targetProfileId).collection('followers').doc(userId);
  const existing = await followingRef.get();
  const following = !existing.exists;
  if (following) {
    await Promise.all([
      followingRef.set({ createdAt: new Date().toISOString() }),
      followerRef.set({ createdAt: new Date().toISOString() }),
      db.collection('socialProfiles').doc(userId).set({ followingCount: viewerProfile.followingCount + 1 }, { merge: true }),
      db.collection('socialProfiles').doc(targetProfileId).set({ followerCount: targetProfile.followerCount + 1 }, { merge: true }),
    ]);

    sendPushNotification(
      targetProfileId,
      { title: 'New Follower', body: `${viewerProfile.displayName} started following you` },
      { type: 'follow', profileId: userId },
      'followers',
    ).catch(() => {});

    return {
      following: true,
      followerCount: targetProfile.followerCount + 1,
      followingCount: viewerProfile.followingCount + 1,
    };
  }

  await Promise.all([
    followingRef.delete(),
    followerRef.delete(),
    db.collection('socialProfiles').doc(userId).set({ followingCount: Math.max(0, viewerProfile.followingCount - 1) }, { merge: true }),
    db.collection('socialProfiles').doc(targetProfileId).set({ followerCount: Math.max(0, targetProfile.followerCount - 1) }, { merge: true }),
  ]);
  return {
    following: false,
    followerCount: Math.max(0, targetProfile.followerCount - 1),
    followingCount: Math.max(0, viewerProfile.followingCount - 1),
  };
}

// Shared pagination helper for followers/following lists. Reads the relation
// subcollection (socialProfiles/{profileId}/{kind}) ordered by createdAt desc,
// then batch-hydrates each target's SocialProfile in parallel, and finally
// checks whether the VIEWER follows each target (so the UI can render a
// correct follow/unfollow button without a second round-trip per row).
async function listFollowRelations(
  viewerId: string,
  profileId: string,
  kind: 'followers' | 'following',
  cursor: string | undefined,
  limit: number,
): Promise<{
  profiles: Array<{ id: string; name: string; headline: string; avatarUrl: string | null; isFollowedByViewer: boolean }>;
  nextCursor: string | null;
}> {
  let query: FirebaseFirestore.Query = db
    .collection('socialProfiles')
    .doc(profileId)
    .collection(kind)
    .orderBy('createdAt', 'desc')
    .limit(limit);
  if (cursor) {
    query = query.startAfter(cursor);
  }
  const snapshot = await query.get();
  if (snapshot.empty) {
    return { profiles: [], nextCursor: null };
  }

  // Hydrate each target profile. In follow subcollections the doc id IS the
  // other side of the relation: in "followers" it's the follower's userId, in
  // "following" it's the target's userId.
  const relatedIds = snapshot.docs.map((doc) => doc.id);
  const profileDocs = await Promise.all(
    relatedIds.map((id) => db.collection('socialProfiles').doc(id).get()),
  );

  // Check which of these ids the viewer follows. Only relevant when viewer is
  // not the profile owner (for the owner's "following" list, every entry is
  // by definition followed).
  let followedByViewer: Set<string>;
  if (viewerId === profileId && kind === 'following') {
    followedByViewer = new Set(relatedIds);
  } else {
    const followChecks = await Promise.all(
      relatedIds.map((id) =>
        db.collection('socialProfiles').doc(viewerId).collection('following').doc(id).get(),
      ),
    );
    followedByViewer = new Set(
      followChecks.map((doc, idx) => (doc.exists ? relatedIds[idx] : null)).filter((v): v is string => v !== null),
    );
  }

  const profiles = profileDocs.map((doc, idx) => {
    const id = relatedIds[idx];
    const data = (doc.data() as SocialProfile | undefined) ?? null;
    return {
      id,
      name: data?.displayName ?? 'Creator',
      headline: data?.headline ?? '',
      avatarUrl: data?.avatarUrl ?? null,
      isFollowedByViewer: followedByViewer.has(id),
    };
  });

  // Use the last doc's createdAt as the next cursor. Firestore `startAfter`
  // on an ordered query accepts the ordered field's value.
  const lastDoc = snapshot.docs[snapshot.docs.length - 1];
  const lastCreatedAt = lastDoc.get('createdAt');
  const nextCursor = snapshot.size === limit && typeof lastCreatedAt === 'string' ? lastCreatedAt : null;

  return { profiles, nextCursor };
}

async function toggleSavedPost(userId: string, postId: string): Promise<SocialSaveResponse> {
  const profileRef = db.collection('socialProfiles').doc(userId);
  const savedRef = profileRef.collection('savedPosts').doc(postId);
  const postRef = db.collection('socialPosts').doc(postId);
  const [profileDoc, savedDoc, postDoc] = await Promise.all([profileRef.get(), savedRef.get(), postRef.get()]);
  if (!postDoc.exists) {
    throw new Error('Post not found');
  }
  const profile = (profileDoc.data() as SocialProfile | undefined) ?? await ensureSocialProfile(userId);
  const post = postDoc.data() as SocialPost;
  const currentlySaved = savedDoc.exists;
  const nextSaveCount = currentlySaved
    ? Math.max(0, ((post as SocialPost & { saveCount?: number }).saveCount ?? 0) - 1)
    : (((post as SocialPost & { saveCount?: number }).saveCount ?? 0) + 1);
  await Promise.all([
    currentlySaved ? savedRef.delete() : savedRef.set({ createdAt: new Date().toISOString() }),
    profileRef.set({ savedCount: currentlySaved ? Math.max(0, profile.savedCount - 1) : profile.savedCount + 1 }, { merge: true }),
    postRef.set({ saveCount: nextSaveCount }, { merge: true }),
    db.collection('socialProjects').doc(post.projectId).set({ saveCount: nextSaveCount }, { merge: true }),
  ]);
  return {
    saved: !currentlySaved,
    saveCount: nextSaveCount,
  };
}

async function resolveDownloadableArtifacts(userId: string, artifactIds: string[] | undefined | null): Promise<DownloadableArtifact[]> {
  // Bug 19: защита от старых socialProjects-документов без поля artifactIds —
  // раньше undefined.length валил всю ветку /api/social/posts/:postId в HTTP 500.
  if (!artifactIds || !Array.isArray(artifactIds) || !artifactIds.length) return [];
  const docs = await Promise.all(
    artifactIds.map((id) => db.collection('artifacts').doc(id).get()),
  );
  return docs
    .map((doc) => {
      if (!doc.exists) return null;
      const data = doc.data() as GenerationArtifact & { userId?: string; downloadUrl?: string };
      if (data.userId && data.userId !== userId) return null;
      return {
        id: doc.id,
        type: data.type,
        name: data.name,
        downloadUrl: data.downloadUrl,
        url: data.url,
        extension: data.extension,
        mimeType: data.mimeType,
        sizeBytes: data.sizeBytes,
        metadata: data.metadata,
      } as DownloadableArtifact;
    })
    .filter((a): a is DownloadableArtifact => a !== null);
}

async function buildSocialPostDetail(
  userId: string,
  postId: string,
  authToken: DecodedIdToken | null | undefined,
): Promise<SocialPostDetail | null> {
  const [postDoc, profile] = await Promise.all([
    db.collection('socialPosts').doc(postId).get(),
    ensureSocialProfile(userId, authToken),
  ]);
  if (!postDoc.exists) {
    return null;
  }
  const post = { ...(postDoc.data() as SocialPost), id: postId };
  const [projectDoc, authorDoc, commentsSnapshot, likedDoc, savedDoc, dislikedDoc, commentLikesSnapshot] = await Promise.all([
    db.collection('socialProjects').doc(post.projectId).get(),
    db.collection('socialProfiles').doc(post.authorId).get(),
    db.collection('socialPosts').doc(postId).collection('comments').orderBy('createdAt', 'asc').limit(500).get(),
    db.collection('socialProfiles').doc(profile.id).collection('likes').doc(postId).get(),
    db.collection('socialProfiles').doc(profile.id).collection('savedPosts').doc(postId).get(),
    db.collection('socialProfiles').doc(profile.id).collection('dislikes').doc(postId).get(),
    // Bug 20: this viewer's liked-comments for this post → drives filled heart + toggle state.
    db.collection('socialProfiles').doc(profile.id).collection('commentLikes').where('postId', '==', postId).get(),
  ]);
  const likedCommentIds = new Set(
    commentLikesSnapshot.docs.map((d) => (d.data() as { commentId?: string }).commentId).filter(Boolean),
  );

  // Bug 19: normalize all nested objects — legacy / simulated docs often lack non-optional
  // fields (saveCount, updatedAt, badges, likeCount, ...) which crash iOS Swift Decodable
  // with "The data couldn't be read because it is missing".
  const project = projectDoc.exists
    ? normalizeSocialProject({ ...(projectDoc.data() as Partial<SocialProject>), id: post.projectId })
    : undefined;
  const downloadableArtifacts = project ? await resolveDownloadableArtifacts(post.authorId, project.artifactIds) : [];

  return {
    ...normalizeSocialPost(post),
    likedByViewer: likedDoc.exists,
    dislikedByViewer: dislikedDoc.exists,
    savedByViewer: savedDoc.exists,
    project,
    comments: commentsSnapshot.docs.map((doc) =>
      normalizeSocialComment({
        ...(doc.data() as Partial<SocialComment>),
        id: doc.id,
        postId,
        likedByViewer: likedCommentIds.has(doc.id),
      }),
    ),
    author: authorDoc.exists
      ? normalizeSocialProfileForResponse({ ...(authorDoc.data() as Partial<SocialProfile>), id: post.authorId })
      : undefined,
    downloadableArtifacts,
  };
}

async function createModerationAppeal(userId: string, caseId: string, reason: string): Promise<ModerationAppeal> {
  if (!reason.trim()) {
    throw new Error('Appeal reason is required');
  }
  const caseRef = db.collection('moderationCases').doc(caseId);
  const doc = await caseRef.get();
  if (!doc.exists) {
    throw new Error('Moderation case not found');
  }
  const moderationCase = doc.data() as ModerationCase;
  if (moderationCase.userId !== userId) {
    throw new Error('Forbidden');
  }
  const now = new Date().toISOString();
  const appeal: ModerationAppeal = {
    id: uuidv4(),
    caseId,
    userId,
    reason: reason.trim(),
    status: 'open',
    createdAt: now,
    updatedAt: now,
  };
  await caseRef.collection('appeals').doc(appeal.id).set(appeal);
  await caseRef.set({ status: 'appealed', updatedAt: now }, { merge: true });
  return appeal;
}

async function runModerationPipeline(args: {
  userId: string;
  text: string;
  stage: ModerationStage;
  requestedProvider?: Extract<AIProvider, 'openai' | 'anthropic' | 'gemini'>;
  artifactType?: ArtifactType;
  metadata?: Record<string, unknown>;
}): Promise<ModerationCheckResponse> {
  const heuristic = heuristicModeration(args.text, args.stage, args.artifactType);
  if (!heuristic.allowed || heuristic.severity === 'review') {
    return persistModerationEvent(args.userId, args.stage, args.text, heuristic, args.metadata);
  }

  // Skip LLM moderation for weapon content — combat descriptions (bleeding, poison, knockback)
  // are standard Roblox game mechanics, not real violence
  const isWeaponContent = args.metadata?.contentCategory === 'weapon';
  if (isWeaponContent) {
    return persistModerationEvent(args.userId, args.stage, args.text, heuristic, args.metadata);
  }
  // Same for items & tools — medkits (heal, bandage, syringe), potions, weapons-adjacent
  // props often trip Gemini on medical/combat language in templated Lua scripts.
  const isItemContent = args.metadata?.contentCategory === 'item_tool';
  if (isItemContent) {
    return persistModerationEvent(args.userId, args.stage, args.text, heuristic, args.metadata);
  }

  // Skip LLM moderation for explicit supported-genre games (obby/tycoon/simulator) when
  // the heuristic already passed. Gemini tends to over-flag mainstream meme/brainrot briefs
  // ("Skibidi Toilet", "Ohio", "Rizz") as "potentially inappropriate / confusing for young
  // players" even though they're standard Roblox UGC themes. The heuristic blocklist still
  // catches real policy violations (phishing, casino, self-harm, terrorist, credit card).
  const subcategory = typeof args.metadata?.contentSubcategory === 'string'
    ? (args.metadata.contentSubcategory as string).toLowerCase() : '';
  const projectKind = typeof args.metadata?.projectKind === 'string'
    ? (args.metadata.projectKind as string).toLowerCase() : '';
  const isSupportedGameGenre = projectKind === 'game'
    && (subcategory === 'obby' || subcategory === 'tycoon' || subcategory === 'simulator');
  if (isSupportedGameGenre && args.stage !== 'publication') {
    return persistModerationEvent(args.userId, args.stage, args.text, heuristic, args.metadata);
  }

  if (args.stage === 'artifact' || args.stage === 'publication' || args.text.length > 1600) {
    try {
      const moderationInput = truncatePrompt(args.text, 3000);
      const modelReview = await runModelModerationReview(moderationInput, args.requestedProvider);
      return persistModerationEvent(args.userId, args.stage, args.text, modelReview, args.metadata);
    } catch (error) {
      logger.warn('Model moderation fallback to heuristic', error);
    }
  }

  return persistModerationEvent(args.userId, args.stage, args.text, heuristic, args.metadata);
}

function heuristicModeration(
  text: string,
  stage: ModerationStage,
  artifactType?: ArtifactType,
): ModerationCheckResponse {
  const trimmed = text.trim();
  if (!trimmed) {
    return {
      allowed: false,
      reason: 'Text is empty',
      provider: 'heuristic',
      severity: 'blocked',
      action: 'block',
      category: 'empty',
      flags: ['empty'],
    };
  }
  if (trimmed.length > 20_000) {
    const truncated = truncatePrompt(trimmed, 12000);
    return {
      allowed: true,
      reason: 'Text was too long and has been truncated for safety checks',
      provider: 'heuristic',
      severity: 'review',
      action: 'review',
      category: 'length',
      flags: ['too_long'],
      rewrittenText: truncated,
    };
  }

  const lower = trimmed.toLowerCase();
  // Word-boundary matching so we don't trigger on substrings inside LLM-generated prose.
  // 'scam' was dropped from hard-block because it's too common in meme/game content
  // and caused legitimate brainrot-obby generations to fail. Kept in reviewTerms below.
  const blockedPatterns: { term: string; re: RegExp }[] = [
    { term: 'credit card', re: /\bcredit\s+card\b/ },
    { term: 'kill myself', re: /\bkill\s+myself\b/ },
    { term: 'terrorist',   re: /\bterrorist\w*\b/ },
    { term: 'phishing',    re: /\bphishing\b/ },
    { term: 'casino',      re: /\bcasino\b/ },
  ];
  const reviewTerms = ['exploit', 'bypass', 'hack', 'obfuscate', 'leak', 'nsfw', 'stolen', 'scam'];
  const blockedHit = blockedPatterns.find((p) => p.re.test(lower));
  if (blockedHit) {
    // Downgrade hard-block to review for generated artifacts — a single false positive
    // in LLM output shouldn't kill an entire build. User-input (stage==='input') and
    // publication stages keep the hard block so real prompt attacks still fail closed.
    if (stage === 'artifact') {
      return {
        allowed: true,
        reason: `Heuristic flag (review): ${blockedHit.term}`,
        provider: 'heuristic',
        severity: 'review',
        action: 'review',
        category: 'policy',
        flags: [blockedHit.term],
      };
    }
    return {
      allowed: false,
      reason: `Blocked by safety filter: ${blockedHit.term}`,
      provider: 'heuristic',
      severity: 'blocked',
      action: 'block',
      category: 'policy',
      flags: [blockedHit.term],
    };
  }

  if (artifactType === 'lua') {
    const scriptModeration = moderateLuaSource(trimmed);
    if (scriptModeration) {
      return scriptModeration;
    }
  }

  const reviewMatch = reviewTerms.find((term) => lower.includes(term));
  if (reviewMatch || stage === 'publication' && lower.includes('free robux')) {
    return {
      allowed: true,
      reason: `Needs review: ${reviewMatch ?? 'publication copy'}`,
      provider: 'heuristic',
      severity: 'review',
      action: 'review',
      category: stage === 'publication' ? 'publication' : 'policy',
      flags: [reviewMatch ?? 'manual_review'],
    };
  }

  return {
    allowed: true,
    provider: 'heuristic',
    severity: 'safe',
    action: 'allow',
  };
}

function truncatePrompt(text: string, maxLength: number): string {
  if (text.length <= maxLength) return text;
  return text.slice(0, maxLength);
}

// ─── Smart Stubs: 3-Tier Intent Classification & Token Protection ───────────

interface SmartStubResult {
  isSupported: boolean;
  tier: 0 | 1 | 2;
  unsupportedCategory?: string;
  intentSummary?: string;
  stubScenario?: 'global_mechanics' | 'scripts_monetization' | 'partial_complex';
  stubMessage?: string;
  alternativeActions?: string[];
}

const SMART_STUB_SUPPORTED_GAME_SUBCATEGORIES = new Set([
  'obby',
  'obby_troll',
  'brainrot_sim',
  'tycoon',
  'simulator',
  'parkour',
  'rpg',
  'horror',
  'pvp',
  'pvp_arena',
]);

function isSmartStubSupportedGame(metadata?: Record<string, unknown>): boolean {
  const projectKind = ((metadata?.projectKind as string) ?? '').toLowerCase();
  const genre = ((metadata?.genre as string) ?? '').toLowerCase();
  const contentSubcategory = ((metadata?.contentSubcategory as string) ?? '').toLowerCase();
  if (projectKind !== 'game') return false;
  if (contentSubcategory && SMART_STUB_SUPPORTED_GAME_SUBCATEGORIES.has(contentSubcategory)) return true;
  return [...SMART_STUB_SUPPORTED_GAME_SUBCATEGORIES].some((g) => genre.includes(g));
}

/** LEVEL 1 — Zero-cost regex pre-filter against known unsupported feature keywords. */
function smartStubPreFilter(prompt: string, metadata?: Record<string, unknown>): SmartStubResult | null {
  const lower = prompt.toLowerCase();

  // Bypass for supported game genres. Session #188: RPG/Horror/PvP/Simulator
  // now have runtime builders, so Smart Stubs must not show "coming soon" chips.
  if (isSmartStubSupportedGame(metadata)) {
    return null;
  }

  // Unsupported genre/mechanic triggers
  const genreTriggers: Record<string, string[]> = {
    'Advanced RPG Mechanics': ['rpg quest', 'dungeon crawl', 'class system', 'loot table', 'skill tree', 'xp system', 'leveling system', 'character class'],
    'Horror Chase Mechanics': ['chase mechanic', 'jumpscare system', 'monster ai patrol', 'horror ai'],
    'Tower Defense': ['tower defense system', 'td wave', 'tower placement grid', 'wave spawner'],
    'Matchmaking / PvP': ['matchmaking system', 'elo rating', 'pvp matchmaking', 'ranked match'],
    'Racing Mechanics': ['racing checkpoint', 'racing system', 'lap timer', 'vehicle physics system'],
  };

  // Unsupported system/script triggers
  const systemTriggers: Record<string, string[]> = {
    'Combat Scripts': ['combat system script', 'damage calculation', 'hitbox detection', 'combo system script'],
    'Inventory System': ['inventory system', 'inventory script', 'item storage system', 'backpack system script'],
    'Shop / Economy': ['shop system script', 'currency system script', 'trading system'],
    'DataStore / Saving': ['datastore save', 'data persistence', 'player data save', 'profileservice'],
    'Leaderboard System': ['global leaderboard script', 'ordered datastore leaderboard'],
    'Weather System': ['weather system', 'dynamic weather', 'rain system', 'day night cycle script'],
    'Crafting System': ['crafting system', 'crafting recipe', 'crafting table script'],
    'Dialogue Trees': ['dialogue tree system', 'branching dialogue script', 'npc dialogue system'],
  };

  // Unsupported monetization triggers
  const monetizationTriggers: Record<string, string[]> = {
    'Game Passes': ['gamepass script', 'game pass system', 'developer product script', 'dev product', 'premium token'],
    'Monetization Logic': ['monetization system', 'robux purchase', 'premium benefit', 'vip gamepass script'],
  };

  // Unsupported visual/platform triggers
  const visualTriggers: Record<string, string[]> = {
    'Shaders': ['shader', 'custom shader', 'postprocessing effect'],
    'Java Edition': ['java edition', 'java version'],
    'Advanced VFX': ['particle system script', 'vfx system', 'trail system script', 'beam system'],
  };

  const allTriggers = { ...genreTriggers, ...systemTriggers, ...monetizationTriggers, ...visualTriggers };

  for (const [category, keywords] of Object.entries(allTriggers)) {
    for (const kw of keywords) {
      if (lower.includes(kw)) {
        const isMonetization = category in monetizationTriggers || category === 'Shop / Economy';
        const isPartial = category === 'Crafting System' || category === 'Dialogue Trees' || category === 'Weather System';
        const scenario: SmartStubResult['stubScenario'] = isMonetization
          ? 'scripts_monetization'
          : isPartial ? 'partial_complex' : 'global_mechanics';

        return {
          isSupported: false,
          tier: 1,
          unsupportedCategory: category,
          intentSummary: `Unsupported: ${category}`,
          stubScenario: scenario,
          stubMessage: getStubMessage(scenario),
          alternativeActions: getAlternativeActions(category),
        };
      }
    }
  }
  return null;
}

/** LEVEL 2 — Cheap LLM classifier for ambiguous prompts not caught by Level 1. */
async function smartStubLLMClassifier(prompt: string): Promise<SmartStubResult | null> {
  const classifierPrompt: import('./promptCatalog.js').ProviderPromptInput = {
    system: `You are an Intent Classifier API for an AI Games & Mods Generator App.
Your ONLY task is to analyze the user's prompt and determine if it requests ANY unsupported features.
You do not generate content, code, or conversational responses.

SUPPORTED FEATURES (Can be generated):
- 3D Models (characters, clothing, accessories, weapons, vehicles, buildings, simple maps, pets, furniture)
- Simple UI layouts and mockups (HUD, shop window, inventory grid visual, menus)
- Playable game packages: Obby, Troll Obby, Tycoon, Simulator (pet/mining/fighting/muscle/clicker), RPG adventure, Roblox-safe Horror escape, PvP Arena FFA rounds
- Basic game levels (simple Obby structure, platformer layout)
- Textures, Decals, 2D Skins, Materials
- Animations (walk, dance, emote, idle, combat moves — keyframe based)
- Audio (music tracks, sound effects, ambient sounds)
- Simple Luau scripts (basic game logic, NPC behavior, tool scripts)
- Tycoon game systems (dropper/conveyor/collector loops, purchase buttons, upgrades, rebirth, economy)
- Simulator game systems (collect/sell loops, multipliers, bag upgrades, rebirth, egg hatching, pet following)
- Monetization scripts (Game Pass handlers, Developer Product purchase scripts, shop UI) — when requested via dedicated "Game Passes & Products" content type

UNSUPPORTED FEATURES (Flag these as NOT supported):
- Complex game genre systems not in the supported list: Tower Defense wave logic, Matchmaking/ELO/ranked PvP, Racing physics
- Complex backend scripts: DataStore/ProfileService persistence, Trading systems, Crafting systems, Global leaderboards with OrderedDataStore, Dynamic weather systems
- Monetization scripts in general chat (outside of the dedicated Game Passes flow): Premium tokens, Robux transaction systems
- Platform features: Custom shaders, Java Edition, Advanced particle/VFX scripting systems

RULES:
1. If the user request contains ANY unsupported feature, output "is_supported": false.
2. If the request only asks for supported features, output "is_supported": true.
3. Respond ONLY with valid JSON, no markdown, no extra text.

JSON OUTPUT:
{"is_supported": boolean, "unsupported_category": "string or null", "intent_summary": "string 3-5 words"}`,
    user: `User prompt:\n${prompt}`,
  };

  try {
    const result = await Promise.race([
      runChatProvider('gemini', classifierPrompt, 'gemini-2.5-flash'),
      new Promise<never>((_, reject) => setTimeout(() => reject(new Error('LLM classifier timeout (15s)')), 15_000)),
    ]);
    const raw = (result.text ?? '').replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(raw) as { is_supported: boolean; unsupported_category?: string | null; intent_summary?: string };

    if (parsed.is_supported === false && parsed.unsupported_category) {
      const category = parsed.unsupported_category;
      const isMonetization = /monetiz|gamepass|game pass|dev.*product|robux|premium/i.test(category);
      const isPartial = /craft|dialogue|weather/i.test(category);
      const scenario: SmartStubResult['stubScenario'] = isMonetization
        ? 'scripts_monetization'
        : isPartial ? 'partial_complex' : 'global_mechanics';

      return {
        isSupported: false,
        tier: 2,
        unsupportedCategory: category,
        intentSummary: parsed.intent_summary ?? `Unsupported: ${category}`,
        stubScenario: scenario,
        stubMessage: getStubMessage(scenario),
        alternativeActions: getAlternativeActions(category),
      };
    }
    return null; // supported
  } catch (error) {
    logger.warn('Smart stub LLM classifier failed, allowing through', error);
    return null; // on failure, allow through (don't block)
  }
}

function getStubMessage(scenario: SmartStubResult['stubScenario']): string {
  switch (scenario) {
    case 'scripts_monetization':
      return 'Great thinking! Complex scripting systems are in final debugging — coming in the next update! ⚙️ Your token balance is untouched. While we polish the code, want to create the visual part? Generate a UI or 3D model!';
    case 'partial_complex':
      return 'This requires precision engineering! ⚙️ To make sure the system works flawlessly, we only use battle-tested solutions from pros. Tokens not charged! Want to pick a ready-made base from our catalog?';
    case 'global_mechanics':
    default:
      return 'Huge ambition! 🔥 These mechanics are being compiled in our lab — soon in the next update! Your tokens are safe 🛡️. Let\'s create something awesome from what\'s available — like a unique model or skin!';
  }
}

function getAlternativeActions(category: string): string[] {
  const base = ['Generate 3D Model', 'Create UI Design', 'Browse Community'];
  if (/combat|weapon|fight/i.test(category)) return ['Generate 3D Weapon', 'Create Combat Animation', ...base.slice(2)];
  if (/shop|economy|monetiz|gamepass/i.test(category)) return ['Create Shop UI Mockup', 'Generate Store Interior', ...base.slice(2)];
  if (/inventory|craft/i.test(category)) return ['Create Inventory UI Mockup', 'Generate Item 3D Models', ...base.slice(2)];
  if (/rpg|quest|dialogue/i.test(category)) return ['Generate NPC Character', 'Create Quest UI Mockup', ...base.slice(2)];
  if (/tycoon|simulator/i.test(category)) return ['Generate Building 3D', 'Create Game UI', ...base.slice(2)];
  return base;
}

/** Anti-Fatigue: check consecutive stub count for a user session. */
async function getConsecutiveStubCount(userId: string): Promise<number> {
  const doc = await db.collection('userSessions').doc(userId).get();
  return (doc.data()?.consecutiveStubs as number) ?? 0;
}

async function incrementConsecutiveStubs(userId: string): Promise<number> {
  const ref = db.collection('userSessions').doc(userId);
  const doc = await ref.get();
  const current = (doc.data()?.consecutiveStubs as number) ?? 0;
  const next = current + 1;
  await ref.set({ consecutiveStubs: next, lastStubAt: new Date().toISOString() }, { merge: true });
  return next;
}

async function resetConsecutiveStubs(userId: string): Promise<void> {
  await db.collection('userSessions').doc(userId).set({ consecutiveStubs: 0 }, { merge: true });
}

const HARD_PIVOT_THRESHOLD = 3;
const HARD_PIVOT_MESSAGE = "Hey, we're thinking too big! 🤯 While our devs are building these powerful systems, let's take a breather. I've put together a collection of the hottest content other creators generated today. Want to check it out?";

/** Full Smart Stubs classification pipeline (Level 1 + Level 2 + Anti-Fatigue). */
async function runSmartStubsClassification(
  userId: string,
  prompt: string,
  metadata?: Record<string, unknown>,
  kind?: ContentGenerateRequest['kind'],
): Promise<{ blocked: boolean; stub?: SmartStubResult; hardPivot?: boolean; hardPivotMessage?: string }> {
  if (shouldBypassSmartStubsForVehicleRequest(prompt, metadata, kind)) {
    return { blocked: false };
  }

  // Bypass Smart Stubs for fully supported content categories
  const contentCategory = normalizedMetadataString(metadata, 'contentCategory');
  const supportedCategories = [
    'weapon',
    'character',
    'npc_ai',
    'audio',
    'animation',
    'decal_texture',
    'gamepass',
    'script',
    'game_system',
    'map_environment',
    'building',
    'item_tool',
    'furniture_prop',
    'ugc_accessory',
    'vehicle',
  ];
  if (supportedCategories.includes(contentCategory)) {
    return { blocked: false };
  }

  const contentSubcategory = ((metadata?.contentSubcategory as string) ?? '').toLowerCase();
  if (contentSubcategory === 'npcs' || contentSubcategory === 'vehicles') {
    return { blocked: false };
  }

  if (isVehicleGenerationMetadata(metadata)) {
    return { blocked: false };
  }

  // Bypass Smart Stubs for supported playable game genres.
  if (isSmartStubSupportedGame(metadata)) {
    return { blocked: false };
  }

  // Check Anti-Fatigue first
  const stubCount = await getConsecutiveStubCount(userId);
  if (stubCount >= HARD_PIVOT_THRESHOLD) {
    return {
      blocked: true,
      hardPivot: true,
      hardPivotMessage: HARD_PIVOT_MESSAGE,
      stub: {
        isSupported: false,
        tier: 0,
        unsupportedCategory: 'anti_fatigue_pivot',
        stubScenario: 'global_mechanics',
        stubMessage: HARD_PIVOT_MESSAGE,
        alternativeActions: ['Explore Trending', 'Browse Community', 'Start Fresh Chat'],
      },
    };
  }

  // Level 1: Regex pre-filter
  const level1 = smartStubPreFilter(prompt, metadata);
  if (level1) {
    await incrementConsecutiveStubs(userId);
    await trackSmartStubEvent(userId, prompt, level1);
    return { blocked: true, stub: level1 };
  }

  // Level 2: LLM classifier
  const level2 = await smartStubLLMClassifier(prompt);
  if (level2) {
    await incrementConsecutiveStubs(userId);
    await trackSmartStubEvent(userId, prompt, level2);
    return { blocked: true, stub: level2 };
  }

  return { blocked: false };
}

/** Analytics: track blocked generation events. */
async function trackSmartStubEvent(userId: string, prompt: string, stub: SmartStubResult): Promise<void> {
  try {
    await db.collection('analyticsEvents').add({
      type: 'generation_blocked',
      userId,
      timestamp: new Date().toISOString(),
      tierLevel: stub.tier,
      unsupportedCategory: stub.unsupportedCategory,
      intentSummary: stub.intentSummary,
      userPrompt: truncatePrompt(prompt, 500),
      stubScenario: stub.stubScenario,
    });
  } catch (e) {
    logger.warn('Failed to track smart stub event', e);
  }
}

