async function runModelModerationReview(
  text: string,
  provider: Extract<AIProvider, 'openai' | 'anthropic' | 'gemini'> = 'gemini',
): Promise<ModerationCheckResponse> {
  const prompt = buildModerationReviewPrompt(text);
  const response = await Promise.race([
    runChatProvider(provider, {
      system: `${prompt.system}\n\nReturn strict JSON only.`,
      user: `${prompt.user}\n\nSchema:
{
  "allowed": true,
  "severity": "safe | review | blocked",
  "action": "allow | review | block",
  "reason": "short reason",
  "category": "policy | script_safety | publication | other",
  "flags": ["flag"],
  "rewrittenText": "optional safe rewrite"
}`,
    }),
    new Promise<never>((_, reject) => setTimeout(() => reject(new Error('Moderation review timeout (15s)')), 15_000)),
  ]);
  const parsed = JSON.parse(extractJsonObject(response.text ?? '{}')) as Record<string, unknown>;
  const severity = parsed.severity === 'review' || parsed.severity === 'blocked' ? parsed.severity : 'safe';
  const action = parsed.action === 'review' || parsed.action === 'block' ? parsed.action : 'allow';
  const flags = Array.isArray(parsed.flags)
    ? parsed.flags.filter((item): item is string => typeof item === 'string' && item.trim().length > 0)
    : [];
  const reason = typeof parsed.reason === 'string' ? parsed.reason : undefined;
  const lowerReason = reason?.toLowerCase() ?? '';
  if (lowerReason.includes('prompt is too long') || lowerReason.includes('too long')) {
    return {
      allowed: true,
      reason: 'Moderation text exceeded provider limits and was accepted with review fallback',
      provider,
      severity: 'review',
      action: 'review',
      category: 'length',
      flags: ['moderation_prompt_too_long'],
      rewrittenText: truncatePrompt(text, 1500),
    };
  }

  return {
    allowed: parsed.allowed === false ? false : action !== 'block',
    reason,
    provider,
    severity,
    action,
    category: typeof parsed.category === 'string' ? parsed.category : undefined,
    flags,
    rewrittenText: typeof parsed.rewrittenText === 'string' ? parsed.rewrittenText : undefined,
  };
}

async function moderateImage(imageUrl: string): Promise<ModerationCheckResponse> {
  if (!imageUrl || !imageUrl.trim()) {
    return {
      allowed: true,
      provider: 'skip',
      severity: 'safe',
      action: 'allow',
      reason: 'No image URL provided',
    };
  }

  try {
    const systemPrompt = getImageModerationSystemPrompt();
    const result: VisionModerationResult = await runGeminiVision(systemPrompt, imageUrl);

    const action: ModerationCheckResponse['action'] =
      result.severity === 'blocked' ? 'block'
        : result.severity === 'review' ? 'review'
          : 'allow';

    return {
      allowed: result.severity !== 'blocked',
      reason: result.reason,
      provider: 'gemini-vision',
      severity: result.severity,
      action,
      category: result.category,
      flags: result.flags,
    };
  } catch (error) {
    logger.warn('Image moderation via Vision API failed, allowing with review', error);
    return {
      allowed: true,
      reason: 'Vision moderation unavailable — flagged for manual review',
      provider: 'gemini-vision-fallback',
      severity: 'review',
      action: 'review',
      category: 'error',
      flags: ['vision_api_error'],
    };
  }
}

async function moderateImageUrls(
  userId: string,
  imageUrls: string[],
  entityType: ModerationEntityType,
  entityId?: string,
): Promise<ModerationCheckResponse> {
  const validUrls = imageUrls.filter((url) => typeof url === 'string' && url.trim().length > 0);
  if (validUrls.length === 0) {
    return { allowed: true, provider: 'skip', severity: 'safe', action: 'allow' };
  }

  const results = await Promise.all(validUrls.map((url) => moderateImage(url)));

  const blocked = results.find((r) => r.severity === 'blocked');
  if (blocked) {
    const persisted = await persistModerationEvent(userId, 'publication', `[image] ${validUrls.join(', ')}`, blocked, { entityType, entityId });
    return persisted;
  }

  const review = results.find((r) => r.severity === 'review');
  if (review) {
    const persisted = await persistModerationEvent(userId, 'publication', `[image] ${validUrls.join(', ')}`, review, { entityType, entityId });
    return persisted;
  }

  return { allowed: true, provider: 'gemini-vision', severity: 'safe', action: 'allow' };
}

async function persistModerationEvent(
  userId: string,
  stage: ModerationStage,
  text: string,
  moderation: ModerationCheckResponse,
  metadata?: Record<string, unknown>,
): Promise<ModerationCheckResponse> {
  const eventId = uuidv4();
  const event: ModerationEvent = {
    id: eventId,
    userId,
    stage,
    provider: moderation.provider,
    inputText: text,
    allowed: moderation.allowed,
    severity: moderation.severity,
    action: moderation.action,
    reason: moderation.reason,
    category: moderation.category,
    flags: moderation.flags,
    rewrittenText: moderation.rewrittenText,
    metadata,
    createdAt: new Date().toISOString(),
  };
  await db.collection('moderationEvents').doc(eventId).set(event);
  if (moderation.severity === 'review' || moderation.severity === 'blocked') {
    await ensureModerationCase({
      eventId,
      userId,
      entityType: inferModerationEntityType(stage, metadata),
      entityId: typeof metadata?.entityId === 'string'
        ? metadata.entityId
        : typeof metadata?.postId === 'string'
          ? metadata.postId
          : typeof metadata?.artifactId === 'string'
            ? metadata.artifactId
            : undefined,
      severity: moderation.severity,
      reason: moderation.reason,
      evidence: {
        category: moderation.category,
        flags: moderation.flags,
        stage,
        metadata,
      },
    });
  }
  return { ...moderation, eventId };
}

function inferModerationEntityType(
  stage: ModerationStage,
  metadata?: Record<string, unknown>,
): ModerationEntityType {
  if (typeof metadata?.entity === 'string' && metadata.entity === 'comment') {
    return 'comment';
  }
  if (typeof metadata?.audioAssetId === 'string' || typeof metadata?.sessionId === 'string') {
    return 'voice';
  }
  if (typeof metadata?.artifactId === 'string') {
    return 'artifact';
  }
  if (typeof metadata?.postId === 'string') {
    return 'project';
  }
  if (stage === 'report') {
    return 'report';
  }
  if (stage === 'publication') {
    return 'project';
  }
  return 'chat';
}

async function getViolationCount(userId: string): Promise<number> {
  const snapshot = await db
    .collection('moderationCases')
    .where('userId', '==', userId)
    .where('status', '==', 'resolved')
    .get();
  return snapshot.docs.filter((doc) => {
    const data = doc.data() as ModerationCase;
    return data.decisions.some((d) => d.action === 'block');
  }).length;
}

async function applyEscalation(userId: string, reason?: string): Promise<void> {
  const userRef = db.collection('users').doc(userId);
  const count = await getViolationCount(userId);
  await userRef.set(
    {
      moderationWarnings: FieldValue.increment(1),
      bannedUntil: null,
      permanentlyBanned: false,
    },
    { merge: true },
  );
  logger.info('Escalation: ban enforcement disabled (warning only)', { userId, reason, violationCount: count });
}

async function ensureModerationCase(args: {
  eventId: string;
  userId: string;
  entityType: ModerationEntityType;
  entityId?: string;
  severity: ModerationCase['severity'];
  reason?: string;
  evidence?: Record<string, unknown>;
}): Promise<ModerationCase> {
  const existingSnapshot = await db
    .collection('moderationCases')
    .where('eventId', '==', args.eventId)
    .limit(1)
    .get();
  if (!existingSnapshot.empty) {
    return { ...(existingSnapshot.docs[0].data() as ModerationCase), id: existingSnapshot.docs[0].id };
  }
  const now = new Date().toISOString();
  const decision: ModerationDecision = {
    id: uuidv4(),
    actorType: 'system',
    action: args.severity === 'blocked' ? 'block' : 'review',
    rationale: args.reason ?? 'Automatically escalated by moderation pipeline.',
    createdAt: now,
  };
  const moderationCase: ModerationCase = {
    id: uuidv4(),
    eventId: args.eventId,
    userId: args.userId,
    entityType: args.entityType,
    entityId: args.entityId,
    status: args.severity === 'blocked' ? 'resolved' : 'open',
    severity: args.severity,
    reason: args.reason,
    evidence: args.evidence,
    decisions: [decision],
    createdAt: now,
    updatedAt: now,
  };
  await db.collection('moderationCases').doc(moderationCase.id).set(moderationCase);

  if (decision.action === 'block') {
    await applyEscalation(args.userId, args.reason);
  }

  return moderationCase;
}

function generationPushLanguage(job: GenerationJob): 'ru' | 'en' {
  const language = typeof job.metadata?.language === 'string' ? job.metadata.language.toLowerCase() : '';
  return language.startsWith('ru') ? 'ru' : 'en';
}

function generationPushTitle(job: GenerationJob): string {
  const candidates = [
    job.metadata?.displayTitle,
    job.metadata?.title,
    job.metadata?.threadTitle,
    job.prompt,
  ];
  for (const candidate of candidates) {
    if (typeof candidate !== 'string') continue;
    const title = candidate.trim().replace(/\s+/g, ' ');
    if (title) return title.slice(0, 80);
  }
  return 'Generation';
}

function generationPushAction(type: string): string {
  if (type === 'generation_review_needed') return 'open_review';
  if (type === 'generation_failed') return 'open_retry';
  return 'open_preview';
}

function generationPushData(job: GenerationJob, type: string, title: string, language = generationPushLanguage(job)): Record<string, string> {
  const data: Record<string, string> = {
    type,
    jobId: job.id,
    kind: job.kind,
    title,
    language,
    route: 'generation',
    screen: 'generation_preview',
    action: generationPushAction(type),
    status: job.status,
  };
  if (job.threadId) data.threadId = job.threadId;
  if (typeof job.metadata?.projectKind === 'string') data.projectKind = job.metadata.projectKind;
  if (typeof job.metadata?.contentSubcategory === 'string') {
    data.contentSubcategory = job.metadata.contentSubcategory;
  }
  return data;
}

async function sendGenerationTerminalPush(job: GenerationJob): Promise<void> {
  const title = generationPushTitle(job);
  const language = generationPushLanguage(job);
  if (job.status === 'completed' || job.status === 'partial') {
    await sendPushNotification(
      job.userId,
      language === 'ru'
        ? { title: 'Генерация готова', body: `«${title}» готов к экспорту. Нажмите, чтобы открыть превью.` }
        : { title: 'Generation Ready!', body: `“${title}” is ready to export. Tap to open the preview.` },
      generationPushData(job, 'generation_completed', title),
      'generations',
    );
    logger.info('Generation terminal push queued', { jobId: job.id, status: job.status, kind: job.kind });
    return;
  }

  if (job.status === 'awaiting_review') {
    await sendPushNotification(
      job.userId,
      language === 'ru'
        ? { title: 'Нужен апрув', body: `«${title}» ждёт апрува. Нажмите, чтобы открыть превью.` }
        : { title: 'Review needed', body: `“${title}” needs approval. Tap to open the preview.` },
      generationPushData(job, 'generation_review_needed', title),
      'generations',
    );
    logger.info('Generation review push queued', { jobId: job.id, status: job.status });
    return;
  }

  if (job.status === 'failed') {
    await sendPushNotification(
      job.userId,
      language === 'ru'
        ? { title: 'Генерация остановилась', body: `«${title}» остановился до экспорта. Нажмите, чтобы открыть экран генерации.` }
        : { title: 'Generation Failed', body: `“${title}” stopped before export. Tap to open the generation screen.` },
      generationPushData(job, 'generation_failed', title),
      'generations',
    );
    logger.info('Generation failed push queued', { jobId: job.id, status: job.status });
  }
}

async function runGenerationJobLifecycle(jobId: string, job: GenerationJob): Promise<GenerationJob> {
  const processingJob: GenerationJob = {
    ...job,
    status: 'processing',
    updatedAt: new Date().toISOString(),
    history: [...job.history, 'Started generation worker'],
    dispatchMode: job.dispatchMode ?? (getJobDispatchMode() as JobDispatchMode),
    workerTarget: job.workerTarget ?? getRobloxWorkerCommand() ?? getRobloxWorkerUrl(),
  };
  await db.collection('generationJobs').doc(jobId).set(processingJob, { merge: true });
  const completed = await processGenerationJob(jobId, processingJob);
  await db.collection('generationJobs').doc(jobId).set(completed, { merge: true });
  if (completed.status === 'completed' || completed.status === 'partial' || completed.status === 'awaiting_review') {
    syncThreadProjectMemoryFromJob(completed).catch((err) => {
      logger.error('Failed to sync thread project memory from generation job', { jobId, error: errorMessage(err) });
    });
  }

  sendGenerationTerminalPush(completed).catch(() => {});

  return completed;
}

