type FurnitureBuildMode = 'auto' | 'parts' | 'mesh';

function normalizeFurnitureBuildMode(value: unknown): FurnitureBuildMode | null {
  if (typeof value !== 'string') return null;
  const normalized = value.trim().toLowerCase().replace(/[\s-]+/g, '_');
  if (!normalized) return null;
  if (['parts', 'fast_parts', 'roblox_parts', 'primitive_parts', 'blocks', 'blocky', 'cubes'].includes(normalized)) return 'parts';
  if (['mesh', 'ai_mesh', '3d_mesh', '3d', 'pbr_mesh', 'detailed_mesh'].includes(normalized)) return 'mesh';
  if (['auto', 'automatic', 'decide_for_me', 'recommended'].includes(normalized)) return 'auto';
  return null;
}

function preferredFurnitureBuildMode(metadata: Record<string, unknown>): FurnitureBuildMode {
  return normalizeFurnitureBuildMode(metadata.furnitureBuildMode)
    ?? normalizeFurnitureBuildMode(metadata.furnitureMode)
    ?? normalizeFurnitureBuildMode(metadata.buildMode)
    ?? 'auto';
}

function resolveFurnitureBuildMode(prompt: string, metadata: Record<string, unknown>): FurnitureBuildMode {
  const preferred = preferredFurnitureBuildMode(metadata);
  if (preferred === 'parts' || preferred === 'mesh') return preferred;
  const text = [
    prompt,
    metadata.latestUserIntent,
    metadata.title,
    metadata.style,
    metadata.material,
    metadata.visualDescription,
    JSON.stringify(metadata),
  ]
    .filter((value): value is string => typeof value === 'string' && value.trim().length > 0)
    .join(' ')
    .toLowerCase();
  if (/\b(fast\s*parts?|roblox\s*parts?|primitive\s*parts?|parts\s*only|blocky|blocks?|cubes?|no\s*mesh|without\s*(?:ai\s*)?mesh)\b|кубик|кубиками|блоками|частями|деталями|без\s*(?:3d|3д|ai)?\s*(?:mesh|меш|мэш)/i.test(text)) {
    return 'parts';
  }
  if (/\b(ai\s*mesh|3d\s*mesh|mesh\s*quality|pbr|realistic|high\s*detail|ornate|organic|sculpted|velvet|plush|tufted|statue|throne|sofa|couch|armchair|chandelier)\b|меш|мэш|реалист|детальн|сложн|бархат|плюш|резн|орнамент|диван|кресл|трон|стату|люстр/i.test(text)) {
    return 'mesh';
  }
  return 'parts';
}

// Furniture supports a fast Roblox Parts path and an AI mesh path. The mesh path
