type VehicleTypeId = 'car' | 'motorcycle' | 'boat' | 'plane' | 'helicopter' | 'tank' | 'spaceship' | 'bicycle' | 'bus';

interface VehicleManifestReviewFacts {
  vehicleType: string;
  driveMode: string;
  partCount: number;
  wheelCount: number;
  seatCount: number;
  hasDriveSeat: boolean;
  hasController: boolean;
  hasEngineSound: boolean;
  hasVfx: boolean;
  hasRaceFrameMarkers: boolean;
  matchedMarkers: string[];
  missingMarkers: string[];
  // Layer 2 — visual heuristics that catch "looks like a slab even though all named parts exist"
  monochromeBodyShare: number; // 0..1, fraction of body volume in single dominant primary color
  bodyVerticalLayerRange: number; // Y-spread of underbody/body/cabin/roof centers (studs)
  glassToBodyAreaRatio: number; // side-view glass area / side-view body area
  steeringWheelVisibleThroughWindshield: boolean; // steering wheel sits in cabin window band with glass in front
}

interface VehicleManifestReviewRun {
  manifest: RobloxBuildManifest;
  metadata: Record<string, unknown>;
  review: ObbyQualityReviewResult;
  attempts: ObbyQualityReviewResult[];
}

function vehicleManifestSearchText(manifest: RobloxBuildManifest): string {
  const sceneText = manifest.scene
    .map((node) => `${node.className} ${node.name} ${node.properties ? JSON.stringify(node.properties).slice(0, 700) : ''}`)
    .join('\n');
  const scriptText = manifest.scripts.map((script) => `${script.name} ${script.scriptType} ${script.container}`).join('\n');
  return `${sceneText}\n${scriptText}`.toLowerCase();
}

function vehicleManifestFacts(manifest: RobloxBuildManifest): VehicleManifestReviewFacts {
  const text = vehicleManifestSearchText(manifest);
  const vehicleType = typeof manifest.metadata?.vehicleType === 'string' ? manifest.metadata.vehicleType : 'unknown';
  const driveMode = typeof manifest.metadata?.driveMode === 'string' ? manifest.metadata.driveMode : 'unknown';
  const partCount = manifest.scene.filter((node) => node.className === 'Part' || node.className === 'VehicleSeat' || node.className === 'Seat').length;
  const wheelCount = manifest.scene.filter((node) => /^Wheel\d+$/i.test(node.name)).length;
  const seatCount = manifest.scene.filter((node) => node.className === 'Seat' || node.className === 'VehicleSeat').length;
  const hasDriveSeat = manifest.scene.some((node) => node.className === 'VehicleSeat' && /driveseat/i.test(node.name));
  const hasController = manifest.scripts.some((script) => /vehiclecontroller/i.test(script.name)) || /vehiclecontroller/.test(text);
  const hasEngineSound = manifest.scene.some((node) => node.className === 'Sound' && /engine/i.test(node.name));
  const hasVfx = manifest.scene.some((node) => node.className === 'ParticleEmitter');
  // Mesh-mode detection: when buildVehicleModelManifest emitted a MeshPart
  // body (Meshy v6 GLB url present in metadata), the procedural family-car
  // markers do not exist. QA must accept the mesh-mode car as a different
  // structural shape rather than rejecting it for "missing FamilyCarBodyShell".
  const hasMeshBody = manifest.scene.some((node) => node.className === 'MeshPart' && /VehicleMeshBody/i.test(node.name));
  // Session 373: VehicleSceneRoot marker is now ONLY a debug breadcrumb that
  // the LLM contributed accents on top of the procedural baseline. The body
  // shell is always procedural (FamilyCar*), so required-marker logic stays
  // on the FamilyCar checks. We do NOT short-circuit to ['VehicleSceneRoot',…]
  // because that would skip the actual car structure validation.
  const requiredMarkers = hasMeshBody
    ? ['VehicleMeshBody', 'DriveSeat', 'VehicleController']
    : vehicleType === 'car'
    ? [
        'FamilyCarBodyShell',
        'FamilyCarCabinShell',
        'FamilyCarRoofPanel',
        'FamilyCarWindshieldLarge',
        'FamilyCarFrontGrilleWide',
        'FamilyCarSteeringWheelVisible',
        'ChromeOuterRim',
        'FamilyCarVisibleRim',
      ]
    : (vehicleType === 'motorcycle' || vehicleType === 'bicycle')
      ? [
          'FuelTank',
          'EngineBlock',
          'FrontForkLeft',
          'FrontForkRight',
          'GaugeCluster',
          'TwoWheelBalanceSkidLeft',
          'TwoWheelBalanceSkidRight',
          'BrakeDisc',
        ]
      : ['DriveSeat', 'VehicleController'];
  const matchedMarkers = requiredMarkers.filter((marker) => text.includes(marker.toLowerCase()));
  const missingMarkers = requiredMarkers.filter((marker) => !text.includes(marker.toLowerCase()));
  // Race-frame markers are EXACT names of parts emitted by the old (pre-
  // session-367) sports-car builder. Substring matching used to false-
  // positive on legitimate family-car trims (e.g. RearSpoilerTrim, which
  // contains the substring "rearspoiler" even though it is a tiny chrome
  // moulding). Switch to exact-name set lookup against scene nodes.
  const OLD_RACE_FRAME_NAMES = new Set([
    'CarCenterTunnel',
    'CarRearEngineCover',
    'RearSpoiler', 'RearSpoilerLeft', 'RearSpoilerRight',
    'CockpitRearBulkhead',
    'RoofAirScoop',
  ]);
  const hasRaceFrameMarkers = vehicleType === 'car'
    && manifest.scene.some((node) => OLD_RACE_FRAME_NAMES.has(node.name));
  const visual = computeVehicleVisualFacts(manifest, vehicleType);
  return {
    vehicleType,
    driveMode,
    partCount,
    wheelCount,
    seatCount,
    hasDriveSeat,
    hasController,
    hasEngineSound,
    hasVfx,
    hasRaceFrameMarkers,
    matchedMarkers,
    missingMarkers,
    monochromeBodyShare: visual.monochromeBodyShare,
    bodyVerticalLayerRange: visual.bodyVerticalLayerRange,
    glassToBodyAreaRatio: visual.glassToBodyAreaRatio,
    steeringWheelVisibleThroughWindshield: visual.steeringWheelVisibleThroughWindshield,
  };
}

interface VehicleVisualFacts {
  monochromeBodyShare: number;
  bodyVerticalLayerRange: number;
  glassToBodyAreaRatio: number;
  steeringWheelVisibleThroughWindshield: boolean;
}

function computeVehicleVisualFacts(manifest: RobloxBuildManifest, vehicleType: string): VehicleVisualFacts {
  const BODY_NAME_RX = /(BodyShell|CabinShell|RoofPanel|Hood|CargoBlock|SidePanel|Fender|Underbody|Bumper|Hull|Fuselage|Cabin)/i;
  const GLASS_NAME_RX = /(Windshield|RearGlass|FrontWindow|RearWindow|Glass|CockpitGlass|WindDeflector)/i;
  const SKIP_RX = /(QARepair|Trim|Light|Tail|Spoke|Hub|Mirror|Plate|Stripe|Handle|Seam|Slat|Skirt|Rack)/i;
  const HIDDEN_RX = /(Root|Chassis|Collider|Attach|Constraint)/i;

  const parts = manifest.scene.filter((n) => n.className === 'Part');
  type Box = { name: string; cx: number; cy: number; cz: number; sx: number; sy: number; sz: number; volume: number; transparency: number; isGlass: boolean; isBody: boolean; colorKey: string; colorR: number; colorG: number; colorB: number };

  const boxes: Box[] = parts.map((p) => {
    const props = (p as { properties?: Record<string, unknown> }).properties ?? {};
    const size = (props as { Size?: { x?: number; y?: number; z?: number } }).Size ?? { x: 0, y: 0, z: 0 };
    const cf = (props as { CFrame?: { position?: { x?: number; y?: number; z?: number } } }).CFrame ?? {};
    const pos = cf.position ?? { x: 0, y: 0, z: 0 };
    const col = (props as { Color?: { r?: number; g?: number; b?: number } }).Color ?? { r: 0, g: 0, b: 0 };
    const mat = String((props as { Material?: string }).Material ?? '');
    const transparency = Number((props as { Transparency?: number }).Transparency ?? 0);
    const r = Number(col.r ?? 0);
    const g = Number(col.g ?? 0);
    const b = Number(col.b ?? 0);
    const sx = Number(size.x ?? 0);
    const sy = Number(size.y ?? 0);
    const sz = Number(size.z ?? 0);
    // Material- and transparency-based glass detection only; name-based check
    // would mis-count opaque accent trims like "HoodToWindshieldTrim" as glass area.
    // Exclude effectively invisible physics helpers (ChassisRoot etc.) and parts
    // named like internal hidden helpers.
    const isHiddenHelper = HIDDEN_RX.test(p.name) || transparency >= 0.95;
    const isGlass = !isHiddenHelper && (mat === 'Glass' || (transparency >= 0.3 && transparency < 0.95)) && !SKIP_RX.test(p.name);
    const isBody = !isGlass && !isHiddenHelper && !SKIP_RX.test(p.name) && BODY_NAME_RX.test(p.name);
    // Quantize color to 0.05 buckets so near-identical reds count as one color.
    const colorKey = `${Math.round(r * 20)}_${Math.round(g * 20)}_${Math.round(b * 20)}`;
    return {
      name: p.name,
      cx: Number(pos.x ?? 0),
      cy: Number(pos.y ?? 0),
      cz: Number(pos.z ?? 0),
      sx,
      sy,
      sz,
      volume: Math.max(0, sx * sy * sz),
      transparency,
      isGlass,
      isBody,
      colorKey,
      colorR: r,
      colorG: g,
      colorB: b,
    };
  });

  // 1) monochromeBodyShare: dominant-color body volume / total body volume.
  const bodyBoxes = boxes.filter((b) => b.isBody);
  const totalBodyVolume = bodyBoxes.reduce((acc, b) => acc + b.volume, 0);
  const volumeByColor = new Map<string, number>();
  for (const b of bodyBoxes) {
    volumeByColor.set(b.colorKey, (volumeByColor.get(b.colorKey) ?? 0) + b.volume);
  }
  const dominantVolume = Array.from(volumeByColor.values()).reduce((m, v) => Math.max(m, v), 0);
  const monochromeBodyShare = totalBodyVolume > 0 ? dominantVolume / totalBodyVolume : 0;

  // 2) bodyVerticalLayerRange: Y-spread of canonical layer parts.
  const layerNames = ['FamilyCarUnderbody', 'FamilyCarBodyShell', 'FamilyCarCabinShell', 'FamilyCarRoofPanel'];
  const ys = boxes.filter((b) => layerNames.some((n) => b.name === n)).map((b) => b.cy);
  const bodyVerticalLayerRange = ys.length >= 2 ? Math.max(...ys) - Math.min(...ys) : 0;

  // 3) glassToBodyAreaRatio: side-view (x,y plane) cross-section area.
  const sideArea = (b: Box) => b.sx * b.sy;
  const glassArea = boxes.filter((b) => b.isGlass).reduce((a, b) => a + sideArea(b), 0);
  const bodyArea = bodyBoxes.reduce((a, b) => a + sideArea(b), 0);
  const glassToBodyAreaRatio = bodyArea > 0 ? glassArea / bodyArea : 0;

  // 4) steeringWheelVisibleThroughWindshield: SW between cabin and roof, with a glass part forward of it.
  const sw = boxes.find((b) => b.name === 'FamilyCarSteeringWheelVisible');
  const cabin = boxes.find((b) => b.name === 'FamilyCarCabinShell');
  const roof = boxes.find((b) => b.name === 'FamilyCarRoofPanel');
  const windshield = boxes.find((b) => b.name === 'FamilyCarWindshieldLarge');
  let steeringWheelVisibleThroughWindshield = false;
  if (sw && cabin && roof && windshield) {
    const cabinTop = cabin.cy + cabin.sy / 2;
    const cabinBottom = cabin.cy - cabin.sy / 2;
    const inCabin = sw.cy >= cabinBottom && sw.cy <= roof.cy + roof.sy / 2;
    const windshieldInFront = windshield.cz < sw.cz; // -Z is forward in this builder
    const windshieldTransparentEnough = windshield.transparency >= 0.3;
    const swInWindowYBand = sw.cy >= cabinTop - cabin.sy * 0.5 && sw.cy <= cabinTop + 0.6;
    steeringWheelVisibleThroughWindshield = inCabin && windshieldInFront && windshieldTransparentEnough && swInWindowYBand;
  }

  // For non-car vehicles, skip body-specific signals (return neutral values so they don't trigger car-only checks).
  if (vehicleType !== 'car') {
    return {
      monochromeBodyShare: 0,
      bodyVerticalLayerRange: 0,
      glassToBodyAreaRatio: 0,
      steeringWheelVisibleThroughWindshield: false,
    };
  }

  return { monochromeBodyShare, bodyVerticalLayerRange, glassToBodyAreaRatio, steeringWheelVisibleThroughWindshield };
}

function deterministicVehicleReview(args: {
  prompt: string;
  manifest: RobloxBuildManifest;
}): ObbyQualityReviewResult {
  const facts = vehicleManifestFacts(args.manifest);
  const issues: string[] = [];
  const repairActions: string[] = [];
  if (!facts.hasDriveSeat) issues.push('missing_drive_seat: vehicle has no VehicleSeat named DriveSeat.');
  if (!facts.hasController) issues.push('missing_controller: vehicle has no VehicleController script.');
  if (!facts.hasEngineSound) issues.push('missing_engine_sound: vehicle has no engine Sound marker.');
  if (!facts.hasVfx) issues.push('missing_vfx: vehicle has no wheel/exhaust ParticleEmitter markers.');
  if (facts.driveMode === 'land_wheels' && facts.wheelCount < 2) issues.push(`missing_wheels: land vehicle has only ${facts.wheelCount} wheel part(s).`);
  // Detect mesh-mode export: the builder swapped the procedural family-sedan
  // body for a single MeshPart named VehicleMeshBody when Meshy v6 returned a
  // mesh URL. Mesh-mode does NOT have FamilyCar* / monochrome / vertical /
  // glass-area / steering-visible heuristics applicable — the body is one
  // mesh, not a stack of Blocks — so those car-specific checks are skipped.
  const hasMeshBody = args.manifest.scene.some((node) => node.className === 'MeshPart' && /VehicleMeshBody/i.test(node.name));
  // Session 373: LLM scene is now ACCENT-ONLY on top of the procedural
  // baseline — `VehicleSceneRoot` marker only signals that accents were
  // contributed, not that the body itself is custom. Heuristics must still
  // validate the FamilyCar* baseline. Only a real MeshPart body skips them.
  const isCustomBody = hasMeshBody;
  if (facts.vehicleType === 'car' && !isCustomBody) {
    if (facts.partCount < 105) issues.push(`low_car_detail: car has ${facts.partCount} physical/seat parts; premium vehicle exports need at least 105.`);
    if (facts.hasRaceFrameMarkers) issues.push('race_frame_silhouette: car still contains sports/race-frame body markers instead of the boxy family-car shell.');
    if (facts.missingMarkers.length > 0) issues.push(`missing_family_car_markers: ${facts.missingMarkers.join(', ')}.`);
    if (/family|семейн|low[-\s]*poly|cartoon|мульт|машин/i.test(args.prompt) && !facts.matchedMarkers.includes('FamilyCarBodyShell')) {
      issues.push('prompt_mismatch_family_car: prompt asks for a readable family/cartoon car but manifest lacks FamilyCarBodyShell.');
    }
    if (facts.monochromeBodyShare >= 0.7) {
      issues.push(`monochrome_silhouette: ${Math.round(facts.monochromeBodyShare * 100)}% of body volume is in one color; large coplanar same-color panels read as a flat slab from chase camera.`);
      repairActions.push('Recolor roof, hood, and trim in a contrasting tone (silver/black accent over red body) so the cabin reads as a separate volume.');
    }
    if (facts.bodyVerticalLayerRange < 1.2) {
      issues.push(`flat_body_layers: vertical range between underbody/body/cabin/roof centers is only ${facts.bodyVerticalLayerRange.toFixed(2)} studs; expected at least 1.2 for a readable 3D silhouette.`);
      repairActions.push('Raise cabin and roof higher above body shell; ensure underbody / body / cabin / roof centers are clearly separated by Y.');
    }
    if (facts.glassToBodyAreaRatio < 0.08) {
      issues.push(`low_glass_area: glass parts cover only ${Math.round(facts.glassToBodyAreaRatio * 100)}% of body side area; windshield/windows too small to break up the body.`);
      repairActions.push('Enlarge windshield, rear glass, and door windows; bump glass transparency to 0.35-0.45 so interior reads.');
    }
    if (!facts.steeringWheelVisibleThroughWindshield) {
      issues.push('steering_wheel_hidden: FamilyCarSteeringWheelVisible is not positioned in the cabin window band behind a transparent windshield.');
      repairActions.push('Raise steering wheel Y to cabin window band; enlarge its diameter; ensure windshield in front of it has transparency >= 0.3.');
    }
    repairActions.push('Rebuild as a boxy low-poly family car, not a race-frame wedge.');
    repairActions.push('Add large readable body shell, doors, roof, windshield, grille, headlights, and visible steering wheel.');
    repairActions.push('Add chrome wheel rings/spokes and sidewall detail for all four wheels.');
  } else if (facts.vehicleType === 'car' && isCustomBody) {
    // Custom-body car (Meshy MeshPart or LLM-scene): only structural checks
    // (DriveSeat / wheels / controller already covered above). Trust the body
    // — its visual quality is the LLM/Meshy's responsibility, not the
    // deterministic family-sedan heuristic battery's.
    if (facts.missingMarkers.length > 0) issues.push(`missing_custom_car_markers: ${facts.missingMarkers.join(', ')}.`);
  } else if (facts.vehicleType === 'motorcycle' || facts.vehicleType === 'bicycle') {
    if (facts.partCount < 52) issues.push(`low_two_wheel_detail: ${facts.vehicleType} has ${facts.partCount} physical/seat parts; expected detailed tank/forks/engine/fenders/brakes.`);
    if (facts.missingMarkers.length > 0) issues.push(`missing_two_wheel_markers: ${facts.missingMarkers.join(', ')}.`);
    repairActions.push('Add tank, engine block, forks, fenders, brake discs, grips, gauge cluster, exhaust and visible seat stack.');
    repairActions.push('Add two-wheel arcade stabilizer: balance skids plus upright controller so it does not fall sideways.');
  }
  if (repairActions.length === 0) repairActions.push('Keep DriveSeat, passenger seats, controller, engine sound, VFX and readable vehicle silhouette.');
  const score = Math.max(5, 100 - issues.length * 18 - Math.max(0, facts.missingMarkers.length - 1) * 4);
  return {
    status: issues.length > 0 ? 'rejected' : 'passed',
    score,
    userMessage: issues.length > 0
      ? `Vehicle QA rejected this export before download: ${issues[0]}`
      : `Vehicle QA passed: ${facts.vehicleType} has ${facts.partCount} parts, ${facts.wheelCount} wheels, controller, sounds and VFX.`,
    reasons: issues.length > 0
      ? issues
      : [
          `vehicleType=${facts.vehicleType}; driveMode=${facts.driveMode}; parts=${facts.partCount}; wheels=${facts.wheelCount}; seats=${facts.seatCount}`,
          `matched markers: ${facts.matchedMarkers.join(', ') || 'core vehicle markers'}`,
        ],
    repairActions,
    reviewer: 'deterministic',
  };
}

function renderVehicleSideSilhouetteAscii(manifest: RobloxBuildManifest): string {
  // Deterministic side-view (Y vs Z) ASCII projection of the manifest so the
  // text-only LLM reviewer can "see" the silhouette without an actual image.
  // Resolution: 24 cols (Z) x 12 rows (Y). Each cell records the highest-priority
  // role hit by any part footprint that covers that (z, y) area.
  const COLS = 24;
  const ROWS = 12;
  const parts = manifest.scene.filter((n) => n.className === 'Part');
  const boxes = parts.map((p) => {
    const props = (p as { properties?: Record<string, unknown> }).properties ?? {};
    const size = (props as { Size?: { x?: number; y?: number; z?: number } }).Size ?? { x: 0, y: 0, z: 0 };
    const cf = (props as { CFrame?: { position?: { x?: number; y?: number; z?: number } } }).CFrame ?? {};
    const pos = cf.position ?? { x: 0, y: 0, z: 0 };
    const transparency = Number((props as { Transparency?: number }).Transparency ?? 0);
    return {
      name: p.name,
      cy: Number(pos.y ?? 0),
      cz: Number(pos.z ?? 0),
      sy: Number(size.y ?? 0),
      sz: Number(size.z ?? 0),
      transparency,
    };
  });
  if (boxes.length === 0) return '(empty)';
  const visible = boxes.filter((b) => b.transparency < 0.95);
  if (visible.length === 0) return '(empty)';
  const yLo = Math.min(...visible.map((b) => b.cy - b.sy / 2));
  const yHi = Math.max(...visible.map((b) => b.cy + b.sy / 2));
  const zLo = Math.min(...visible.map((b) => b.cz - b.sz / 2));
  const zHi = Math.max(...visible.map((b) => b.cz + b.sz / 2));
  const yRange = Math.max(yHi - yLo, 0.0001);
  const zRange = Math.max(zHi - zLo, 0.0001);
  const grid: string[][] = Array.from({ length: ROWS }, () => Array.from({ length: COLS }, () => '.'));
  // Priority: higher = more important; later writes only if higher priority.
  const ROLE_PRIORITY: Record<string, number> = { '.': 0, B: 1, C: 2, R: 3, W: 4, G: 5, S: 6 };
  function roleFor(name: string): string {
    if (/SteeringWheelVisible/i.test(name)) return 'S';
    if (/^Wheel\d+$|ChromeOuterRim|VisibleRim|TireSidewallStripe|BrakeDisc/i.test(name)) return 'W';
    if (/Windshield|RearGlass|FrontWindow|RearWindow|Glass(?!.*Trim)|CockpitGlass/i.test(name)) return 'G';
    if (/Roof(Panel|Edge)/i.test(name)) return 'R';
    if (/CabinShell|CabinBackPanel|InteriorFloor|Dashboard/i.test(name)) return 'C';
    if (/BodyShell|Hood|CargoBlock|Fender|Bumper|SidePanel|Underbody|Hull|Fuselage/i.test(name)) return 'B';
    return '';
  }
  for (const b of visible) {
    const role = roleFor(b.name);
    if (!role) continue;
    const zCol0 = Math.max(0, Math.floor(((b.cz - b.sz / 2) - zLo) / zRange * COLS));
    const zCol1 = Math.min(COLS - 1, Math.floor(((b.cz + b.sz / 2) - zLo) / zRange * COLS));
    const yRow0 = Math.max(0, Math.floor(((b.cy - b.sy / 2) - yLo) / yRange * ROWS));
    const yRow1 = Math.min(ROWS - 1, Math.floor(((b.cy + b.sy / 2) - yLo) / yRange * ROWS));
    for (let yRow = yRow0; yRow <= yRow1; yRow += 1) {
      for (let zCol = zCol0; zCol <= zCol1; zCol += 1) {
        const yIdx = ROWS - 1 - yRow; // flip so top of grid = high Y
        const existing = grid[yIdx][zCol];
        if ((ROLE_PRIORITY[role] ?? 0) > (ROLE_PRIORITY[existing] ?? 0)) {
          grid[yIdx][zCol] = role;
        }
      }
    }
  }
  return grid.map((row) => row.join('')).join('\n');
}

async function runVehicleLlmQualityReview(args: {
  prompt: string;
  title: string;
  facts: VehicleManifestReviewFacts;
  deterministic: ObbyQualityReviewResult;
  manifest: RobloxBuildManifest;
  previewPng?: Buffer;
}): Promise<ObbyQualityReviewResult | null> {
  const digest = {
    vehicleType: args.facts.vehicleType,
    driveMode: args.facts.driveMode,
    partCount: args.facts.partCount,
    wheelCount: args.facts.wheelCount,
    seatCount: args.facts.seatCount,
    hasDriveSeat: args.facts.hasDriveSeat,
    hasController: args.facts.hasController,
    hasEngineSound: args.facts.hasEngineSound,
    hasVfx: args.facts.hasVfx,
    hasRaceFrameMarkers: args.facts.hasRaceFrameMarkers,
    matchedMarkers: args.facts.matchedMarkers,
    missingMarkers: args.facts.missingMarkers,
    monochromeBodyShare: args.facts.monochromeBodyShare,
    bodyVerticalLayerRange: args.facts.bodyVerticalLayerRange,
    glassToBodyAreaRatio: args.facts.glassToBodyAreaRatio,
    steeringWheelVisibleThroughWindshield: args.facts.steeringWheelVisibleThroughWindshield,
    prominentPartNames: args.manifest.scene
      .filter((node) => /familycar|steering|wheel|rim|fender|hood|roof|door|windshield|fuel|engine|fork|balance|brake/i.test(node.name))
      .map((node) => `${node.className}:${node.name}`)
      .slice(0, 90),
    sideSilhouetteAscii: renderVehicleSideSilhouetteAscii(args.manifest),
  };
  const hasImage = args.previewPng && args.previewPng.length > 0;
  const hasMeshBody = args.manifest.scene.some((node) => node.className === 'MeshPart' && /VehicleMeshBody/i.test(node.name));
  const system = [
    'You are a strict Roblox Vehicles QA reviewer.',
    'Review factual manifest evidence AND a rendered preview image of the vehicle before a .rbxm is exported to the user.',
    hasMeshBody
      ? 'MESH MODE: this build uses a single MeshPart "VehicleMeshBody" generated by Meshy v6 as the entire car body. Procedural family-car heuristics (monochromeBodyShare, bodyVerticalLayerRange, glassToBodyAreaRatio, steeringWheelVisibleThroughWindshield, sideSilhouetteAscii) WILL READ AS ZERO/FLAT because the body is one mesh — that is EXPECTED, not a defect. Do NOT reject for those heuristics in mesh mode. Judge the body purely from the rendered image. The chassis (wheels, DriveSeat, controller, sounds, VFX) is still procedural and the matched markers list should confirm those.'
      : 'PROCEDURAL MODE: build is 100% procedural Roblox Parts. Reject if the model does not match the user brief, e.g. a family car looks like a flat race-frame wedge, no readable body, no visible steering wheel, no wheel details. Pay close attention to manifestDigest.monochromeBodyShare (>=0.8 means same-color body that visually merges into a slab), bodyVerticalLayerRange (<1.2 means body/cabin/roof are coplanar), glassToBodyAreaRatio (<0.08 means windows too small to break up the body), and steeringWheelVisibleThroughWindshield (must be true so the user sees the wheel through the front glass).',
    hasMeshBody
      ? ''
      : 'Also study manifestDigest.sideSilhouetteAscii: deterministic side-view projection. Vertical axis Y, horizontal axis Z (front to back). Characters: B=body, C=cabin, R=roof, G=glass, W=wheel, S=steering wheel, .=empty. A correct family car shows three stacked layers (R top, C+G middle, B below, W at bottom). A flat strip of "B" with wheels and almost no "C"/"R" is the slab failure mode — reject.',
    hasImage
      ? (hasMeshBody
          ? 'The first content block is the Meshy v6 rendered preview of the GLB body mesh the user will receive. LOOK at it. Reject ONLY if the mesh is clearly broken — e.g. a featureless blob, the wrong type of object (clothing, character, building), or completely unrelated to the brief. Do NOT reject for "missing cabin layer" / "no windows" / "no procedural detail" — the body is one mesh; those heuristics do not apply.'
          : 'The first content block is a PNG preview rendered directly from the Roblox Parts manifest the user is about to receive. LOOK at it. Reject when the rendered image shows a flat slab, missing cabin/roof, indistinguishable colors blending into one mass, no readable doors/windows/headlights, or anything that does not match the user brief.')
      : 'No rendered preview image was available for this attempt — judge from the manifest facts and ASCII silhouette only.',
    'Do not reward speed. A slower export is acceptable only if quality passes.',
    'Output JSON only: {"status":"passed|warning|rejected","score":0-100,"userMessage":"short user-facing reason","reasons":["..."],"repairActions":["concrete fixes"]}.',
  ].filter(Boolean).join('\n');
  const user = JSON.stringify({
    userPrompt: args.prompt.slice(0, 1600),
    title: args.title,
    manifestDigest: digest,
    deterministicReview: {
      status: args.deterministic.status,
      score: args.deterministic.score,
      reasons: args.deterministic.reasons,
      repairActions: args.deterministic.repairActions,
    },
  }, null, 2);

  // Try Claude vision first when we have a rendered PNG, so the LLM
  // critic actually looks at the image instead of judging by JSON alone.
  // Tight 25s timeout: the critic is advisory now (deterministic gates
  // export), so a slow Anthropic call must not stall the whole pipeline.
  if (hasImage && args.previewPng) {
    try {
      const result = await runAnthropicVisionStructured(
        {
          system,
          user,
          images: [{ base64: args.previewPng.toString('base64'), mediaType: 'image/png' }],
        },
        defaults.anthropicModel,
        25_000,
      );
      const parsed = parseQualityReviewResponse(result.text ?? '');
      if (parsed?.status) {
        return {
          status: parsed.status,
          score: parsed.score ?? 0,
          userMessage: parsed.userMessage ?? 'Vehicle quality review completed.',
          reasons: parsed.reasons ?? [],
          repairActions: parsed.repairActions ?? [],
          reviewer: 'llm_vision',
          llmProvider: 'anthropic',
        };
      }
      logger.warn('[VehicleQualityReview] invalid Anthropic vision response, falling back to text providers');
    } catch (err) {
      logger.warn('[VehicleQualityReview] Anthropic vision failed, falling back to text providers', { error: errorMessage(err) });
    }
  }

  // Text-only fallback chain. Each provider gets a tight budget so the entire
  // QA stage stays under ~60s in the worst case (25s vision + 20s+15s+10s text).
  const attempts: Array<{ provider: AIProvider; model?: string; timeoutMs: number }> = [
    { provider: 'anthropic', model: defaults.anthropicModel, timeoutMs: 20_000 },
    { provider: 'openai', model: defaults.chatModel, timeoutMs: 15_000 },
    { provider: 'gemini', model: defaults.geminiModel, timeoutMs: 10_000 },
  ];
  for (const attempt of attempts) {
    try {
      const result = await runSingleChatProvider(attempt.provider, { system, user }, attempt.model, { timeoutMs: attempt.timeoutMs });
      const parsed = parseQualityReviewResponse(result.text ?? '');
      if (!parsed?.status) {
        logger.warn('[VehicleQualityReview] invalid LLM response', { provider: attempt.provider });
        continue;
      }
      return {
        status: parsed.status,
        score: parsed.score ?? 0,
        userMessage: parsed.userMessage ?? 'Vehicle quality review completed.',
        reasons: parsed.reasons ?? [],
        repairActions: parsed.repairActions ?? [],
        reviewer: 'llm',
        llmProvider: attempt.provider,
      };
    } catch (err) {
      logger.warn('[VehicleQualityReview] provider failed', { provider: attempt.provider, error: errorMessage(err) });
    }
  }
  return null;
}

async function reviewVehicleManifestWithRepair(args: {
  prompt: string;
  title: string;
  initialMetadata: Record<string, unknown>;
  buildManifest: (metadata: Record<string, unknown>) => RobloxBuildManifest;
  maxAttempts?: number;
}): Promise<VehicleManifestReviewRun> {
  const maxAttempts = Math.max(1, Math.min(args.maxAttempts ?? 2, 3));
  let metadata: Record<string, unknown> = {
    ...args.initialMetadata,
    vehicleQualityTier: 'premium_reviewed',
    vehicleQualityReviewEnabled: true,
  };
  let bestManifest = args.buildManifest(metadata);
  let bestReview = deterministicVehicleReview({ prompt: args.prompt, manifest: bestManifest });
  const attempts: ObbyQualityReviewResult[] = [];

  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    const manifest = args.buildManifest({
      ...metadata,
      vehicleQualityAttempt: attempt,
    });
    const deterministic = deterministicVehicleReview({ prompt: args.prompt, manifest });
    // Preview image for the vision critic. In MESH MODE we must use Meshy's
    // own thumbnail of the generated GLB — our blocky-renderer
    // (createFurniturePreviewPng) cannot render MeshPart with a remote GLB
    // URL, so it would feed the reviewer black rectangles and trigger false
    // rejections like "rendered image shows abstract black rectangles".
    // In procedural fallback mode (no mesh URL) the blocky renderer is the
    // right choice — the manifest is 100% Block parts which it renders well.
    const meshThumbnailUrl = typeof (manifest.metadata?.vehicleMeshThumbnailUrl) === 'string'
      ? (manifest.metadata.vehicleMeshThumbnailUrl as string)
      : '';
    const hasMeshBody = manifest.scene.some((node) => node.className === 'MeshPart' && /VehicleMeshBody/i.test(node.name));
    // Session 373: VehicleSceneRoot is now an LLM-accent debug breadcrumb,
    // NOT a marker that the body is custom. The body remains the procedural
    // FamilyCar* baseline, so the visual heuristics + LLM critic should run
    // and validate it. Only a real MeshPart body skips them.
    const isCustomBody = hasMeshBody;
    let previewPng: Buffer | undefined;
    let llmReview: ObbyQualityReviewResult | null = null;
    // SIMPLIFIED REVIEW: skip the LLM/vision critic entirely when the body is
    // already custom-composed (mesh from Meshy OR LLM-scene from gemini). Two
    // reasons:
    //   1. The composer already validated the scene at creation time
    //      (validateVehicleScene) — adding a second LLM review on top creates
    //      false-positive reject loops the user can't escape.
    //   2. The procedural visual heuristics (monochromeBodyShare,
    //      bodyVerticalLayerRange, glassToBodyAreaRatio, steeringWheelVisible
    //      ThroughWindshield) all measure FamilyCar* Block geometry that does
    //      not exist in custom-body mode — they always read as 0/1.0, which
    //      the LLM reviewer kept parroting as defects.
    // The deterministic gate (which only enforces DriveSeat / wheels /
    // controller in custom-body mode) is the sole authoritative blocker.
    if (!isCustomBody) {
      if (hasMeshBody && meshThumbnailUrl) {
        try {
          const thumbResp = await fetch(meshThumbnailUrl);
          if (thumbResp.ok) {
            const arrayBuf = await thumbResp.arrayBuffer();
            previewPng = Buffer.from(arrayBuf);
          }
        } catch (thumbErr) {
          logger.warn('[VehicleQualityReview] Meshy thumbnail fetch failed', { error: errorMessage(thumbErr) });
        }
      }
      if (!previewPng) {
        try {
          const scene = createVehiclePreviewSceneFromManifest(manifest, args.title);
          previewPng = createFurniturePreviewPng(scene, args.title);
        } catch (renderErr) {
          logger.warn('[VehicleQualityReview] preview render failed; text-only critic', { error: errorMessage(renderErr) });
        }
      }
      llmReview = await runVehicleLlmQualityReview({
        prompt: args.prompt,
        title: args.title,
        facts: vehicleManifestFacts(manifest),
        deterministic,
        manifest,
        previewPng,
      });
    }
    // BOTH the deterministic battery AND the LLM/vision critic can block the
    // export. Deterministic catches measurable structural failures
    // (monochrome / flat layers / no glass / hidden steering); vision catches
    // anything the rules can't see (proportions wrong, doesn't look like a
    // car, wheels too big, etc.) — that was the whole point of adding the
    // image-aware critic. We still ship when the LLM is unavailable, so a
    // transient provider outage doesn't sink every export.
    const llmAvailable = !!llmReview;
    const llmRejected = llmReview?.status === 'rejected';
    const llmSeriousRejection = llmRejected && (llmReview?.score ?? 0) < 55;
    const review: ObbyQualityReviewResult = llmReview
      ? {
          ...llmReview,
          // Reject when deterministic rejects OR when LLM/vision gives a
          // serious rejection (status=rejected AND score<55). A merely
          // skeptical LLM (rejected but score>=55) downgrades to warning so
          // the export still ships — the model is borderline, not broken.
          status: deterministic.status === 'rejected'
            ? 'rejected'
            : (llmSeriousRejection ? 'rejected' : (llmRejected ? 'warning' : llmReview.status)),
          score: Math.round(((deterministic.score) + (llmReview.score ?? deterministic.score)) / 2),
          reviewer: 'deterministic+llm',
          reasons: [...deterministic.reasons, ...(llmReview.reasons ?? [])].slice(0, 10),
          repairActions: [...deterministic.repairActions, ...(llmReview.repairActions ?? [])].slice(0, 10),
          userMessage: deterministic.status === 'rejected'
            ? deterministic.userMessage
            : (llmSeriousRejection
                ? `Vision QA rejected this export: ${llmReview.userMessage}`
                : (llmRejected
                    ? `Vehicle exported with an AI-flagged concern: ${llmReview.userMessage}. The deterministic safety checks all passed, so the model still ships.`
                    : llmReview.userMessage)),
        }
      : {
          // LLM provider failure no longer blocks the export. Deterministic
          // verdict is authoritative when the LLM critic isn't reachable.
          ...deterministic,
          status: deterministic.status,
          score: deterministic.score,
          reviewer: 'deterministic',
          userMessage: deterministic.status === 'rejected'
            ? deterministic.userMessage
            : 'Vehicle passed deterministic QA checks. AI-vision reviewer was unavailable for this attempt, but the safety-critical signals all passed.',
          reasons: deterministic.status === 'passed'
            ? [...deterministic.reasons, 'LLM/vision reviewer unavailable; deterministic checks were sole gatekeeper.']
            : deterministic.reasons,
          repairActions: deterministic.repairActions,
        };
    attempts.push(review);
    bestManifest = manifest;
    bestReview = review;
    // Exit when BOTH gates accept the build (deterministic not rejected AND
    // vision/LLM did not seriously reject it). Otherwise loop into another
    // repairBoost attempt — that's the whole point of having a vision review.
    if (review.status !== 'rejected') {
      return { manifest, metadata: { ...metadata, vehicleQualityReviewAttemptCount: attempt, vehicleQualityLlmAdvisory: llmAvailable ? llmReview?.status : 'unavailable' }, review, attempts };
    }
    metadata = {
      ...metadata,
      vehicleQualityTier: 'premium_reviewed_retry',
      vehicleQualityRepairActions: review.repairActions,
      vehicleQualityPreviousReasons: review.reasons,
      vehicleQualityReviewAttemptCount: attempt,
      repairMode: 'vehicle_quality_review_retry',
    };
  }

  return { manifest: bestManifest, metadata, review: bestReview, attempts };
}

function detectVehicleType(prompt: string, metadata?: Record<string, unknown>): VehicleTypeId {
  const raw = typeof metadata?.vehicleType === 'string' ? metadata.vehicleType.toLowerCase().trim() : '';
  const known = new Set<VehicleTypeId>(['car', 'motorcycle', 'boat', 'plane', 'helicopter', 'tank', 'spaceship', 'bicycle', 'bus']);
  if (known.has(raw as VehicleTypeId)) return raw as VehicleTypeId;
  const haystack = `${prompt} ${metadata?.title ?? ''} ${metadata?.genre ?? ''} ${metadata?.theme ?? ''}`.toLowerCase();
  if (/\b(bus|coach|shuttle)\b|автобус|маршрутк/i.test(haystack)) return 'bus';
  if (/\b(tank|armored|armoured|tread|tracked)\b|танк|гусениц/i.test(haystack)) return 'tank';
  if (/\b(helicopter|heli|chopper|rotor)\b|вертол/i.test(haystack)) return 'helicopter';
  if (/\b(plane|airplane|jet|fighter|aircraft)\b|самол[её]т|истреб/i.test(haystack)) return 'plane';
  if (/\b(boat|ship|speedboat|yacht|submarine)\b|лодк|корабл|яхт|катер/i.test(haystack)) return 'boat';
  if (/\b(spaceship|space\s*ship|starfighter|ufo|rocket)\b|косми|звездол|ракета|нло/i.test(haystack)) return 'spaceship';
  if (/\b(motorcycle|motorbike|bike|hoverbike)\b|мото|байк/i.test(haystack)) return 'motorcycle';
  if (/\b(bicycle|cycle|bmx)\b|велосип/i.test(haystack)) return 'bicycle';
  return 'car';
}

function vehicleDriveMode(vehicleType: VehicleTypeId): string {
  switch (vehicleType) {
    case 'boat': return 'watercraft';
    case 'plane': return 'aircraft';
    case 'helicopter': return 'rotorcraft';
    case 'tank': return 'tracked';
    case 'spaceship': return 'hover';
    case 'car':
    case 'motorcycle':
    case 'bicycle':
    case 'bus':
    default:
      return 'land_wheels';
  }
}

function inferVehicleSeatCount(vehicleType: VehicleTypeId, metadata?: Record<string, unknown>): number {
  const explicit = Number(metadata?.seatCount ?? metadata?.passengerCount);
  if (Number.isFinite(explicit) && explicit > 0) return Math.max(1, Math.min(12, Math.round(explicit)));
  switch (vehicleType) {
    case 'motorcycle':
    case 'bicycle':
      return 2;
    case 'plane':
    case 'helicopter':
    case 'boat':
    case 'tank':
    case 'spaceship':
      return 4;
    case 'bus':
      return 8;
    case 'car':
    default:
      return 4;
  }
}

