  const serverSource = `-- ${safeName} server-side use logic + AI mesh loader
local Players = game:GetService("Players")
local InsertService = game:GetService("InsertService")

local tool = script.Parent
-- Config ModuleScript lives inside the Tool (sibling to this Script)
local configModule = tool:WaitForChild("${safeName}Config", 5)
if not configModule then warn("[${safeName}] Config not found inside Tool — aborting"); return end
local Config = require(configModule)

-- RemoteEvent for client feedback (floating text + sound trigger)
local effectEvent = tool:FindFirstChild("EffectEvent")
if not effectEvent then
\teffectEvent = Instance.new("RemoteEvent")
\teffectEvent.Name = "EffectEvent"
\teffectEvent.Parent = tool
end

local lastUse = {}
local currentPlayer

-- Fires client feedback (popup + sound) and delays Tool:Destroy() so the
-- sound/particle burst can finish before the Tool disappears from Backpack.
local function finishUse(effectText, colorKey, consumeOverride)
\tif currentPlayer then
\t\tpcall(function() effectEvent:FireClient(currentPlayer, effectText or "", colorKey or "white") end)
\tend
\tlocal shouldConsume = consumeOverride
\tif shouldConsume == nil then shouldConsume = Config.Consumable end
\tif shouldConsume then
\t\ttask.delay(1.2, function() if tool.Parent then tool:Destroy() end end)
\tend
end

-- ── AI mesh runtime loader ─────────────────────────────────────────
-- meshAssetId is a Model asset (uploaded via Open Cloud). SpecialMesh.MeshId cannot load
-- Model IDs, so we pull the model via InsertService:LoadAsset at runtime, scale to Handle
-- size and weld all its BaseParts to Handle (matches session #095 weapon pattern).
local AI_MESH_MODEL_ID = ${numericMeshModelId}

local function loadAiMesh()
\tif AI_MESH_MODEL_ID == 0 then return end
\tlocal Handle = tool:FindFirstChild("Handle")
\tif not Handle then return end
\tlocal ok, loaded = pcall(function()
\t\treturn InsertService:LoadAsset(AI_MESH_MODEL_ID)
\tend)
\tif not (ok and loaded) then
\t\twarn("[${safeName}] InsertService:LoadAsset failed for " .. tostring(AI_MESH_MODEL_ID))
\t\treturn
\tend
\tlocal parts = {}
\tfor _, desc in loaded:GetDescendants() do
\t\tif desc:IsA("BasePart") then table.insert(parts, desc) end
\tend
\tif #parts == 0 then loaded:Destroy(); return end

\t-- Hide Handle's fallback SpecialMesh so AI mesh is the only visible geometry.
\tlocal sm = Handle:FindFirstChildOfClass("SpecialMesh")
\tif sm then sm.Scale = Vector3.new(0, 0, 0) end
\t-- Make Handle invisible but keep it present (Tool requires Handle for grip/welds).
\tHandle.Transparency = 1

\t-- Pick largest part as primary, scale wrapper Model to Handle's longest dimension.
\tlocal primary = parts[1]
\tlocal maxVol = 0
\tfor _, p in parts do
\t\tlocal v = p.Size.X * p.Size.Y * p.Size.Z
\t\tif v > maxVol then maxVol = v; primary = p end
\tend
\tlocal tmp = Instance.new("Model")
\ttmp.Parent = workspace
\tfor _, p in parts do p.Parent = tmp end
\ttmp.PrimaryPart = primary
\tlocal _, preSize = tmp:GetBoundingBox()
\tlocal meshLong = math.max(preSize.X, preSize.Y, preSize.Z)
\t-- Target ~3 studs for the longest axis so items/tools render at a readable
\t-- in-hand size regardless of how Meshy exported the model. Handle's own size
\t-- (often 1x1x1 for pickups) is a poor scale reference because it would shrink
\t-- large tools (pickaxes, flashlights) into invisible nubs.
\tlocal TARGET_LONG = 3
\tif meshLong > 0.01 then tmp:ScaleTo(TARGET_LONG / meshLong) end

\t-- Align to Handle position, weld every piece to Handle.
\ttmp:PivotTo(Handle.CFrame)
\tfor _, p in tmp:GetDescendants() do
\t\tif p:IsA("BasePart") then
\t\t\tp.Anchored = false
\t\t\tp.CanCollide = false
\t\t\tp.Massless = true
\t\t\tlocal w = Instance.new("WeldConstraint")
\t\t\tw.Part0 = Handle
\t\t\tw.Part1 = p
\t\t\tw.Parent = p
\t\t\tp.Parent = tool
\t\tend
\tend
\ttmp:Destroy()
\tloaded:Destroy()
end

task.spawn(loadAiMesh)

tool.Activated:Connect(function()
\tlocal player = Players:GetPlayerFromCharacter(tool.Parent)
\tif not player then return end
\tlocal now = tick()
\tif lastUse[player.UserId] and now - lastUse[player.UserId] < Config.Cooldown then return end
\tlastUse[player.UserId] = now

\tlocal char = tool.Parent
\tlocal hum = char and char:FindFirstChildOfClass("Humanoid")
\tif not hum then return end

\tcurrentPlayer = player
\tlocal ok, err = pcall(function()
${bodyByType[itemType]}
\tend)
\tif not ok then warn("[${safeName}] use failed:", err); finishUse("Error", "red") end
end)

Players.PlayerRemoving:Connect(function(player)
\tlastUse[player.UserId] = nil
end)
`;

