function trollObbyDeterministicIssues(args: {
  facts: TrollObbyScriptFacts;
  expectations: TrollObbyBriefExpectations;
  expectedThemeKey: string;
}): string[] {
  const { facts, expectations, expectedThemeKey } = args;
  const issues: string[] = [];
  if (!facts.hasTrollRuntime) issues.push('missing_troll_runtime: final package does not contain the Obby Troll runtime world builder.');
  if (!facts.hasConfigModule) issues.push('missing_troll_config: final package is missing TrollObbyConfig with levels/traps.');
  if (!facts.hasGotchaRemote || !facts.hasGotchaClient) issues.push('missing_gotcha_ui: final package is missing the GOTCHA feedback loop expected for Obby Troll.');
  if (!facts.hasFirstRunCue) issues.push('missing_first_run_cue: first playable route does not expose an obvious RUN cue.');
  if (facts.trapEntries.length === 0) issues.push('missing_traps: final package contains no configured troll trap stages.');
  if (facts.trapEntries.length > 0 && !facts.hasFairRoutes) issues.push('missing_fair_routes: trap stages have no fair bypass/readability route markers.');
  if (facts.levelOneTrap) issues.push('level_1_trap: level 1 must stay a warm-up normal stage, not a trap.');
  if (facts.invalidFakeCheckpointLevels.length > 0) {
    issues.push(`fake_checkpoint_on_real_checkpoint: fake checkpoints are placed on real checkpoint levels (${facts.invalidFakeCheckpointLevels.join(', ')}).`);
  }
  if (facts.savagery !== 'lite' && facts.trapEntries.length > 0 && !facts.hasEarlyTroll) {
    issues.push('missing_early_troll: medium/savage troll obbies need a troll moment shortly after the warm-up.');
  }

  if (expectedThemeKey && expectedThemeKey !== 'default') {
    if (!facts.themeKey) {
      issues.push(`wrong_theme: user brief resolves to ${expectedThemeKey}, but generated TrollObbyConfig has no themeKey.`);
    } else if (facts.themeKey !== expectedThemeKey) {
      issues.push(`wrong_theme: user brief resolves to ${expectedThemeKey}, but generated TrollObbyConfig themeKey is ${facts.themeKey}.`);
    }
  }
  if (expectations.requestedLevels && facts.totalLevels !== expectations.requestedLevels) {
    issues.push(`wrong_stage_count: user requested ${expectations.requestedLevels} stages, but generated ${facts.totalLevels ?? 'unknown'} stages.`);
  }
  if (expectations.requestedCheckpointEvery && facts.checkpointEvery !== expectations.requestedCheckpointEvery) {
    issues.push(`wrong_checkpoint_cadence: user requested checkpoint every ${expectations.requestedCheckpointEvery}, but generated every ${facts.checkpointEvery ?? 'unknown'}.`);
  }
  if (expectations.requestedSavagery && facts.savagery !== expectations.requestedSavagery) {
    issues.push(`wrong_savagery: user requested ${expectations.requestedSavagery}, but generated ${facts.savagery ?? 'unknown'}.`);
  }

  const trapTotal = facts.trapEntries.length;
  if (expectations.focusedTrapTypes.length > 0 && trapTotal > 0) {
    const focusCount = expectations.focusedTrapTypes.reduce((sum, type) => sum + facts.trapCounts[type], 0);
    const focusRatio = focusCount / trapTotal;
    const missing = expectations.focusedTrapTypes.filter((type) => facts.trapCounts[type] === 0);
    if (missing.length > 0) {
      issues.push(`missing_focused_trap: user focused ${missing.map((type) => TROLL_OBBY_TRAP_LABELS[type]).join(', ')}, but those traps are absent.`);
    }
    if (focusRatio < 0.80) {
      issues.push(`focused_trap_diluted: user asked for focused ${expectations.focusedTrapTypes.map((type) => TROLL_OBBY_TRAP_LABELS[type]).join(', ')}, but only ${Math.round(focusRatio * 100)}% of trap stages match.`);
    }
    if (expectations.focusedTrapTypes.includes('invisible_kill') && !facts.hasInvisibleSpikeTell) {
      issues.push('missing_invisible_spike_tell: invisible spike focus needs the InvisibleSpikeGlitch/fair visual tell so the trap is playable, not random.');
    }
  } else if (expectations.focusedTrapTypes.length > 0 && trapTotal === 0) {
    issues.push(`missing_focused_trap: user focused ${expectations.focusedTrapTypes.map((type) => TROLL_OBBY_TRAP_LABELS[type]).join(', ')}, but no traps were generated.`);
  }

  if (expectations.wantsAllSixTraps && trapTotal >= 6 && facts.uniqueTrapTypes.length < 6) {
    issues.push(`all_6_not_generated: user requested all 6 trap types, but only ${facts.uniqueTrapTypes.length} types are present.`);
  } else if (expectations.wantsMixedTraps && (facts.totalLevels ?? 0) >= 15 && trapTotal >= 5 && facts.uniqueTrapTypes.length < 4) {
    issues.push(`mixed_traps_too_narrow: user requested mixed traps, but only ${facts.uniqueTrapTypes.length} trap types are present.`);
  }

  const levels = facts.totalLevels ?? 0;
  if (levels >= 10 && facts.savagery === 'medium' && trapTotal < Math.max(3, Math.floor((levels - 1) * 0.35))) {
    issues.push(`trap_density_too_low: medium savagery generated only ${trapTotal} trap stages for ${levels} levels.`);
  }
  if (levels >= 10 && facts.savagery === 'savage' && trapTotal < Math.max(5, Math.floor((levels - 1) * 0.55))) {
    issues.push(`trap_density_too_low: savage mode generated only ${trapTotal} trap stages for ${levels} levels.`);
  }
  return issues.slice(0, 10);
}

function trollObbyRepairActions(expectations: TrollObbyBriefExpectations, facts: TrollObbyScriptFacts): string[] {
  const actions = [
    'Regenerate the same Obby Troll & Trap Maker request from the original user brief only; do not treat previous rejection wording as a new theme.',
    'Keep contentSubcategory/gameKind as obby_troll and emit valid GDD JSON for buildTrollObbyScript.',
    'Preserve TrollObbyConfig, TrollGotcha, first RUN cue, fair bypass routes, and a real warm-up level 1 before export.',
  ];
  if (expectations.focusedTrapTypes.length > 0) {
    actions.push(`Use ${expectations.focusedTrapTypes.map((type) => TROLL_OBBY_TRAP_LABELS[type]).join(' + ')} for 80-100% of trap stages; do not mix in other trap types unless the user asked for All 6 mixed.`);
  } else if (expectations.wantsAllSixTraps) {
    actions.push('Include all 6 trap types at least once when there are enough trap slots.');
  } else if (expectations.wantsMixedTraps) {
    actions.push('Include at least 4 distinct trap types for a mixed 15+ stage troll obby.');
  }
  if (expectations.requestedLevels) actions.push(`Set totalLevels exactly to ${expectations.requestedLevels}.`);
  if (expectations.requestedCheckpointEvery) actions.push(`Set checkpointEvery exactly to ${expectations.requestedCheckpointEvery} and never place fake checkpoints on real checkpoint levels.`);
  if (expectations.requestedSavagery) actions.push(`Set savagery exactly to ${expectations.requestedSavagery} and match the trap density for that mode.`);
  if (facts.trapEntries.length === 0) actions.push('Populate trolls[] with concrete level/type/intensity entries; level 1 must remain normal.');
  return actions.slice(0, 8);
}

async function runObbyTrollLlmQualityReview(args: {
  brief: string;
  latestUserIntent: string;
  title: string;
  expectedThemeKey: string;
  expectations: TrollObbyBriefExpectations;
  facts: TrollObbyScriptFacts;
  deterministicFacts: string[];
}): Promise<ObbyQualityReviewResult | null> {
  const system = [
    'You are a strict Roblox QA reviewer for Obby Troll & Trap Maker packages.',
    'The original user request is authoritative. Compare it to factual Lua/Config evidence only.',
    'Reject if the generated package is not obby_troll, misses TrollObbyConfig/GOTCHA/traps, uses the wrong theme/stage count/savagery/checkpoint cadence, or dilutes a focused trap request.',
    'If the user picked one trap type, 80-100% of trap stages must use that focused trap. Only "All 6 mixed" means broad variety.',
    'Do not reject merely because a trap is mean; troll obbies are expected to be prank-like, but must remain playable with warm-up, cues, and fair routes.',
    'Output JSON only: {"status":"passed|warning|rejected","score":0-100,"userMessage":"short user-facing reason","reasons":["..."],"repairActions":["..."]}.',
  ].join('\n');
  const user = JSON.stringify({
    requestedBrief: args.brief.slice(0, 1400),
    latestUserIntent: args.latestUserIntent.slice(0, 900),
    title: args.title,
    expectedThemeKey: args.expectedThemeKey,
    expectations: {
      focusedTrapTypes: args.expectations.focusedTrapTypes,
      wantsMixedTraps: args.expectations.wantsMixedTraps,
      wantsAllSixTraps: args.expectations.wantsAllSixTraps,
      requestedLevels: args.expectations.requestedLevels,
      requestedSavagery: args.expectations.requestedSavagery,
      requestedCheckpointEvery: args.expectations.requestedCheckpointEvery,
      cleanIntent: args.expectations.intentText.slice(0, 900),
    },
    factualRuntimeReview: args.deterministicFacts,
    parsedFacts: {
      themeKey: args.facts.themeKey,
      totalLevels: args.facts.totalLevels,
      checkpointEvery: args.facts.checkpointEvery,
      savagery: args.facts.savagery,
      trapCounts: args.facts.trapCounts,
      uniqueTrapTypes: args.facts.uniqueTrapTypes,
      trapEntries: args.facts.trapEntries.slice(0, 30),
      hasTrollRuntime: args.facts.hasTrollRuntime,
      hasConfigModule: args.facts.hasConfigModule,
      hasGotchaRemote: args.facts.hasGotchaRemote,
      hasGotchaClient: args.facts.hasGotchaClient,
      hasFairRoutes: args.facts.hasFairRoutes,
      hasFirstRunCue: args.facts.hasFirstRunCue,
      hasEarlyTroll: args.facts.hasEarlyTroll,
    },
  }, null, 2);
  const attempts: Array<{ provider: AIProvider; model?: string }> = [
    { provider: 'anthropic', model: defaults.anthropicModel },
    { provider: 'openai', model: defaults.chatModel },
    { provider: 'gemini', model: defaults.geminiModel },
  ];
  for (const attempt of attempts) {
    try {
      const result = await runSingleChatProvider(attempt.provider, { system, user }, attempt.model, { timeoutMs: 75_000 });
      const parsed = parseQualityReviewResponse(result.text ?? '');
      if (!parsed?.status) {
        logger.warn('[ObbyTrollQualityReview] invalid LLM response', { provider: attempt.provider });
        continue;
      }
      return {
        status: parsed.status,
        score: parsed.score ?? 0,
        userMessage: parsed.userMessage ?? 'Obby Troll quality review completed.',
        reasons: parsed.reasons ?? [],
        repairActions: parsed.repairActions ?? [],
        reviewer: 'llm',
        llmProvider: attempt.provider,
      };
    } catch (err) {
      logger.warn('[ObbyTrollQualityReview] provider failed', { provider: attempt.provider, error: errorMessage(err) });
    }
  }
  return null;
}

async function reviewGeneratedTrollObbyPackage(args: {
  brief: string;
  latestUserIntent: string;
  title: string;
  script: string;
  expectedThemeKey: string;
  metadata?: Record<string, unknown>;
}): Promise<ObbyQualityReviewResult> {
  const metadata = args.metadata ?? {};
  const expectations = detectObbyTrollBriefExpectations(`${args.latestUserIntent}\n${args.brief}`, metadata);
  const facts = parseTrollObbyScriptFacts(args.script);
  const deterministicFacts = trollObbyFactLines(facts, expectations);
  const issues = trollObbyDeterministicIssues({ facts, expectations, expectedThemeKey: args.expectedThemeKey });
  if (issues.length > 0) {
    return {
      status: 'rejected',
      score: Math.max(5, 45 - issues.length * 5),
      userMessage: `Quality review stopped this troll obby before export: ${issues[0]}`,
      reasons: issues,
      repairActions: trollObbyRepairActions(expectations, facts),
      reviewer: 'deterministic',
    };
  }

  const llmReview = await runObbyTrollLlmQualityReview({
    brief: args.brief,
    latestUserIntent: args.latestUserIntent,
    title: args.title,
    expectedThemeKey: args.expectedThemeKey,
    expectations,
    facts,
    deterministicFacts,
  });
  if (!llmReview) {
    return {
      status: 'warning',
      score: 80,
      userMessage: 'Deterministic Obby Troll checks passed, but the AI reviewer was unavailable. Export can continue with a warning.',
      reasons: ['Obby Troll runtime facts match deterministic brief checks.', 'LLM reviewer was unavailable or returned invalid JSON.'],
      repairActions: ['Inspect the generated troll obby in Studio and regenerate if the trap focus still feels off.'],
      reviewer: 'deterministic',
    };
  }
  const status: ObbyQualityStatus = llmReview.status === 'rejected' || llmReview.score < 65 ? 'rejected' : llmReview.status;
  return {
    ...llmReview,
    status,
    reviewer: 'deterministic+llm',
    reasons: llmReview.reasons.length > 0 ? llmReview.reasons : deterministicFacts,
    repairActions: llmReview.repairActions.length > 0 ? llmReview.repairActions : trollObbyRepairActions(expectations, facts),
  };
}

async function reviewGeneratedObbyPackage(args: {
  brief: string;
  latestUserIntent: string;
  title: string;
  script: string;
  expectedThemeKey: string;
  visualSpec: unknown;
  apifyTasks: ObbyApifyReferenceTask[];
  contentSubcategory?: string;
  metadata?: Record<string, unknown>;
}): Promise<ObbyQualityReviewResult> {
  if (args.contentSubcategory === 'obby_troll' || /TrollObbyConfig|TrollObbyWorld/.test(args.script)) {
    return reviewGeneratedTrollObbyPackage({
      brief: args.brief,
      latestUserIntent: args.latestUserIntent,
      title: args.title,
      script: args.script,
      expectedThemeKey: args.expectedThemeKey,
      metadata: args.metadata,
    });
  }

  const deterministic = deterministicObbyQualityFacts(args.script, args.expectedThemeKey, `${args.brief} ${args.latestUserIntent}`);
  if (deterministic.issues.length > 0) {
    return {
      status: 'rejected',
      score: 20,
      userMessage: 'Quality review stopped this obby before export because required playability or theme markers were missing.',
      reasons: deterministic.issues,
      repairActions: [
        'Regenerate the obby with the requested theme locked.',
        'Rebuild route bridge, route arrows, connector pads, and readability lights.',
        'Use neutral lab metal/concrete as the base palette and keep toxic green only as hazard accents.',
        'If the prompt says monster lab, add visible monster/specimen props before export.',
        'Keep Apify assets as references only until the map passes route checks.',
      ],
      reviewer: 'deterministic',
    };
  }

  const llmReview = await runObbyLlmQualityReview({
    brief: args.brief,
    latestUserIntent: args.latestUserIntent,
    title: args.title,
    expectedThemeKey: args.expectedThemeKey,
    visualSpec: args.visualSpec,
    deterministicFacts: deterministic.facts,
    apifyTasks: args.apifyTasks,
  });
  if (!llmReview) {
    return {
      status: 'warning',
      score: 78,
      userMessage: 'Deterministic quality checks passed, but the AI reviewer was unavailable. The export can continue with a warning.',
      reasons: ['Deterministic route and theme markers passed.', 'LLM quality reviewer was unavailable or returned invalid JSON.'],
      repairActions: ['Inspect the generated map in Studio and regenerate if the prompt match still feels off.'],
      reviewer: 'deterministic',
    };
  }
  const status: ObbyQualityStatus = llmReview.status === 'rejected' || llmReview.score < 65 ? 'rejected' : llmReview.status;
  return {
    ...llmReview,
    status,
    reviewer: 'deterministic+llm',
    reasons: llmReview.reasons.length > 0 ? llmReview.reasons : ['LLM reviewer returned no detailed reasons.'],
    repairActions: llmReview.repairActions.length > 0 ? llmReview.repairActions : ['Regenerate with stricter theme and route requirements.'],
  };
}

async function buildGamePackageArtifacts(
  job: GenerationJob,
  result: Awaited<ReturnType<typeof executeProvider>>,
): Promise<GenerationArtifact[]> {
  const gameBrief = result.text?.trim() || 'Roblox project bundle generated.';
  const latestUserIntent = latestUserIntentForJob(job);
  const displayTitle = summarizeGamePackageTitle(job, gameBrief);
  const gamePackageIntentText = `${gameBrief} ${latestUserIntent}`;
  const target = resolveRobloxBuildTarget(job);
  let obbyApifyReferenceTasks: ObbyApifyReferenceTask[] = [];

  // stagedJob is mutated through each phase so updateStage sees the latest
  // stages array; we persist a Firestore snapshot after every transition so
  // the iOS progress rail updates in near-realtime.
  let stagedJob = job;
  const markStage = async (
    stageId: GenerationStageId,
    patch: Partial<GenerationStageProgress>,
    historyLine?: string,
  ): Promise<void> => {
    stagedJob = updateStage(stagedJob, stageId, patch);
    stagedJob = {
      ...stagedJob,
      updatedAt: new Date().toISOString(),
      history: historyLine ? [...stagedJob.history, historyLine] : stagedJob.history,
    };
    try {
      await persistJobSnapshot(job.id, stagedJob);
    } catch (snapErr) {
      logger.warn('[GamePackageStages] snapshot persist failed', { stageId, error: (snapErr as Error).message });
    }
  };

  // ── Phase 1: Plan systems ──
  await markStage('plan_systems', {
    status: 'processing',
    startedAt: new Date().toISOString(),
  }, 'Planning game systems');

  let sceneSpec: GameSceneSpec | null = null;
  let simulatorSpec: SimulatorSceneSpec | null = null;
  if (target === 'place') {
    // Detect genre for template lookup
    // Generic values like "game", "clone" are iOS defaults — not real genres, skip them
    const rawGenre = typeof job.metadata?.genre === 'string' ? job.metadata.genre : '';
    const genericGenres = ['game', 'clone', 'content', 'ugc', 'fix', 'analyze'];
    const genre = genericGenres.includes(rawGenre.toLowerCase()) ? '' : rawGenre;
    const briefLower = gamePackageIntentText.toLowerCase();
    // Title keywords override metadata genre (Smart Interview often sets "Simulator" for tycoons)
    const briefIsTycoon = briefLower.includes('tycoon') || briefLower.includes('тайкун') || briefLower.includes('фабрик') || briefLower.includes('завод') || briefLower.includes('магнат');
    const briefIsSimulator = briefLower.includes('simulator') || briefLower.includes('симулятор') || briefLower.includes('pet sim') || briefLower.includes('collect') || briefLower.includes('clicker') || briefLower.includes('питомц') || briefLower.includes('кликер');
    const briefIsObby = briefLower.includes('obby') || briefLower.includes('parkour') || briefLower.includes('obstacle course') || briefLower.includes('обби') || briefLower.includes('паркур') || briefLower.includes('полоса препятств');
    const detectedGenre = briefIsObby ? 'obby'
      : briefIsTycoon ? 'tycoon'
      : briefIsSimulator ? 'simulator'
      : genre
      || (briefLower.includes('factory') || briefLower.includes('фабрик') || briefLower.includes('завод') ? 'tycoon' : '')
      || '';

    // Session #149 HOTFIX: brainrot_sim Steal-a-Brainrot mode brings its own
    // world layout (conveyor + radial plots + stands + rebirth portal) created
    // at runtime by buildBrainrotConveyorScript. Generating the simulator
    // pet-game scene on top would mash a sandcastle/egg-hatchery/power-up world
    // into the manifest alongside our conveyor — exactly the bug user reported.
    // Skip both simulator + obby/tycoon static templates for brainrot_sim, leave
    // sceneSpec=null so the manifest stays empty and the runtime script owns
    // the world.
    const subcategoryForGenre = typeof (job.metadata as Record<string, unknown>)?.contentSubcategory === 'string'
      ? ((job.metadata as Record<string, unknown>).contentSubcategory as string).toLowerCase()
      : '';
    const isBrainrotSim = subcategoryForGenre === 'brainrot_sim';
    const isObbyTroll = subcategoryForGenre === 'obby_troll';
    const playableGddForScene = parsePlayableGddJson(gameBrief, 'playable_scene_routing', job.id);
    const simulatorKindForScene = typeof playableGddForScene.simulatorKind === 'string'
      ? playableGddForScene.simulatorKind.toLowerCase()
      : '';
    const briefSimulatorVariant = briefLower.includes('mining') || briefLower.includes('fighting') || briefLower.includes('muscle') || briefLower.includes('clicker');
    const runtimeOwnedSimulator = subcategoryForGenre === 'simulator' && (TRAINING_SIMULATOR_KINDS.has(simulatorKindForScene) || briefSimulatorVariant);
    const runtimeOwnedPlayable = RUNTIME_PLAYABLE_SUBCATEGORIES.has(subcategoryForGenre) || runtimeOwnedSimulator;

    if (isBrainrotSim) {
      sceneSpec = null;
      logger.info('brainrot_sim: skipping simulator scene generation; runtime conveyor script owns the world layout');
    } else if (isObbyTroll) {
      sceneSpec = null;
      logger.info('obby_troll: skipping scene generation; runtime troll-obby script owns the world layout', { jobId: job.id });
    } else if (runtimeOwnedPlayable) {
      sceneSpec = null;
      logger.info('playable genre: skipping generic Scene JSON; runtime builder owns the world layout', {
        jobId: job.id,
        contentSubcategory: subcategoryForGenre,
        simulatorKind: simulatorKindForScene || undefined,
      });
    } else if (detectedGenre === 'simulator') {
      // For simulators: try LLM-generated dynamic layout first, static fallback
      simulatorSpec = await generateSimulatorSceneSpec(gameBrief);
      if (simulatorSpec) {
        const dynamicScene = buildDynamicSimulatorScene(simulatorSpec);
        sceneSpec = dynamicScene as unknown as GameSceneSpec;
        logger.info('Using LLM-generated dynamic simulator scene', { theme: simulatorSpec.theme.name });
      } else {
        // Fallback to static template
        logger.warn('LLM simulator scene failed, using static template');
        sceneSpec = getGenreSceneTemplate('simulator', briefLower) as unknown as GameSceneSpec;
      }
    } else {
      // Use deterministic template for tycoon (and other supported genres)
      const template = detectedGenre ? getGenreSceneTemplate(detectedGenre, briefLower) : null;
      if (template) {
        sceneSpec = template as unknown as GameSceneSpec;
      } else {
        sceneSpec = await generateSceneFromGDD(gameBrief, job.metadata);
        // Fallback: ensure genre-critical functional parts exist
        if (sceneSpec && detectedGenre) {
          sceneSpec = ensureGenreRequiredParts(sceneSpec, detectedGenre);
        }
      }
    }
  }

  // ── Phase 1 complete ──
  await markStage('plan_systems', {
    status: 'completed',
    completedAt: new Date().toISOString(),
  });

  // ── Phase 2: Build themed scene (hero 3D assets) ──
  await markStage('build_scene', {
    status: 'processing',
    startedAt: new Date().toISOString(),
  }, 'Building themed scene');

  // ── Hero 3D Assets (tycoon + obby) ──
  let heroAssets: HeroAssetResult[] = [];
  if (target === 'place') {
    // HIGHEST PRIORITY: user's explicit category selection from iOS ("Obby — Text",
    // "Tycoon — Text", etc.) must win over LLM-generated brief keyword matching.
    // Otherwise a brief that happens to mention "tycoon-like income" in a meme obby
    // GDD incorrectly routes hero assets to the tycoon pipeline.
    const subcategoryForHero = typeof (job.metadata as Record<string, unknown>)?.contentSubcategory === 'string'
      ? ((job.metadata as Record<string, unknown>).contentSubcategory as string).toLowerCase()
      : '';
    const briefLowerForHero = gamePackageIntentText.toLowerCase();
    const isTycoonForHero = subcategoryForHero === 'tycoon'
      || (subcategoryForHero === '' && (briefLowerForHero.includes('tycoon') || briefLowerForHero.includes('тайкун') || briefLowerForHero.includes('фабрик') || briefLowerForHero.includes('завод') || briefLowerForHero.includes('магнат') || briefLowerForHero.includes('factory')));
    const isObbyForHero = subcategoryForHero === 'obby'
      || (subcategoryForHero === '' && !isTycoonForHero && (
        briefLowerForHero.includes('obby')
        || briefLowerForHero.includes('обби')
        || briefLowerForHero.includes('паркур')
        || briefLowerForHero.includes('parkour')
      ));

    // Session #223: 3D hero assets disabled for obby — they were not adding
    // visible value (procedural blocks looked off-theme, Meshy generation was
    // slow & failed often, post-Phase 0+A TrendingShowcase already provides
    // visible Roblox-flavour). Obby pipeline goes straight through with
    // heroAssets=[] which is the same code path as the legacy non-meme obby.
    // Keep tycoon hero-asset path untouched — it's gameplay-relevant there.
    if (isObbyForHero) {
      logger.info('obby: skipping 3D hero asset pipeline (session 223 — disabled per user request)', { jobId: job.id });
      heroAssets = [];
      // Mirror the non-hero `else` block so iOS pipeline UI doesn't hang
      // waiting on hero-related stage transitions.
      await markStage('hero_concepts', { status: 'skipped', completedAt: new Date().toISOString(), notes: ['Obby: 3D hero assets disabled'] });
      await markStage('hero_approval', { status: 'skipped', completedAt: new Date().toISOString() });
      await markStage('generate_hero_assets', { status: 'skipped', completedAt: new Date().toISOString(), notes: ['Obby: 3D hero assets disabled'] });
    } else if (isTycoonForHero) {
      // ── Tycoon: direct Meshy generation (no approval step) ──
      await markStage('hero_concepts', { status: 'skipped', completedAt: new Date().toISOString() });
      await markStage('hero_approval', { status: 'skipped', completedAt: new Date().toISOString() });
      await markStage('generate_hero_assets', {
        status: 'processing',
        startedAt: new Date().toISOString(),
        errorMessage: undefined,
      }, 'Generating 3D hero assets via Meshy');

      try {
        const tycoonThemeKey = detectTycoonThemeKey(gameBrief);
        const memeSubTheme = tycoonThemeKey === 'meme' ? detectMemeSubTheme(gameBrief) : '';
        const specs = deriveHeroAssetsForTycoon(tycoonThemeKey);
        heroAssets = await generateHeroAssets(specs, stagedJob, tycoonThemeKey, memeSubTheme);

        const meshCount = heroAssets.filter((h) => h.isMesh).length;
        await markStage('generate_hero_assets', {
          status: meshCount > 0 ? 'completed' : 'skipped',
          completedAt: new Date().toISOString(),
          notes: [`${meshCount}/${specs.length} Meshy 3D assets generated`],
        }, `Hero assets: ${meshCount}/${specs.length} real meshes`);
      } catch (heroErr) {
        const msg = (heroErr as Error).message;
        logger.warn('[HeroAssets] Pipeline failed (non-fatal)', { error: msg });
        heroAssets = [];
        await markStage('generate_hero_assets', { status: 'failed', completedAt: new Date().toISOString(), errorMessage: msg });
      }
    } else {
      // Non-hero genre — skip all hero stages
      await markStage('hero_concepts', { status: 'skipped', completedAt: new Date().toISOString(), notes: ['Genre does not use hero assets'] });
      await markStage('hero_approval', { status: 'skipped', completedAt: new Date().toISOString() });
      await markStage('generate_hero_assets', { status: 'skipped', completedAt: new Date().toISOString(), notes: ['Genre does not use hero 3D assets'] });
    }
  } else {
    // Model target — skip all hero stages
    await markStage('hero_concepts', { status: 'skipped', completedAt: new Date().toISOString() });
    await markStage('hero_approval', { status: 'skipped', completedAt: new Date().toISOString() });
    await markStage('generate_hero_assets', { status: 'skipped', completedAt: new Date().toISOString(), notes: ['Model target skips hero assets'] });
  }

  // ── Phase 2 complete ──
  await markStage('build_scene', {
    status: 'completed',
    completedAt: new Date().toISOString(),
  });

  // ── Phase 3: Assemble Roblox package ──
  await markStage('assemble_package', {
    status: 'processing',
    startedAt: new Date().toISOString(),
  }, 'Assembling Roblox package');

  // ── Generate themed platform textures for obby (in parallel, ~5s total) ──
  // Session #073: Roblox runtime cannot load raw HTTP URLs in ImageLabel.Image —
  // only rbxassetid:// works. After generating textures via Fal.ai, we upload
  // each to Roblox as a Decal, resolve the inner Image ID, and pass
  // rbxassetid://<imageId> URLs to the Lua script.
  // Session #077: Run texture gen + NPC image gen IN PARALLEL with reduced timeouts
  let platformTextureUrls: string[] = [];
  let npcImageUrls: string[] = [];
  const subcategoryForTextures = typeof (job.metadata as Record<string, unknown>)?.contentSubcategory === 'string'
    ? ((job.metadata as Record<string, unknown>).contentSubcategory as string).toLowerCase() : '';
  const briefForTextures = gamePackageIntentText.toLowerCase();
  const isObbyForTextures = subcategoryForTextures === 'obby'
    || (subcategoryForTextures === '' && (briefForTextures.includes('obby') || briefForTextures.includes('parkour') || briefForTextures.includes('обби') || briefForTextures.includes('паркур')));
  if (isObbyForTextures) {
    const texThemeKey = detectObbyThemeKey(gamePackageIntentText);
    const texMemeSubTheme = texThemeKey === 'meme' ? detectMemeSubTheme(gamePackageIntentText) : '';

    // Helper: generate images + upload to Roblox as Decals (shared by textures & NPC images)
    const generateAndUploadImages = async (prompts: string[], labelPrefix: string, genContext: 'game' | 'prop'): Promise<string[]> => {
      const results: string[] = [];
      try {
        const rawUrls: string[] = [];
        const genResults = await Promise.allSettled(
          prompts.map(p => generatePreviewTexture(p, 'roblox', genContext))
        );
        for (const r of genResults) {
          if (r.status === 'fulfilled' && r.value) rawUrls.push(r.value);
        }
        logger.info(`[${labelPrefix}] Generated ${rawUrls.length}/${prompts.length}`);

        const robloxAuth = await getRobloxUserToken(job.userId).catch(() => null);
        if (robloxAuth && rawUrls.length > 0) {
          const uploadResults = await Promise.allSettled(
            rawUrls.map(async (url, i) => {
              try {
                const imgResp = await fetch(url);
                if (!imgResp.ok) return null;
                const imgBuf = Buffer.from(await imgResp.arrayBuffer());
                const upload = await uploadAssetToRoblox({
                  bearerToken: robloxAuth.accessToken,
                  creatorId: robloxAuth.robloxUserId,
                  assetType: 'Decal',
                  name: `${labelPrefix}_${texThemeKey}_${i}`,
                  description: `AI-generated ${labelPrefix.toLowerCase()}`,
                  fileContent: imgBuf,
                  contentType: 'image/png',
                });
                if (!upload) return null;
                let assetId = upload.assetId;
                if (upload.operationId) {
                  // Session #077: reduced poll from 20×3s=60s to 8×2s=16s per asset
                  const polled = await pollRobloxOperation(robloxAuth.accessToken, upload.operationId, 'bearer', 8, 2000);
                  if (polled) assetId = polled;
                }
                if (!assetId) return null;
                const imageId = await resolveImageIdFromDecal(assetId, robloxAuth.accessToken);
                return imageId ? `rbxassetid://${imageId}` : `rbxassetid://${assetId}`;
              } catch (e) {
                logger.warn(`[${labelPrefix}] Upload ${i} failed`, { error: (e as Error).message });
                return null;
              }
            })
          );
          for (const r of uploadResults) {
            if (r.status === 'fulfilled' && r.value) results.push(r.value);
          }
          logger.info(`[${labelPrefix}] Uploaded ${results.length}/${rawUrls.length} to Roblox`);
        }
      } catch (err) {
        logger.warn(`[${labelPrefix}] Failed (non-fatal)`, { error: (err as Error).message });
      }
      return results;
    };

    // Phase G v2 follow-up (session 233): texturePrompts now built BELOW after
    // visualSpec resolves (spec-aware). Hardcoded `getObbyTexturePrompts` is
    // used only as fallback when LLM spec generation fails.
    const npcPrompts: Record<string, string[]> = {
      skibidi: [
        'Skibidi Toilet meme character, human head sticking out of white toilet, singing face, full body front view, vibrant colors, white background, no text',
        'Skibidi Cameraman meme character, camera for a head, holding camera, full body front view, vibrant colors, white background, no text',
      ],
      bombardir: [
        'Bombardiro Crocodilo meme character, green crocodile with airplane wings and propeller nose, full body front view, vibrant colors, white background, no text',
        'Bombardiro Crocodilo flying, green crocodile airplane, side view, vibrant colors, white background, no text',
      ],
      tralalero: [
        'Tralalero Tralala meme character, blue shark wearing white sneakers walking on legs, full body front view, vibrant colors, white background, no text',
        'Tralalero Tralala shark with shoes, blue shark standing upright with legs, front view, vibrant colors, white background, no text',
      ],
      sigma: [
        'Sigma meme character, golden face with black sunglasses, muscular pose, full body front view, vibrant colors, white background, no text',
        'Sigma Boy meme, cool face with sunglasses and crown, front view, vibrant colors, white background, no text',
      ],
    };
    const npcPromptsForTheme = (texThemeKey === 'meme' && texMemeSubTheme) ? (npcPrompts[texMemeSubTheme] || npcPrompts.skibidi) : [];

    // Phase G v2 follow-up (session 233): textures, decoration props, and
    // hydration are now SPEC-DRIVEN. Sequential structure:
    //   Stage 1: kick off visualSpec LLM + NPC gen (NPC doesn't need spec)
    //   Stage 2: when spec resolves, build spec-aware texture/decoration prompts
    //   Stage 3: parallel — texture gen + decoration prop gen + Apify hydration
    // Without this fix, hardcoded `getObbyTexturePrompts(themeKey, ...)` produced
    // bright/generic textures that visually overrode the spec's dark palette via
    // SurfaceGui ImageLabel — user saw default-looking obby despite correct spec.
    const visualSpecPromise = generateObbyVisualSpec({
      brief: gamePackageIntentText.slice(0, 1500),
      title: typeof job.metadata?.title === 'string' ? job.metadata.title : undefined,
    });
    const npcPromise = npcPromptsForTheme.length > 0
      ? generateAndUploadImages(npcPromptsForTheme, 'NpcImg', 'prop')
      : Promise.resolve([] as string[]);

    const spec = await visualSpecPromise;
    const deterministicObbyTheme = ['lab_horror', 'hospital_horror', 'school_horror', 'slime_horror'].includes(texThemeKey);

    // Build texture prompts — spec-aware when available, else hardcoded fallback.
    let texturePrompts: string[];
    if (deterministicObbyTheme) {
      texturePrompts = [];
    } else if (spec) {
      const concepts = spec.decorationConcepts.slice(0, 3).join(', ') || spec.themeName;
      const avgBright = (spec.palette.platform[0] + spec.palette.platform[1] + spec.palette.platform[2]) / 3;
      const isDark = avgBright < 0.40;
      const moodWords = isDark
        ? 'dark moody atmosphere, dim ominous lighting, gritty, weathered, distressed worn surface, low saturation'
        : 'vibrant clean polished, bright, saturated';
      texturePrompts = [
        `seamless tileable Roblox obby platform top-down texture, ${spec.themeName} setting, ${concepts} motifs, ${moodWords}, square tile, no people, no faces, no blood, family-friendly`,
        `cracked floor surface texture, ${spec.themeName} environment, ${moodWords}, top-down square tileable, no characters, family-friendly, no gore`,
        `decorative wall panel pattern, ${spec.themeName} mood, ${concepts}, ${moodWords}, square tileable, family-friendly, no faces`,
        `worn ground surface texture, ${spec.themeName} aesthetic, ${moodWords}, top-down view, seamless square, family-friendly, no blood`,
      ];
    } else {
      texturePrompts = getObbyTexturePrompts(texThemeKey, texMemeSubTheme);
    }

    // Stage 3: parallel image-gen + hydration. Decoration prop prompts also
    // now use spec themeName explicitly (was already there but re-stated for
    // clarity after refactor).
    const decorationPrompts = spec && !deterministicObbyTheme
      ? spec.decorationConcepts.slice(0, 4).map((concept) =>
          `${concept}, ${spec.themeName} theme, isolated decorative prop on white background, full view, no people, no blood, family-friendly, atmospheric`
        )
      : [];

    const [texResults, npcResults, hydratedSpec, propUrls, apifyReferenceResults] = await Promise.all([
      texturePrompts.length > 0
        ? generateAndUploadImages(texturePrompts, 'PlatformTex', 'game')
        : Promise.resolve([] as string[]),
      npcPromise,
      spec && !deterministicObbyTheme
        ? hydrateVisualSpecWithLiveAssets(spec).catch((err) => {
            logger.warn('[ObbyVisualSpec] hydration threw, returning unhydrated spec', {
              error: err instanceof Error ? err.message : String(err),
            });
            return spec;
          })
        : Promise.resolve(spec ?? null as ObbyVisualSpec | null),
      decorationPrompts.length > 0
        ? generateAndUploadImages(decorationPrompts, 'DecorationProp', 'prop').catch((err) => {
            logger.warn('[Phase G v2] decoration prop image-gen failed', {
              error: err instanceof Error ? err.message : String(err),
            });
            return [] as string[];
          })
        : Promise.resolve([] as string[]),
      deterministicObbyTheme
        ? collectDeterministicObbyApifyReferences(texThemeKey, gamePackageIntentText).catch((err) => {
            logger.warn('[ObbyApifyReference] collection failed', {
              themeKey: texThemeKey,
              error: err instanceof Error ? err.message : String(err),
            });
            return [] as ObbyApifyReferenceTask[];
          })
        : Promise.resolve([] as ObbyApifyReferenceTask[]),
    ]);
    platformTextureUrls = texResults;
    npcImageUrls = npcResults;
    obbyApifyReferenceTasks = apifyReferenceResults;

    if (obbyApifyReferenceTasks.length > 0) {
      (job.metadata as Record<string, unknown>).obbyApifyReferenceTasks = obbyApifyReferenceTasks;
      (job.metadata as Record<string, unknown>).obbyApifyTaskSummary = summarizeObbyApifyTasks(obbyApifyReferenceTasks);
    }

    if (hydratedSpec) {
      (job.metadata as Record<string, unknown>).obbyVisualSpec = hydratedSpec;
      if (propUrls.length > 0) {
        (job.metadata as Record<string, unknown>).obbyDecorationPropImageUrls = propUrls;
      }
      logger.info('[ObbyVisualSpec] attached to job', {
        jobId: job.id, themeName: hydratedSpec.themeName,
        decorationConcepts: hydratedSpec.decorationConcepts.length,
        hydratedTerms: Object.keys(hydratedSpec.liveDecalsByTerm ?? {}).length,
        decorationPropsCount: propUrls.length,
        textureSource: deterministicObbyTheme ? 'deterministic-kit' : 'spec-aware',
        deterministicObbyTheme,
      });
    } else {
      logger.info('[ObbyVisualSpec] no spec — used hardcoded texture prompts', {
        jobId: job.id, textureSource: deterministicObbyTheme ? 'deterministic-kit' : 'fallback', texThemeKey,
      });
    }

    if (platformTextureUrls.length === 0) {
      logger.info('[PlatformTextures] No Roblox uploads — Lua fallback textures will be used');
    }
  }

  const isObbyTrollForReview = subcategoryForTextures === 'obby_troll';
  const shouldReviewObby = target === 'place' && (isObbyForTextures || isObbyTrollForReview);
  const reviewMetadata = job.metadata as Record<string, unknown> | undefined;
  const expectedObbyThemeKey = shouldReviewObby
    ? isObbyTrollForReview
      ? detectObbyTrollExpectedThemeKey(`${latestUserIntent}\n${gameBrief}`, reviewMetadata ?? {})
      : detectObbyThemeKey(gamePackageIntentText)
    : '';
  if (shouldReviewObby) {
    await markStage('quality_review', {
      status: 'processing',
      startedAt: new Date().toISOString(),
      notes: isObbyTrollForReview
        ? [
            'Checking prompt match, Obby Troll runtime facts, trap focus, stage count, checkpoint cadence, and GOTCHA/fair-route evidence.',
          ]
        : [
            'Checking prompt match, route clarity, deterministic theme kit, and Apify reference evidence.',
            ...summarizeObbyApifyTasks(obbyApifyReferenceTasks).slice(0, 4),
          ],
    }, 'Running obby quality review');
  } else {
    await markStage('quality_review', {
      status: 'skipped',
      completedAt: new Date().toISOString(),
      notes: ['Quality review applies to playable obby place generation.'],
    });
  }

  let starterScript: string;
  let additionalScripts: Array<{ name: string; scriptType: string; container: string; source: string }>;
  try {
    const rawScript = buildStarterLuau(job, gameBrief, simulatorSpec, heroAssets, platformTextureUrls, npcImageUrls);
    const resolvedScripts = resolveStarterScript(rawScript);
    starterScript = resolvedScripts.starterScript;
    additionalScripts = resolvedScripts.additionalScripts;
  } catch (err) {
    if (shouldReviewObby && errorMessage(err).includes('ObbyQualityGate failed')) {
      const review: ObbyQualityReviewResult = {
        status: 'rejected',
        score: 10,
        userMessage: 'Quality review stopped this obby before export because the static route/theme gate failed.',
        reasons: errorMessage(err).replace(/^ObbyQualityGate failed:\s*/i, '').split(';').map((item) => item.trim()).filter(Boolean),
        repairActions: [
          'Regenerate the obby with the requested horror theme locked.',
          'Rebuild the first playable route from spawn to stage 1 with route bridge, arrows, connector pads, and readable lamps.',
          'Use neutral lab metal/concrete as the base palette and keep toxic green only as hazard accents.',
          'If the prompt says monster lab, add visible monster/specimen props before export.',
          'Keep Apify results as reference-only until the deterministic route kit passes.',
        ],
        reviewer: 'deterministic',
      };
      const metadataPatch = qualityRejectionMetadata(review, obbyApifyReferenceTasks);
      job.metadata = { ...(job.metadata ?? {}), ...metadataPatch };
      stagedJob = { ...stagedJob, metadata: { ...(stagedJob.metadata ?? {}), ...metadataPatch } };
      await markStage('quality_review', {
        status: 'failed',
        completedAt: new Date().toISOString(),
        errorMessage: review.userMessage,
        notes: [...review.reasons, 'Repair actions:', ...review.repairActions],
      }, `Quality review rejected output: ${review.userMessage}`);
      await markStage('assemble_package', {
        status: 'failed',
        completedAt: new Date().toISOString(),
        errorMessage: 'Stopped before export because quality review rejected the obby.',
        notes: [review.userMessage],
      });
      throw new GenerationQualityRejectError(review.userMessage, metadataPatch, stagedJob.stages);
    }
    throw err;
  }

  if (shouldReviewObby) {
    const fullReviewScript = [
      starterScript,
      ...additionalScripts.map((entry) => `-- AdditionalScript:${entry.container}/${entry.scriptType}/${entry.name}\n${entry.source}`),
    ].join('\n\n');
    const review = await reviewGeneratedObbyPackage({
      brief: gameBrief,
      latestUserIntent,
      title: displayTitle,
      script: fullReviewScript,
      expectedThemeKey: expectedObbyThemeKey,
      visualSpec: (job.metadata as Record<string, unknown> | undefined)?.obbyVisualSpec ?? null,
      apifyTasks: obbyApifyReferenceTasks,
      contentSubcategory: subcategoryForTextures,
      metadata: job.metadata as Record<string, unknown> | undefined,
    });
    const metadataPatch = qualityRejectionMetadata(review, obbyApifyReferenceTasks);
    job.metadata = { ...(job.metadata ?? {}), ...metadataPatch };
    stagedJob = { ...stagedJob, metadata: { ...(stagedJob.metadata ?? {}), ...metadataPatch } };

    if (review.status === 'rejected') {
      await markStage('quality_review', {
        status: 'failed',
        completedAt: new Date().toISOString(),
        errorMessage: review.userMessage,
        notes: [...review.reasons, 'Repair actions:', ...review.repairActions],
      }, `Quality review rejected output: ${review.userMessage}`);
      await markStage('assemble_package', {
        status: 'failed',
        completedAt: new Date().toISOString(),
        errorMessage: 'Stopped before export because quality review rejected the obby.',
        notes: [review.userMessage],
      });
      throw new GenerationQualityRejectError(review.userMessage, metadataPatch, stagedJob.stages);
    }

    await markStage('quality_review', {
      status: 'completed',
      completedAt: new Date().toISOString(),
      notes: [
        `Score ${review.score}/100 — ${review.userMessage}`,
        ...review.reasons.slice(0, 4),
      ],
    }, `Quality review passed: ${review.score}/100`);
  }

  const manifest = buildRobloxManifest({
    title: displayTitle,
    summary: gameBrief.slice(0, 600),
    target,
    prompt: latestUserIntent,
    starterScript,
    additionalScripts,
    metadata: job.metadata,
    sceneSpec,
  });
  const nativeBuild = await maybeBuildRobloxBinary(manifest);
  const bundle = buildProjectBundle(job, gameBrief, starterScript, manifest, nativeBuild);

  // ── Phase 3 complete ──
  await markStage('assemble_package', {
    status: 'completed',
    completedAt: new Date().toISOString(),
  });

  // ── Phase 4: Finalize export (upload artifacts) ──
  await markStage('export_rbxm', {
    status: 'processing',
    startedAt: new Date().toISOString(),
  }, 'Finalizing export');

  const artifacts: GenerationArtifact[] = [];
  artifacts.push(await uploadTextArtifact(job, gameBrief, {
    type: 'gdd',
    extension: 'md',
    mimeType: 'text/markdown',
    name: `${displayTitle}-brief.md`,
    previewText: gameBrief.slice(0, 1500),
    metadata: { role: 'brief' },
  }));
  artifacts.push(await uploadTextArtifact(job, starterScript, {
    type: 'lua',
    extension: 'lua',
    mimeType: 'text/plain',
    name: `${displayTitle}-starter.server.lua`,
    previewText: starterScript.slice(0, 1200),
    inlineCode: true,
    metadata: { role: 'starter_script' },
  }));
  if (nativeBuild?.bufferBase64) {
    artifacts.push(await uploadBinaryArtifact(job, Buffer.from(nativeBuild.bufferBase64, 'base64'), {
      type: nativeBuild.artifactType,
      extension: nativeBuild.artifactType,
      mimeType: 'application/octet-stream',
      name: nativeBuild.fileName,
      previewText: nativeBuild.summary,
      metadata: {
        role: 'native_roblox_binary',
        format: nativeBuild.format,
        validationIssues: nativeBuild.validationIssues,
        notes: nativeBuild.notes,
        manifestSummary: describeManifest(manifest),
      },
    }));
  }
  artifacts.push(await uploadTextArtifact(job, JSON.stringify(bundle, null, 2), {
    type: 'project_bundle',
    extension: 'json',
    mimeType: 'application/json',
    name: `${displayTitle}-project-bundle.json`,
    previewText: typeof bundle.summary === 'string' ? bundle.summary : undefined,
    metadata: {
      role: 'project_bundle',
      files: Array.isArray(bundle.files) ? bundle.files.length : 0,
      exportTarget: 'roblox_studio',
      nativeFormat: preferredArtifactFormat(nativeBuild),
    },
  }));

  // ── Phase 4 complete ──
  await markStage('export_rbxm', {
    status: 'completed',
    completedAt: new Date().toISOString(),
  }, `Exported ${artifacts.length} artifact(s)`);

  // ── Phase 5: Honest scene preview ──
  // Marketing-sensitive game packages must not use a separate image model for
  // preview: it can hallucinate props/materials absent from the RBXL. Render a
  // lightweight PNG from the final sceneSpec, or from the runtime script genre
  // schematic when the script owns the world.
  try {
    const preview = createGamePackagePreviewPng({
      sceneSpec,
      title: displayTitle,
      gameBrief,
      starterScript,
      metadata: job.metadata,
    });
    const scenePreviewArtifact = await uploadBinaryArtifact(job, preview.buffer, {
      type: 'png',
      extension: 'png',
      mimeType: 'image/png',
      name: `${displayTitle}-game-preview.png`,
      previewText: `Deterministic 2D preview rendered from the final Roblox ${preview.genre} package scene.`,
      stageId: 'build_scene',
      artifactRole: 'preview_texture',
      metadata: {
        isPreviewTexture: true,
        role: 'game_package_scene_render',
        honestPreview: true,
        previewRenderSource: preview.source,
        previewGenre: preview.genre,
        previewPartCount: preview.partCount,
      },
    });
    artifacts.push(scenePreviewArtifact);
    logger.info('[GamePackage] honest scene preview artifact attached', {
      jobId: job.id,
      artifactId: scenePreviewArtifact.id,
      source: preview.source,
      genre: preview.genre,
      partCount: preview.partCount,
    });
  } catch (previewErr) {
    logger.warn('[GamePackage] honest scene preview failed (non-critical)', { error: errorMessage(previewErr) });
  }

  return artifacts;
}

function resolveRobloxBuildTarget(job: GenerationJob): 'place' | 'model' {
  if (job.kind === 'rbxm_build') {
    return 'model';
  }
  const projectKind = typeof job.metadata?.projectKind === 'string' ? job.metadata.projectKind : 'game';
  return projectKind === 'content' || projectKind === 'ugc' ? 'model' : 'place';
}

/**
 * Ensure genre-critical functional parts exist in the scene spec.
 * LLM sometimes generates decorations but skips the parts the Lua script depends on.
 */
function ensureGenreRequiredParts(spec: GameSceneSpec, genre: string): GameSceneSpec {
  if (!spec?.parts || !Array.isArray(spec.parts)) return spec;
  const existingNames = spec.parts.map(p => (p.name ?? '').toLowerCase());

  const hasPart = (name: string): boolean =>
    existingNames.some(n => n.includes(name.toLowerCase()));

  type RequiredPart = { name: string; size: [number, number, number]; position: [number, number, number]; color: [number, number, number]; material: string; particles?: GameSceneSpec['parts'][0]['particles'] };

  const genreLower = genre.toLowerCase();

  if (genreLower.includes('tycoon')) {
    const required: RequiredPart[] = [
      { name: 'Dropper', size: [12, 8, 12], position: [0, 8, 0], color: [0.5, 0.5, 0.55], material: 'Metal', particles: { rate: 10, lifetime: 1.5, speed: 3, color: [1, 0.5, 0.1], size: 0.5, spread: 30 } },
      { name: 'Conveyor_1', size: [4, 1, 24], position: [0, 2, -12], color: [0.6, 0.6, 0.65], material: 'Metal' },
      { name: 'Conveyor_2', size: [4, 1, 24], position: [0, 2, -36], color: [0.6, 0.6, 0.65], material: 'Metal' },
      { name: 'Collector', size: [14, 3, 14], position: [0, 1.5, -55], color: [0.3, 0.8, 0.3], material: 'SmoothPlastic', particles: { rate: 8, lifetime: 2, speed: 1, color: [1, 1, 0.5], size: 0.4, spread: 45 } },
      { name: 'Upgrade_1', size: [5, 5, 5], position: [30, 2.5, 0], color: [0.2, 0.9, 0.2], material: 'Neon' },
      { name: 'Upgrade_2', size: [5, 5, 5], position: [30, 2.5, -15], color: [0.2, 0.4, 1], material: 'Neon' },
      { name: 'Upgrade_3', size: [5, 5, 5], position: [30, 2.5, -30], color: [0.7, 0.2, 1], material: 'Neon' },
      { name: 'Button_1', size: [5, 4, 5], position: [-30, 2, 0], color: [1, 0.85, 0.2], material: 'Neon' },
      { name: 'RebirthButton', size: [6, 6, 6], position: [0, 5, 40], color: [1, 0.85, 0.3], material: 'Neon', particles: { rate: 8, lifetime: 2, speed: 1, color: [1, 0.9, 0.3], size: 0.4, spread: 40 } },
      { name: 'Gate_1', size: [2, 12, 20], position: [50, 6, 0], color: [0.4, 0.4, 0.4], material: 'Metal' },
      { name: 'Gate_2', size: [2, 12, 20], position: [-50, 6, 0], color: [0.4, 0.4, 0.4], material: 'Metal' },
    ];
    let injected = 0;
    for (const req of required) {
      if (!hasPart(req.name)) {
        spec.parts.push({ ...req, anchored: true, canCollide: true });
        injected++;
      }
    }
    if (injected > 0) {
      logger.info(`ensureGenreRequiredParts: injected ${injected} missing tycoon parts`);
    }
  }

  if (genreLower.includes('simulator')) {
    const required: RequiredPart[] = [
      { name: 'CollectZone_1', size: [40, 1, 40], position: [0, 0.5, 0], color: [0.4, 0.85, 0.4], material: 'Grass', particles: { rate: 6, lifetime: 2, speed: 1, color: [1, 1, 0.5], size: 0.3, spread: 45 } },
      { name: 'CollectZone_2', size: [30, 1, 30], position: [60, 0.5, 0], color: [0.3, 0.6, 0.9], material: 'Grass', particles: { rate: 6, lifetime: 2, speed: 1, color: [0.5, 0.8, 1], size: 0.3, spread: 40 } },
      { name: 'CollectZone_3', size: [30, 1, 30], position: [120, 0.5, 0], color: [0.7, 0.4, 0.9], material: 'Grass', particles: { rate: 8, lifetime: 2, speed: 1, color: [0.8, 0.5, 1], size: 0.35, spread: 50 } },
      { name: 'SellZone', size: [16, 1, 16], position: [-30, 0.5, 0], color: [1, 0.85, 0.3], material: 'SmoothPlastic', particles: { rate: 8, lifetime: 2, speed: 1, color: [1, 0.9, 0.3], size: 0.4, spread: 40 } },
      { name: 'PowerUp_1', size: [6, 5, 6], position: [-30, 2.5, 30], color: [0.9, 0.3, 0.3], material: 'Neon' },
      { name: 'PowerUp_2', size: [6, 5, 6], position: [-30, 2.5, 45], color: [0.9, 0.5, 0.2], material: 'Neon' },
      { name: 'BagUpgrade', size: [5, 5, 5], position: [-30, 2.5, 60], color: [0.3, 0.5, 1], material: 'Neon' },
      { name: 'EggZone_1', size: [5, 7, 5], position: [0, 3.5, 60], color: [0.95, 0.95, 0.95], material: 'Neon', particles: { rate: 6, lifetime: 2, speed: 0.5, color: [1, 1, 1], size: 0.3, spread: 30 } },
      { name: 'EggZone_2', size: [5, 7, 5], position: [12, 3.5, 60], color: [1, 0.85, 0.3], material: 'Neon', particles: { rate: 6, lifetime: 2, speed: 0.5, color: [1, 0.9, 0.3], size: 0.3, spread: 30 } },
      { name: 'EggZone_3', size: [5, 7, 5], position: [24, 3.5, 60], color: [0.8, 0.4, 1], material: 'Neon', particles: { rate: 6, lifetime: 2, speed: 0.5, color: [0.8, 0.5, 1], size: 0.3, spread: 30 } },
      { name: 'PetArea', size: [30, 0.5, 30], position: [0, 0.2, 90], color: [0.5, 0.8, 0.5], material: 'Grass' },
      { name: 'RebirthButton', size: [8, 8, 8], position: [60, 5, 60], color: [1, 0.85, 0.3], material: 'Neon', particles: { rate: 10, lifetime: 2, speed: 1, color: [1, 0.9, 0.3], size: 0.5, spread: 40 } },
    ];
    let injected = 0;
    for (const req of required) {
      if (!hasPart(req.name)) {
        spec.parts.push({ ...req, anchored: true, canCollide: true });
        injected++;
      }
    }
    if (injected > 0) {
      logger.info(`ensureGenreRequiredParts: injected ${injected} missing simulator parts`);
    }
  }

  if (genreLower.includes('obby') || genreLower.includes('parkour')) {
    const sparkle = { rate: 12, lifetime: 3, speed: 1, color: [1, 1, 0.5] as [number, number, number], size: 0.4, spread: 45 };
    const required: RequiredPart[] = [
      { name: 'Checkpoint_1', size: [16, 2, 16], position: [0, 20, -75], color: [0.2, 0.9, 0.2], material: 'SmoothPlastic', particles: sparkle },
      { name: 'Checkpoint_2', size: [16, 2, 16], position: [0, 45, -150], color: [0.2, 0.9, 0.2], material: 'SmoothPlastic', particles: sparkle },
      { name: 'Kill_1', size: [100, 1, 200], position: [0, -10, -75], color: [1, 0, 0], material: 'Neon' },
      { name: 'WinPlatform', size: [20, 2, 20], position: [0, 70, -250], color: [1, 0.85, 0.3], material: 'Neon', particles: { rate: 15, lifetime: 3, speed: 1.5, color: [1, 1, 0.5] as [number, number, number], size: 0.5, spread: 50 } },
    ];
    let injected = 0;
    for (const req of required) {
      if (!hasPart(req.name)) {
        spec.parts.push({ ...req, anchored: true, canCollide: req.name.startsWith('Kill') ? false : true });
        injected++;
      }
    }
    if (injected > 0) {
      logger.info(`ensureGenreRequiredParts: injected ${injected} missing obby parts`);
    }
  }

  return spec;
}

async function generateSceneFromGDD(
  gameBrief: string,
  metadata?: Record<string, unknown>,
): Promise<GameSceneSpec | null> {
  try {
    const genre = typeof metadata?.genre === 'string' ? metadata.genre : '';
    const briefGenre = gameBrief.toLowerCase().includes('obby') ? 'obby'
      : gameBrief.toLowerCase().includes('tycoon') ? 'tycoon'
      : gameBrief.toLowerCase().includes('simulator') ? 'simulator'
      : '';
    const effectiveGenre = genre || briefGenre || 'adventure';
    const genreHint = `\nThe game genre is: ${effectiveGenre}. Follow the ${effectiveGenre.toUpperCase()} rules above.\n`;

    const prompt: import('./promptCatalog.js').ProviderPromptInput = {
      system: 'You output only valid JSON. No markdown, no code fences, no explanation.',
      user: `${PROMPT_CATALOG.generateSceneJSON}\n${genreHint}\n--- GAME DESIGN DOCUMENT ---\n${gameBrief.slice(0, 3000)}`,
    };

    const result = await runChatProvider('gemini', prompt);
    const text = result.text?.trim();
    if (!text) return null;

    const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
    const spec = JSON.parse(cleaned) as GameSceneSpec;

    if (!Array.isArray(spec.parts) || spec.parts.length === 0) {
      logger.warn('generateSceneFromGDD: empty parts array');
      return null;
    }

    return spec;
  } catch (error) {
    logger.error('generateSceneFromGDD failed', { error: error instanceof Error ? error.message : String(error) });
    return null;
  }
}

async function generateSimulatorSceneSpec(
  gameBrief: string,
): Promise<SimulatorSceneSpec | null> {
  try {
    const prompt: import('./promptCatalog.js').ProviderPromptInput = {
      system: 'You output only valid JSON. No markdown, no code fences, no explanation.',
      user: `${PROMPT_CATALOG.generateSimulatorScene}\n\n--- GAME DESIGN DOCUMENT ---\n${gameBrief.slice(0, 3000)}`,
    };

    const result = await runChatProvider('gemini', prompt);
    const text = result.text?.trim();
    if (!text) return null;

    const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
    const spec = JSON.parse(cleaned) as SimulatorSceneSpec;

    const err = validateSimulatorSpec(spec);
    if (err) {
      logger.warn('generateSimulatorSceneSpec: validation failed', { error: err });
      return null;
    }

    return spec;
  } catch (error) {
    logger.error('generateSimulatorSceneSpec failed', { error: error instanceof Error ? error.message : String(error) });
    return null;
  }
}

function resolveStarterScript(result: string | MultiScriptResult): {
  starterScript: string;
  additionalScripts: Array<{ name: string; scriptType: string; container: string; source: string }>;
} {
  if (typeof result === 'string') return { starterScript: result, additionalScripts: [] };
  return { starterScript: result.serverScript, additionalScripts: result.additionalScripts };
}

function buildStarterLuau(job: GenerationJob, gameBrief: string, simSpec?: SimulatorSceneSpec | null, heroAssets?: HeroAssetResult[], platformTextureUrls?: string[], npcImageUrls?: string[]): string | MultiScriptResult {
  const displayTitle = summarizeGamePackageTitle(job, gameBrief);
  const latestUserIntent = latestUserIntentForJob(job);
  // Master Plan Phase 0+A (session 219): structured Roblox catalog items the
  // generated map embeds as a `rbxthumb://` BillboardGui showcase. Populated
  // by /api/content/generate before the job runs (see fetchTrendingShowcaseItems).
  const rawShowcase = (job.metadata as Record<string, unknown> | undefined)?.trendingShowcaseItems;
  const trendingItems: TrendingShowcaseItem[] | undefined = Array.isArray(rawShowcase)
    ? (rawShowcase as TrendingShowcaseItem[])
    : undefined;
  // Phase D (session 225): live Roblox Decal IDs per brainrot sub-theme,
  // pre-fetched at /api/content/generate time (only for brainrot_sim jobs).
  const rawLiveDecals = (job.metadata as Record<string, unknown> | undefined)?.brainrotLiveDecalsBySubTheme;
  const brainrotLiveDecalsBySubTheme: Record<string, number[]> | undefined =
    rawLiveDecals && typeof rawLiveDecals === 'object'
      ? (rawLiveDecals as Record<string, number[]>)
      : undefined;
  // Phase G (session 230): LLM-generated ObbyVisualSpec stashed on metadata
  // by the obby texture/spec pipeline. Forwarded to buildGameplayScript for
  // obby paths so palette/atmosphere reflects user brief (creepy circus vs
  // generic obby) instead of regex-matching one of 11 hardcoded themes.
  const rawObbyVisualSpec = (job.metadata as Record<string, unknown> | undefined)?.obbyVisualSpec;
  const obbyVisualSpec: ObbyVisualSpec | undefined =
    rawObbyVisualSpec && typeof rawObbyVisualSpec === 'object'
      ? (rawObbyVisualSpec as ObbyVisualSpec)
      : undefined;
  // Phase G v2 (session 233): AI-generated decoration prop image URLs (rbxassetid://).
  // One per decorationConcept. SurfaceGui ImageLabel rendered on prop blocks alongside
  // BillboardGui rbxthumb stickers (variant A from liveDecalsByTerm).
  const rawDecorationProps = (job.metadata as Record<string, unknown> | undefined)?.obbyDecorationPropImageUrls;
  const obbyDecorationPropImageUrls: string[] | undefined =
    Array.isArray(rawDecorationProps) && rawDecorationProps.every((u) => typeof u === 'string')
      ? (rawDecorationProps as string[])
      : undefined;
  // UI/GUI content — generate a UI LocalScript scaffold
  const isUIJob =
    job.metadata?.contentCategory === 'ui' ||
    (job.metadata as Record<string, unknown>)?.contentSubcategory === 'ui' ||
    (job.metadata as Record<string, unknown>)?.intent === 'ui_generation' ||
    (job.metadata as Record<string, unknown>)?.intent === 'ui_interview';

  if (isUIJob) {
    const uiType = typeof job.metadata?.genre === 'string' ? job.metadata.genre : 'hud';
    const visualStyle = typeof job.metadata?.visualStyle === 'string' ? job.metadata.visualStyle : 'modern';
    const systems = Array.isArray(job.metadata?.systems) ? job.metadata.systems as string[] : [];
    const currencyName = systems.find(s => /coin|cash|gold|currency/i.test(s)) ?? 'Coins';
    return buildUIScript({
      title: summarizeTitle(job.prompt),
      uiType,
      visualStyle,
      currencyName,
      dataFields: Array.isArray(job.metadata?.mechanics) ? job.metadata.mechanics as string[] : [],
      summary: (gameBrief + ' ' + (job.prompt || '')).slice(0, 500),
    });
  }

  const rawGenre2 = typeof job.metadata?.genre === 'string' ? job.metadata.genre : '';
  const genericGenres2 = ['game', 'clone', 'content', 'ugc', 'fix', 'analyze'];
  const genre = genericGenres2.includes(rawGenre2.toLowerCase()) ? '' : rawGenre2;
  // HIGHEST PRIORITY: iOS sends user's explicit category selection
  // (`contentSubcategory: 'obby' | 'tycoon' | 'simulator'`). It must override
  // keyword matching on the LLM brief — otherwise a meme obby brief that
  // mentions "tycoon-like income" would be routed to buildTycoonScript.
  const subcategoryForKind = typeof (job.metadata as Record<string, unknown>)?.contentSubcategory === 'string'
    ? ((job.metadata as Record<string, unknown>).contentSubcategory as string).toLowerCase()
    : '';
  const explicitGenre = (subcategoryForKind === 'tycoon' || subcategoryForKind === 'obby' || subcategoryForKind === 'simulator')
    ? subcategoryForKind
    : '';
  const briefAndPrompt = `${gameBrief} ${latestUserIntent}`.toLowerCase();
  const hasObbyShop = job.metadata?.hasObbyShop === true || job.metadata?.hasObbyShop === 'true';
  const keywordGenre = explicitGenre ||
    ((briefAndPrompt.includes('tycoon') || briefAndPrompt.includes('тайкун') || briefAndPrompt.includes('фабрик') || briefAndPrompt.includes('завод') || briefAndPrompt.includes('factory') || briefAndPrompt.includes('магнат') ? 'tycoon' : '')
    || (briefAndPrompt.includes('obby') || briefAndPrompt.includes('parkour') || briefAndPrompt.includes('obstacle') || briefAndPrompt.includes('обби') || briefAndPrompt.includes('паркур') ? 'obby' : '')
    || (briefAndPrompt.includes('simulator') || briefAndPrompt.includes('симулятор') || briefAndPrompt.includes('pet sim') || briefAndPrompt.includes('collect') || briefAndPrompt.includes('clicker') || briefAndPrompt.includes('питомц') || briefAndPrompt.includes('кликер') ? 'simulator' : '')
    || '');
  const detectedGenre = keywordGenre || genre || '';

  // Session #149: brainrot_sim Steal-a-Brainrot conveyor — parse the JSON GDD
  // produced by generateBrainrotSimGdd and forward to buildBrainrotConveyorScript.
  // Falls back to default pool if LLM JSON is malformed.
  if (subcategoryForKind === 'brainrot_sim') {
    let parsedGdd: Record<string, unknown> = {};
    try {
      const cleaned = gameBrief.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
      const firstBrace = cleaned.indexOf('{');
      const lastBrace = cleaned.lastIndexOf('}');
      if (firstBrace !== -1 && lastBrace > firstBrace) {
        parsedGdd = JSON.parse(cleaned.slice(firstBrace, lastBrace + 1)) as Record<string, unknown>;
      }
    } catch (e) {
      logger.warn('brainrot_sim: GDD JSON parse failed, using defaults', { jobId: job.id, error: e instanceof Error ? e.message : String(e) });
    }
    const memeSubTheme = (typeof parsedGdd.memeSubTheme === 'string' ? parsedGdd.memeSubTheme : 'generic') as 'skibidi' | 'bombardir' | 'tralalero' | 'sigma' | 'generic';
    const rarityTiers = (parsedGdd.rarityTiers === 3 || parsedGdd.rarityTiers === 5 || parsedGdd.rarityTiers === 7) ? parsedGdd.rarityTiers : 5;
    const baseCpsScale = (parsedGdd.baseCpsScale === 'low' || parsedGdd.baseCpsScale === 'whale' ? parsedGdd.baseCpsScale : 'balanced') as 'low' | 'balanced' | 'whale';
    const stealingEnabled = parsedGdd.stealingEnabled !== false;
    const basePlotCount = typeof parsedGdd.basePlotCount === 'number' ? parsedGdd.basePlotCount : 8;
    const brainrotPool = Array.isArray(parsedGdd.brainrotPool) ? (parsedGdd.brainrotPool as Array<Record<string, unknown>>).map((e) => ({
      name: typeof e?.name === 'string' ? e.name : 'Brainrot',
      memeSubTheme: (typeof e?.memeSubTheme === 'string' ? e.memeSubTheme : memeSubTheme) as 'skibidi' | 'bombardir' | 'tralalero' | 'sigma' | 'generic',
      rarity: (typeof e?.rarity === 'string' ? e.rarity : 'common') as 'common' | 'rare' | 'legendary' | 'mythic' | 'secret' | 'brainrot' | 'galactic',
      baseCps: typeof e?.baseCps === 'number' ? e.baseCps : 1,
      priceCash: typeof e?.priceCash === 'number' ? e.priceCash : 100,
      spawnWeight: typeof e?.spawnWeight === 'number' ? e.spawnWeight : 25,
      primaryColor: (Array.isArray(e?.primaryColor) ? e.primaryColor : [200, 200, 200]) as [number, number, number],
      accentColor: (Array.isArray(e?.accentColor) ? e.accentColor : [120, 120, 120]) as [number, number, number],
    })) : undefined;
    const titleFromGdd = typeof parsedGdd.title === 'string' && parsedGdd.title.trim() ? parsedGdd.title : displayTitle;
    return buildGameplayScript({
      title: titleFromGdd,
      genre: 'simulator',
      gameKind: 'brainrot_sim',
      systems: ['conveyor', 'plot', 'cps', 'leaderboard', 'rebirth', ...(stealingEnabled ? ['steal', 'slap'] : [])],
      summary: typeof parsedGdd.summary === 'string' ? parsedGdd.summary.slice(0, 300) : gameBrief.slice(0, 300),
      memeSubTheme,
      brainrotPool,
      rarityTiers,
      baseCpsScale,
      stealingEnabled,
      basePlotCount,
      platformTextureUrls,
      npcImageUrls,
      heroAssets: heroAssets ?? [],
      trendingItems,
      brainrotLiveDecalsBySubTheme,
      jobId: job.id,
    });
  }

  // Session #175: obby_troll Trap Maker — parse the JSON GDD produced by
  // generateObbyTrollGdd and forward to buildTrollObbyScript. The runtime
  // Lua owns the layout; if GDD JSON is malformed we still get a playable
  // map because buildTrollObbyScript synthesises traps from savagery alone.
  if (subcategoryForKind === 'obby_troll') {
    let parsedGdd: Record<string, unknown> = {};
    try {
      const cleaned = gameBrief.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
      const firstBrace = cleaned.indexOf('{');
      const lastBrace = cleaned.lastIndexOf('}');
      if (firstBrace !== -1 && lastBrace > firstBrace) {
        parsedGdd = JSON.parse(cleaned.slice(firstBrace, lastBrace + 1)) as Record<string, unknown>;
      }
    } catch (e) {
      logger.warn('obby_troll: GDD JSON parse failed, using defaults', { jobId: job.id, error: e instanceof Error ? e.message : String(e) });
    }
    const allowedTrapTypes = new Set<TrollObbyTrapType>(TROLL_OBBY_TRAP_TYPES);
    const metadataRecord = job.metadata && typeof job.metadata === 'object' ? job.metadata as Record<string, unknown> : {};
    const trapFocusCueText = [
      job.prompt,
      metadataRecord.latestUserInput,
      metadataRecord.latestUserIntent,
      metadataRecord.userIntent,
      metadataRecord.requestedChangePrompt,
      metadataRecord.title,
    ].filter((value): value is string => typeof value === 'string' && value.trim().length > 0).join('\n');
    const authoritativeIntentText = trapFocusCueText || `${latestUserIntent}\n${job.prompt}\n${gameBrief}`;
    const briefExpectations = detectObbyTrollBriefExpectations(authoritativeIntentText, metadataRecord);
    const expectedThemeFromBrief = detectObbyTrollExpectedThemeKey(authoritativeIntentText, metadataRecord);
    const allowedThemes = new Set(['default', 'meme', 'candy', 'horror', 'hospital_horror', 'school_horror', 'lab_horror', 'slime_horror', 'space', 'nature', 'lava', 'medieval', 'neon']);
    const gddThemeKey = (typeof parsedGdd.themeKey === 'string' && allowedThemes.has(parsedGdd.themeKey)) ? parsedGdd.themeKey : 'default';
    const themeKey = expectedThemeFromBrief !== 'default' ? expectedThemeFromBrief : gddThemeKey;
    const gddSavagery = (parsedGdd.savagery === 'lite' || parsedGdd.savagery === 'savage' || parsedGdd.savagery === 'medium') ? parsedGdd.savagery : 'medium';
    const savagery = briefExpectations.requestedSavagery ?? gddSavagery;
    const gddTotalLevels = (parsedGdd.totalLevels === 10 || parsedGdd.totalLevels === 15 || parsedGdd.totalLevels === 20 || parsedGdd.totalLevels === 25)
      ? parsedGdd.totalLevels
      : 15;
    const totalLevels = briefExpectations.requestedLevels ?? gddTotalLevels;
    const gddCheckpointEvery = (parsedGdd.checkpointEvery === 2 || parsedGdd.checkpointEvery === 3 || parsedGdd.checkpointEvery === 5)
      ? parsedGdd.checkpointEvery
      : 3;
    const checkpointEvery = briefExpectations.requestedCheckpointEvery ?? gddCheckpointEvery;
    if (themeKey !== gddThemeKey || savagery !== gddSavagery || totalLevels !== gddTotalLevels || checkpointEvery !== gddCheckpointEvery) {
      logger.warn('obby_troll: overriding GDD fields from clean user brief', {
        jobId: job.id,
        gddThemeKey,
        themeKey,
        gddSavagery,
        savagery,
        gddTotalLevels,
        totalLevels,
        gddCheckpointEvery,
        checkpointEvery,
        cleanIntent: briefExpectations.intentText.slice(0, 180),
      });
    }
    const trapFocusFromText = briefExpectations.focusedTrapTypes;
    const trapFocusFromWeights = (() => {
      const weights = parsedGdd.trapWeights;
      if (!weights || typeof weights !== 'object' || Array.isArray(weights)) return [] as TrollObbyTrapType[];
      const weighted = Object.entries(weights as Record<string, unknown>)
        .flatMap(([type, value]) => {
          if (!allowedTrapTypes.has(type as TrollObbyTrapType) || typeof value !== 'number' || !Number.isFinite(value)) return [];
          return [{ type: type as TrollObbyTrapType, value }];
        })
        .sort((a, b) => b.value - a.value);
      if (weighted.length === 0) return [] as TrollObbyTrapType[];
      const [top, second] = weighted;
      if (top.value >= 65 && top.value >= ((second?.value ?? 0) + 25)) return [top.type];
      const focused = weighted.filter((entry) => entry.value >= 35).map((entry) => entry.type);
      return focused.length > 0 && focused.length < allowedTrapTypes.size ? focused : [];
    })();
    const trapFocusTypes = trapFocusFromText.length > 0 ? trapFocusFromText : trapFocusFromWeights;
    if (trapFocusTypes.length > 0) {
      logger.info('obby_troll: applying focused trap preference', { jobId: job.id, trapFocusTypes });
    }
    const trolls = Array.isArray(parsedGdd.trolls)
      ? (parsedGdd.trolls as Array<Record<string, unknown>>).flatMap((t) => {
          if (!t || typeof t !== 'object') return [];
          const lvl = typeof t.level === 'number' ? Math.floor(t.level) : NaN;
          const ty = typeof t.type === 'string' ? t.type : '';
          if (!Number.isFinite(lvl) || !allowedTrapTypes.has(ty as TrollObbyTrapType)) return [];
          const intensityRaw = typeof t.intensity === 'string' ? t.intensity : 'medium';
          const intensity = (intensityRaw === 'soft' || intensityRaw === 'hard') ? intensityRaw : 'medium';
          return [{ level: lvl, type: ty as TrollObbyTrapType, intensity: intensity as 'soft' | 'medium' | 'hard' }];
        })
      : [];
    const signatureGotchaText = typeof parsedGdd.signatureGotchaText === 'string' && parsedGdd.signatureGotchaText.trim()
      ? parsedGdd.signatureGotchaText.slice(0, 24)
      : '💀 GOTCHA';
    const titleFromGdd = typeof parsedGdd.title === 'string' && parsedGdd.title.trim() ? parsedGdd.title : displayTitle;
    return buildGameplayScript({
      title: titleFromGdd,
      genre: 'obby',
      gameKind: 'obby_troll',
      systems: ['troll_obby', 'leaderstats', 'gotcha_ui'],
      summary: typeof parsedGdd.summary === 'string' ? parsedGdd.summary.slice(0, 300) : gameBrief.slice(0, 300),
      obbyThemeKey: themeKey,
      totalLevels: totalLevels as number,
      checkpointEvery: checkpointEvery as number,
      savagery: savagery as 'lite' | 'medium' | 'savage',
      signatureGotchaText,
      trolls,
      trollTrapFocus: trapFocusTypes,
      platformTextureUrls,
      npcImageUrls,
      heroAssets: heroAssets ?? [],
      trendingItems,
      obbyVisualSpec,
      obbyDecorationPropImageUrls,
      jobId: job.id,
    });
  }

  if (subcategoryForKind === 'rpg') {
    const parsedGdd = parsePlayableGddJson(gameBrief, 'rpg_adventure', job.id);
    const titleFromGdd = gddString(parsedGdd, 'title', displayTitle);
    return buildGameplayScript({
      title: titleFromGdd,
      genre: 'rpg',
      gameKind: 'rpg_adventure',
      systems: ['quests', 'classes', 'enemy_camps', 'loot', 'boss', 'leaderstats', 'datastore'],
      summary: gddString(parsedGdd, 'summary', gameBrief.slice(0, 300), 300),
      themeKey: gddString(parsedGdd, 'themeKey', 'fantasy'),
      playerClass: gddEnum(parsedGdd, 'playerClass', ['warrior', 'mage', 'archer'] as const, 'warrior'),
      questCount: gddInt(parsedGdd, 'questCount', 3, 3, 5),
      enemyFamily: gddString(parsedGdd, 'enemyFamily', 'Slimes'),
      bossName: gddString(parsedGdd, 'bossName', 'Ancient Guardian'),
      lootTheme: gddString(parsedGdd, 'lootTheme', 'Gold'),
      heroAssets: heroAssets ?? [],
      trendingItems,
      jobId: job.id,
    });
  }

  if (subcategoryForKind === 'horror') {
    const parsedGdd = parsePlayableGddJson(gameBrief, 'horror_escape', job.id);
    const titleFromGdd = gddString(parsedGdd, 'title', displayTitle);
    return buildGameplayScript({
      title: titleFromGdd,
      genre: 'horror',
      gameKind: 'horror_escape',
      systems: ['flashlight', 'keys', 'locked_doors', 'escape', 'monster_pathfinding', 'jumpscare_ui', 'leaderstats'],
      summary: gddString(parsedGdd, 'summary', gameBrief.slice(0, 300), 300),
      settingKey: gddString(parsedGdd, 'settingKey', 'abandoned_school'),
      monsterName: gddString(parsedGdd, 'monsterName', 'The Watcher'),
      keyCount: gddInt(parsedGdd, 'keyCount', 3, 3, 5),
      doorCount: gddInt(parsedGdd, 'doorCount', 3, 2, 5),
      scareIntensity: gddEnum(parsedGdd, 'scareIntensity', ['soft', 'medium', 'intense'] as const, 'medium'),
      heroAssets: heroAssets ?? [],
      trendingItems,
      jobId: job.id,
    });
  }

  if (subcategoryForKind === 'pvp' || subcategoryForKind === 'pvp_arena') {
    const parsedGdd = parsePlayableGddJson(gameBrief, 'pvp_arena', job.id);
    const titleFromGdd = gddString(parsedGdd, 'title', displayTitle);
    return buildGameplayScript({
      title: titleFromGdd,
      genre: 'pvp arena',
      gameKind: 'pvp_arena',
      systems: ['round_manager', 'server_damage', 'spawn_rotation', 'leaderstats', 'scoreboard_hud'],
      summary: gddString(parsedGdd, 'summary', gameBrief.slice(0, 300), 300),
      arenaTheme: gddString(parsedGdd, 'arenaTheme', 'neon_ruins'),
      mode: gddEnum(parsedGdd, 'mode', ['ffa', 'teams'] as const, 'ffa'),
      weaponSet: gddEnum(parsedGdd, 'weaponSet', ['sword_bow', 'sword_blaster', 'magic'] as const, 'sword_bow'),
      roundSeconds: gddInt(parsedGdd, 'roundSeconds', 180, 120, 300),
      spawnCount: gddInt(parsedGdd, 'spawnCount', 8, 8, 12),
      heroAssets: heroAssets ?? [],
      trendingItems,
      jobId: job.id,
    });
  }

  if (subcategoryForKind === 'simulator') {
    const parsedGdd = parsePlayableGddJson(gameBrief, 'simulator_variant', job.id);
    const simKindFallback: 'pet' | 'mining' | 'fighting' | 'muscle' | 'clicker' = briefAndPrompt.includes('mining') || briefAndPrompt.includes('mine') ? 'mining'
      : briefAndPrompt.includes('fighting') || briefAndPrompt.includes('fight') || briefAndPrompt.includes('boss') ? 'fighting'
      : briefAndPrompt.includes('muscle') || briefAndPrompt.includes('lift') ? 'muscle'
      : briefAndPrompt.includes('clicker') || briefAndPrompt.includes('click') ? 'clicker'
      : 'pet';
    const simulatorKind = gddEnum(parsedGdd, 'simulatorKind', ['pet', 'mining', 'fighting', 'muscle', 'clicker'] as const, simKindFallback);
    const titleFromGdd = gddString(parsedGdd, 'title', displayTitle);
    if (TRAINING_SIMULATOR_KINDS.has(simulatorKind)) {
      return buildGameplayScript({
        title: titleFromGdd,
        genre: 'simulator',
        gameKind: `${simulatorKind}_sim`,
        systems: ['train', 'collect', 'sell', 'upgrades', 'rebirth', 'leaderstats', 'datastore'],
        summary: gddString(parsedGdd, 'summary', gameBrief.slice(0, 300), 300),
        simulatorKind,
        currencyName: gddString(parsedGdd, 'currencyName', simulatorKind === 'mining' ? 'Ore' : 'Coins'),
        zoneTheme: gddString(parsedGdd, 'zoneTheme', 'training_islands'),
        rebirthPace: gddEnum(parsedGdd, 'rebirthPace', ['slow', 'balanced', 'fast'] as const, 'balanced'),
        heroAssets: heroAssets ?? [],
        trendingItems,
        jobId: job.id,
      });
    }
    return buildGameplayScript({
      title: titleFromGdd,
      genre: 'simulator',
      gameKind: 'simulator',
      systems: ['pets', 'currency', 'eggs', 'rebirth', 'leaderstats'],
      summary: gddString(parsedGdd, 'summary', gameBrief.slice(0, 300), 300),
      simulatorKind: 'pet',
      currencyName: gddString(parsedGdd, 'currencyName', 'Coins'),
      simulatorSpec: simSpec || undefined,
      platformTextureUrls,
      npcImageUrls,
      heroAssets: heroAssets ?? [],
      trendingItems,
      jobId: job.id,
    });
  }

  return buildGameplayScript({
    title: displayTitle,
    genre: detectedGenre,
    systems: Array.isArray(job.metadata?.systems) ? job.metadata.systems as string[] : [],
    summary: gameBrief.slice(0, 1600),
    simulatorSpec: simSpec || undefined,
    platformTextureUrls,
    npcImageUrls,
    heroAssets: heroAssets ?? [],
    hasObbyShop,
    obbyDescription: buildGamePackageResultMetadata(job, gameBrief).obbyDescription,
    trendingItems,
    obbyVisualSpec,
    obbyDecorationPropImageUrls,
    jobId: job.id, // Session #073: unique seed per generation for obby variety
  });
}

function buildProjectBundle(
  job: GenerationJob,
  gameBrief: string,
  starterScript: string,
  manifest: RobloxBuildManifest,
  nativeBuild: RobloxBuildResult | null,
): {
  version: number;
  title: string;
  projectKind: string;
  provider: AIProvider;
  summary: string;
  exportNotes: string[];
  files: Array<Record<string, unknown>>;
  metadata: Record<string, unknown>;
} {
  return {
    version: 1,
    title: summarizeTitle(job.prompt),
    projectKind: job.kind,
    provider: job.provider,
    summary: gameBrief.slice(0, 600),
    exportNotes: [
      'Import the Lua script into Roblox Studio as a Script or ModuleScript.',
      'Use the brief as your production checklist for zones, UI, monetization, and retention.',
      nativeBuild?.bufferBase64
        ? `Native ${nativeBuild.artifactType} binary was also generated by the worker path.`
        : 'Treat this bundle as the source-of-truth until a native rbxl/rbxm worker is configured.',
    ],
    files: [
      {
        path: 'docs/game-brief.md',
        kind: 'gdd',
      },
      {
        path: 'src/server/starter.server.lua',
        kind: 'lua',
        preview: starterScript.slice(0, 180),
      },
      {
        path: `build/${manifest.target === 'place' ? 'game.rbxl' : 'model.rbxm'}`,
        kind: manifest.target === 'place' ? 'rbxl' : 'rbxm',
        preview: nativeBuild?.summary ?? 'Binary worker not configured for this build.',
      },
    ],
    metadata: {
      ...(job.metadata ?? {}) as Record<string, unknown>,
      manifest,
      nativeBuild: nativeBuild
        ? {
          artifactType: nativeBuild.artifactType,
          format: nativeBuild.format,
          summary: nativeBuild.summary,
          validationIssues: nativeBuild.validationIssues,
          notes: nativeBuild.notes,
        }
        : undefined,
    },
  };
}

function deepgramPayload(job: GenerationJob): Record<string, unknown> | undefined {
  if (job.kind !== 'transcription' && job.kind !== 'voice_stream_finalize') {
    return undefined;
  }
  const audioUrl = typeof job.metadata?.audioUrl === 'string' && job.metadata.audioUrl.trim()
    ? job.metadata.audioUrl : undefined;
  const audioBase64 = typeof job.metadata?.audioBase64 === 'string' && (job.metadata.audioBase64 as string).trim()
    ? job.metadata.audioBase64 as string : undefined;
  if (!audioUrl && !audioBase64) {
    logger.error('Deepgram: no audioUrl or audioBase64 available for transcription');
    return undefined;
  }
  const rawMime = typeof job.metadata?.audioMimeType === 'string' ? job.metadata.audioMimeType : 'audio/mp4';
  const mimeType = rawMime === 'audio/m4a' ? 'audio/mp4' : rawMime;
  const localeHint = typeof job.metadata?.language === 'string' ? job.metadata.language : undefined;
  const language = mapLocaleToDeepgramLanguage(localeHint);
  const payload: Record<string, unknown> = {
    ...(audioBase64 ? { audioBase64, audioMimeType: mimeType } : {}),
    ...(!audioBase64 && audioUrl ? { url: audioUrl } : {}),
    smart_format: true,
    punctuate: true,
    model: 'nova-2',
  };
  if (language) {
    payload.language = language;
  } else {
    payload.detect_language = true;
  }
  return payload;
}

function mapLocaleToDeepgramLanguage(locale?: string): string | undefined {
  if (!locale) return undefined;
  const lower = locale.toLowerCase().replace(/_/g, '-');
  const primary = lower.split('-')[0];
  const supported: Record<string, string> = {
    ru: 'ru',
    en: 'en',
    es: 'es',
    fr: 'fr',
    de: 'de',
    it: 'it',
    pt: 'pt',
    ja: 'ja',
    ko: 'ko',
    zh: 'zh',
    uk: 'uk',
    pl: 'pl',
    nl: 'nl',
    tr: 'tr',
    hi: 'hi',
    sv: 'sv',
    da: 'da',
    no: 'no',
    fi: 'fi',
    cs: 'cs',
  };
  return supported[primary];
}

async function moderateArtifacts(job: GenerationJob, artifacts: GenerationArtifact[]): Promise<ModerationCheckResponse> {
  const isGameBuild = job.kind === 'game_package' || job.kind === 'rbxl_build' || job.kind === 'rbxm_build';
  const textArtifacts = artifacts.filter((artifact) =>
    artifact.type === 'lua' ||
    artifact.type === 'text' ||
    artifact.type === 'gdd' ||
    artifact.type === 'project_bundle' ||
    artifact.type === 'json',
  );
  for (const artifact of textArtifacts) {
    const text = artifact.code ?? artifact.content ?? artifact.previewText;
    if (!text) {
      continue;
    }
    const moderation = await runModerationPipeline({
      userId: job.userId,
      text,
      stage: 'artifact',
      artifactType: artifact.type,
      // Propagate job metadata (projectKind, contentSubcategory, genre) so the
      // pipeline's supported-genre bypass can trust iOS's explicit category selection
      // (obby/tycoon/simulator) instead of delegating meme-brief classification to Gemini.
      metadata: {
        ...(job.metadata as Record<string, unknown> ?? {}),
        artifactId: artifact.id,
        jobId: job.id,
      },
    });
    if (!moderation.allowed) {
      return moderation;
    }
    // For game builds we skip the review-severity bucket of moderateLuaSource:
    // tycoon/obby scripts legitimately use DataStoreService, MarketplaceService,
    // TeleportService, FireServer — those are review signals for regular user
    // code, but for our templated game builds they're expected and would force
    // every generation into awaiting_review → "did not finish successfully".
    // We still run moderateLuaSource to catch *blocked* signals (loadstring,
    // getfenv/setfenv, HttpGet, untrusted require) — those stay blocked.
    if (artifact.type === 'lua') {
      const scriptModeration = moderateLuaSource(text);
      if (scriptModeration) {
        if (isGameBuild && scriptModeration.action === 'review') {
          continue; // accept review severity for game builds
        }
        return scriptModeration;
      }
    }
  }

  const binaryArtifacts = artifacts.filter((artifact) => artifact.type === 'rbxl' || artifact.type === 'rbxm');
  if (binaryArtifacts.length > 0) {
    // Game build jobs (game_package / rbxl_build / rbxm_build) already go through
    // prompt moderation + lua-script scan earlier in the pipeline. The legacy
    // "manual QA before publication" gate was forcing every successful game
    // generation into awaiting_review status, which the iOS client renders as
    // "did not finish successfully". Auto-complete these kinds.
    if (isGameBuild) {
      return {
        allowed: true,
        provider: 'artifact-scan',
        severity: 'safe',
        action: 'allow',
      };
    }
    return {
      allowed: true,
      provider: 'artifact-scan',
      severity: 'review',
      action: 'review',
      reason: 'Native Roblox binaries should pass manual QA before publication.',
      category: 'publication',
      flags: binaryArtifacts.map((artifact) => artifact.type),
    };
  }

  return {
    allowed: true,
    provider: 'artifact-scan',
    severity: 'safe',
    action: 'allow',
  };
}

const ARTIFACT_STORAGE_TIMEOUT_MS = 45_000;
const ARTIFACT_METADATA_TIMEOUT_MS = 15_000;

async function withOperationTimeout<T>(
  operation: Promise<T>,
  timeoutMs: number,
  label: string,
): Promise<T> {
  let timer: ReturnType<typeof setTimeout> | undefined;
  const timeout = new Promise<never>((_, reject) => {
    timer = setTimeout(() => reject(new Error(`${label} timed out after ${Math.round(timeoutMs / 1000)}s`)), timeoutMs);
  });
  try {
    return await Promise.race([operation, timeout]);
  } finally {
    if (timer) clearTimeout(timer);
  }
}

async function uploadTextArtifact(
  job: GenerationJob,
  text: string,
  descriptor: {
    type: ArtifactType;
    extension: string;
    mimeType: string;
    name: string;
    previewText?: string;
    metadata?: Record<string, unknown>;
    inlineCode?: boolean;
    stageId?: GenerationStageId;
    artifactRole?: GenerationArtifactRole;
  },
): Promise<GenerationArtifact> {
  const MAX_FIRESTORE_TEXT_ARTIFACT_BYTES = 200_000;
  const artifactId = uuidv4();
  const filePath = `artifacts/${job.userId}/${artifactId}.${descriptor.extension}`;
  let downloadUrl: string | undefined;
  const textBytes = Buffer.byteLength(text, 'utf8');
  const shouldStoreFirestorePayload = textBytes <= MAX_FIRESTORE_TEXT_ARTIFACT_BYTES;

  try {
    const activeBucket = await resolvedBucket();
    const file = activeBucket.file(filePath);
    await withOperationTimeout(
      file.save(text, {
        contentType: descriptor.mimeType,
        resumable: false,
      }),
      ARTIFACT_STORAGE_TIMEOUT_MS,
      `Storage text upload ${descriptor.name}`,
    );
    [downloadUrl] = await withOperationTimeout(
      file.getSignedUrl({
        action: 'read',
        expires: Date.now() + 7 * 24 * 60 * 60 * 1000,
      }),
      ARTIFACT_METADATA_TIMEOUT_MS,
      `Signed URL for ${descriptor.name}`,
    );
  } catch (error) {
    logger.warn('Storage upload failed, returning inline artifact only', error);
  }

  const artifact: GenerationArtifact = {
    id: artifactId,
    type: descriptor.type,
    name: descriptor.name,
    url: downloadUrl,
    downloadUrl,
    code: descriptor.inlineCode && shouldStoreFirestorePayload ? text : undefined,
    content: !descriptor.inlineCode && shouldStoreFirestorePayload ? text : undefined,
    previewText: descriptor.previewText ?? text.slice(0, 800),
    extension: descriptor.extension,
    mimeType: descriptor.mimeType,
    stageId: descriptor.stageId,
    artifactRole: descriptor.artifactRole,
    storagePath: downloadUrl ? filePath : undefined,
    metadata: {
      ...(descriptor.metadata ?? {}),
      ...(shouldStoreFirestorePayload ? {} : { contentStoredInStorageOnly: true, contentBytes: textBytes }),
    },
  };

  try {
    await withOperationTimeout(
      db.collection('artifacts').doc(artifactId).set({
        ...artifact,
        userId: job.userId,
        jobId: job.id,
        downloadUrl,
        createdAt: new Date().toISOString(),
      }),
      ARTIFACT_METADATA_TIMEOUT_MS,
      `Artifact metadata write ${artifactId}`,
    );
  } catch (error) {
    logger.warn('Artifact metadata write failed; artifact remains attached to job result', { artifactId, error: errorMessage(error) });
  }

  return artifact;
}

async function uploadBinaryArtifact(
  job: GenerationJob,
  bytes: Buffer,
  descriptor: {
    type: ArtifactType;
    extension: string;
    mimeType: string;
    name: string;
    previewText?: string;
    metadata?: Record<string, unknown>;
    stageId?: GenerationStageId;
    artifactRole?: GenerationArtifactRole;
  },
): Promise<GenerationArtifact> {
  const artifactId = uuidv4();
  const filePath = `artifacts/${job.userId}/${artifactId}.${descriptor.extension}`;
  let downloadUrl: string | undefined;

  try {
    const activeBucket = await resolvedBucket();
    const file = activeBucket.file(filePath);
    await withOperationTimeout(
      file.save(bytes, {
        contentType: descriptor.mimeType,
        resumable: false,
      }),
      ARTIFACT_STORAGE_TIMEOUT_MS,
      `Storage binary upload ${descriptor.name}`,
    );
    [downloadUrl] = await withOperationTimeout(
      file.getSignedUrl({
        action: 'read',
        expires: Date.now() + 7 * 24 * 60 * 60 * 1000,
      }),
      ARTIFACT_METADATA_TIMEOUT_MS,
      `Signed URL for ${descriptor.name}`,
    );
  } catch (error) {
    logger.warn('Binary storage upload failed, returning metadata-only artifact', error);
  }

  const artifact: GenerationArtifact = {
    id: artifactId,
    type: descriptor.type,
    name: descriptor.name,
    url: downloadUrl,
    downloadUrl,
    previewText: descriptor.previewText,
    extension: descriptor.extension,
    mimeType: descriptor.mimeType,
    stageId: descriptor.stageId,
    artifactRole: descriptor.artifactRole,
    storagePath: downloadUrl ? filePath : undefined,
    metadata: descriptor.metadata,
  };
  try {
    await withOperationTimeout(
      db.collection('artifacts').doc(artifactId).set({
        ...artifact,
        userId: job.userId,
        jobId: job.id,
        downloadUrl,
        createdAt: new Date().toISOString(),
      }),
      ARTIFACT_METADATA_TIMEOUT_MS,
      `Artifact metadata write ${artifactId}`,
    );
  } catch (error) {
    logger.warn('Artifact metadata write failed; artifact remains attached to job result', { artifactId, error: errorMessage(error) });
  }
  return artifact;
}

function normalizeArtifactMimeType(mimeType?: string): string {
  const normalized = (mimeType ?? '').split(';')[0].trim().toLowerCase();
  if (!normalized) return '';
  if (normalized === 'image/jpg') return 'image/jpeg';
  if (normalized === 'audio/mp3') return 'audio/mpeg';
  if (normalized === 'audio/x-wav' || normalized === 'audio/wave' || normalized === 'audio/x-pn-wav') return 'audio/wav';
  return normalized;
}

function isGenericArtifactMimeType(mimeType: string): boolean {
  return !mimeType || mimeType === 'application/octet-stream' || mimeType === 'binary/octet-stream';
}

function extensionFromSourceUrl(sourceUrl: string): string | undefined {
  const rawPath = (() => {
    try {
      return new URL(sourceUrl).pathname;
    } catch {
      return sourceUrl.split('?')[0] ?? sourceUrl;
    }
  })();
  const match = rawPath.toLowerCase().match(/\.([a-z0-9]+)$/);
  if (!match) return undefined;
  const ext = match[1];
  return ext === 'jpeg' ? 'jpg' : ext;
}

function extensionForGeneratedMimeType(mimeType: string): string | undefined {
  if (mimeType === 'image/png') return 'png';
  if (mimeType === 'image/jpeg') return 'jpg';
  if (mimeType === 'image/gif') return 'gif';
  if (mimeType === 'audio/ogg' || mimeType === 'application/ogg') return 'ogg';
  if (mimeType === 'audio/mpeg') return 'mp3';
  if (mimeType === 'audio/wav') return 'wav';
  if (mimeType === 'audio/flac') return 'flac';
  if (mimeType === 'audio/mp4' || mimeType === 'audio/m4a' || mimeType === 'audio/x-m4a') return 'm4a';
  if (mimeType === 'audio/aac') return 'aac';
  if (mimeType === 'video/mp4') return 'mp4';
  if (mimeType === 'model/gltf-binary') return 'glb';
  if (mimeType === 'model/obj' || mimeType === 'text/plain+obj') return 'obj';
  if (mimeType.includes('fbx')) return 'fbx';
  return undefined;
}

function mimeTypeForGeneratedExtension(extension: string): string | undefined {
  switch (extension) {
    case 'png': return 'image/png';
    case 'jpg': return 'image/jpeg';
    case 'gif': return 'image/gif';
    case 'ogg': return 'audio/ogg';
    case 'mp3': return 'audio/mpeg';
    case 'wav': return 'audio/wav';
    case 'flac': return 'audio/flac';
    case 'm4a': return 'audio/mp4';
    case 'aac': return 'audio/aac';
    case 'mp4': return 'video/mp4';
    case 'glb': return 'model/gltf-binary';
    case 'obj': return 'model/obj';
    case 'fbx': return 'application/octet-stream';
    default: return undefined;
  }
}

function resolveGeneratedArtifactFormat(sourceUrl: string, requestedMimeType?: string, responseMimeType?: string): { extension: string; mimeType: string } {
  const requested = normalizeArtifactMimeType(requestedMimeType);
  const response = normalizeArtifactMimeType(responseMimeType);
  const urlExtension = extensionFromSourceUrl(sourceUrl);

  let mimeType = 'application/octet-stream';
  if (!isGenericArtifactMimeType(requested)) {
    mimeType = requested;
  } else if (!isGenericArtifactMimeType(response)) {
    mimeType = response;
  } else if (urlExtension) {
    mimeType = mimeTypeForGeneratedExtension(urlExtension) ?? mimeType;
  }
  const extension = extensionForGeneratedMimeType(mimeType) ?? urlExtension ?? 'bin';
  return { extension, mimeType };
}

function artifactTypeForGeneratedExtension(extension: string): ArtifactRef['type'] {
  switch (extension) {
    case 'mp3':
    case 'ogg':
    case 'wav':
    case 'flac':
    case 'm4a':
    case 'aac':
      return 'audio';
    case 'png':
      return 'png';
    case 'jpg':
      return 'jpg';
    case 'gif':
      return 'gif';
    case 'mp4':
      return 'mp4';
    case 'glb':
      return 'glb';
    case 'obj':
      return 'obj';
    case 'fbx':
      return 'fbx';
    default:
      return 'archive';
  }
}

async function copyExternalArtifact(
  job: GenerationJob,
  sourceUrl: string,
  mimeType = 'application/octet-stream',
  descriptor?: {
    name?: string;
    previewText?: string;
    metadata?: Record<string, unknown>;
    stageId?: GenerationStageId;
    artifactRole?: GenerationArtifactRole;
  },
): Promise<GenerationArtifact> {
  const response = await fetch(sourceUrl);
  if (!response.ok) {
    throw new Error(`Failed to fetch generated asset: ${response.status}`);
  }

  const arrayBuffer = await response.arrayBuffer();
  const artifactId = uuidv4();
  const format = resolveGeneratedArtifactFormat(sourceUrl, mimeType, response.headers.get('content-type') ?? undefined);
  const extension = format.extension;
  const filePath = `artifacts/${job.userId}/${artifactId}.${extension}`;
  let downloadUrl: string | undefined;

  try {
    const activeBucket = await resolvedBucket();
    const file = activeBucket.file(filePath);
    await file.save(Buffer.from(arrayBuffer), {
      contentType: format.mimeType,
      resumable: false,
    });
    [downloadUrl] = await file.getSignedUrl({
      action: 'read',
      expires: Date.now() + 7 * 24 * 60 * 60 * 1000,
    });
  } catch (error) {
    logger.warn('External artifact copy to Storage failed', error);
    downloadUrl = sourceUrl;
  }

  const type = artifactTypeForGeneratedExtension(extension);
  const descriptorName = descriptor?.name?.trim();
  const name = descriptorName
    ? (/\.[a-z0-9]{2,5}$/i.test(descriptorName) ? descriptorName : `${descriptorName}.${extension}`)
    : `${job.kind}-${artifactId}.${extension}`;
  const artifact: GenerationArtifact = {
    id: artifactId,
    type,
    name,
    url: downloadUrl,
    downloadUrl,
    mimeType: format.mimeType,
    stageId: descriptor?.stageId,
    artifactRole: descriptor?.artifactRole,
    storagePath: downloadUrl !== sourceUrl ? filePath : undefined,
    extension,
    previewText: descriptor?.previewText ?? `${job.kind} asset ready for export`,
    metadata: descriptor?.metadata,
  };

  await db.collection('artifacts').doc(artifactId).set({
    ...artifact,
    userId: job.userId,
    jobId: job.id,
    downloadUrl,
    createdAt: new Date().toISOString(),
  });

  return artifact;
}

function timestampToIso(value: unknown): string {
  if (value instanceof Date) {
    return value.toISOString();
  }
  if (value && typeof value === 'object' && 'toDate' in value && typeof (value as { toDate: () => Date }).toDate === 'function') {
    return (value as { toDate: () => Date }).toDate().toISOString();
  }
  return new Date().toISOString();
}

function errorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  return 'Unknown error';
}

