// Weekly Challenges
// ──────────────────────────────────────────────

function computeChallengeStatus(c: {
  startDate: string;
  endDate: string;
  votingEndDate: string;
  status?: string;
}): ChallengeStatus {
  const now = Date.now();
  const start = new Date(c.startDate).getTime();
  const end = new Date(c.endDate).getTime();
  const votingEnd = new Date(c.votingEndDate).getTime();
  if (now < start) return 'upcoming';
  if (now >= start && now < end) return 'active';
  if (now >= end && now < votingEnd) return 'voting';
  return 'completed';
}

function normalizeChallenge(data: Record<string, unknown>, id: string): Challenge {
  return {
    id,
    title: (data.title as string) ?? '',
    description: (data.description as string) ?? '',
    type: (data.type as Challenge['type']) ?? 'game',
    startDate: (data.startDate as string) ?? '',
    endDate: (data.endDate as string) ?? '',
    votingEndDate: (data.votingEndDate as string) ?? '',
    status: computeChallengeStatus({
      startDate: (data.startDate as string) ?? '',
      endDate: (data.endDate as string) ?? '',
      votingEndDate: (data.votingEndDate as string) ?? '',
    }),
    rules: (data.rules as string[]) ?? [],
    prizes: (data.prizes as Challenge['prizes']) ?? [],
    featuredProjectIds: (data.featuredProjectIds as string[]) ?? [],
    winnerIds: (data.winnerIds as string[]) ?? [],
    submissionCount: (data.submissionCount as number) ?? 0,
    createdAt: (data.createdAt as string) ?? new Date().toISOString(),
    updatedAt: (data.updatedAt as string) ?? new Date().toISOString(),
  };
}

app.get('/api/challenges', async (_req: AuthedRequest, res) => {
  try {
    const snapshot = await db.collection('challenges').orderBy('startDate', 'desc').limit(50).get();
    const challenges = snapshot.docs.map((doc) =>
      normalizeChallenge(doc.data() as Record<string, unknown>, doc.id),
    );
    const response: ChallengeListResponse = { challenges };
    return res.json(response);
  } catch (error) {
    logger.error('Fetch challenges failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.get('/api/challenges/:id', async (req: AuthedRequest, res) => {
  try {
    const challengeDoc = await db.collection('challenges').doc(req.params.id).get();
    if (!challengeDoc.exists) {
      return res.status(404).json({ error: 'Challenge not found' });
    }

    const challenge = normalizeChallenge(
      challengeDoc.data() as Record<string, unknown>,
      challengeDoc.id,
    );

    const subsSnapshot = await db
      .collection('challenges')
      .doc(req.params.id)
      .collection('submissions')
      .orderBy('votes', 'desc')
      .limit(100)
      .get();

    const submissions: ChallengeSubmission[] = subsSnapshot.docs.map((doc) => {
      const d = doc.data();
      return {
        id: doc.id,
        challengeId: req.params.id,
        projectId: (d.projectId as string) ?? '',
        userId: (d.userId as string) ?? '',
        authorName: (d.authorName as string) ?? '',
        title: (d.title as string) ?? '',
        description: (d.description as string) ?? '',
        previewUrls: (d.previewUrls as string[]) ?? [],
        votes: (d.votes as number) ?? 0,
        submittedAt: (d.submittedAt as string) ?? '',
      };
    });

    let userSubmission: ChallengeSubmission | undefined;
    let userVotedProjectId: string | undefined;
    const userId = req.userId;
    if (userId && userId !== 'dev-user') {
      userSubmission = submissions.find((s) => s.userId === userId);
      const voteDoc = await db
        .collection('challenges')
        .doc(req.params.id)
        .collection('votes')
        .doc(userId)
        .get();
      if (voteDoc.exists) {
        userVotedProjectId = (voteDoc.data()?.projectId as string) ?? undefined;
      }
    }

    const response: ChallengeDetailResponse = {
      challenge,
      submissions,
      userSubmission,
      userVotedProjectId,
    };
    return res.json(response);
  } catch (error) {
    logger.error('Fetch challenge detail failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.post('/api/challenges/:id/submit', async (req: AuthedRequest, res) => {
  try {
    const userId = req.userId;
    if (!userId || userId === 'dev-user') {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const challengeDoc = await db.collection('challenges').doc(req.params.id).get();
    if (!challengeDoc.exists) {
      return res.status(404).json({ error: 'Challenge not found' });
    }

    const challenge = normalizeChallenge(
      challengeDoc.data() as Record<string, unknown>,
      challengeDoc.id,
    );
    if (challenge.status !== 'active') {
      return res.status(400).json({ error: 'Challenge is not currently accepting submissions' });
    }

    const { projectId } = req.body as { projectId?: string };
    if (!projectId) {
      return res.status(400).json({ error: 'Missing projectId' });
    }

    const existingSnap = await db
      .collection('challenges')
      .doc(req.params.id)
      .collection('submissions')
      .where('userId', '==', userId)
      .limit(1)
      .get();
    if (!existingSnap.empty) {
      return res.status(409).json({ error: 'You have already submitted to this challenge' });
    }

    const postDoc = await db.collection('socialPosts').doc(projectId).get();
    const postData = postDoc.exists ? (postDoc.data() as Record<string, unknown>) : {};

    const submissionId = uuidv4();
    const submission: ChallengeSubmission = {
      id: submissionId,
      challengeId: req.params.id,
      projectId,
      userId,
      authorName: (postData.authorName as string) ?? 'Unknown',
      title: (postData.title as string) ?? 'Untitled',
      description: (postData.description as string) ?? '',
      previewUrls: (postData.previewUrls as string[]) ?? [],
      votes: 0,
      submittedAt: new Date().toISOString(),
    };

    await db
      .collection('challenges')
      .doc(req.params.id)
      .collection('submissions')
      .doc(submissionId)
      .set(submission);

    await db
      .collection('challenges')
      .doc(req.params.id)
      .update({ submissionCount: FieldValue.increment(1), updatedAt: new Date().toISOString() });

    const response: ChallengeSubmitResponse = { submission };
    return res.json(response);
  } catch (error) {
    logger.error('Challenge submit failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

app.post('/api/challenges/:id/vote/:projectId', async (req: AuthedRequest, res) => {
  try {
    const userId = req.userId;
    if (!userId || userId === 'dev-user') {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const challengeDoc = await db.collection('challenges').doc(req.params.id).get();
    if (!challengeDoc.exists) {
      return res.status(404).json({ error: 'Challenge not found' });
    }

    const challenge = normalizeChallenge(
      challengeDoc.data() as Record<string, unknown>,
      challengeDoc.id,
    );
    if (challenge.status !== 'voting') {
      return res.status(400).json({ error: 'Challenge is not currently in voting phase' });
    }

    const voteRef = db
      .collection('challenges')
      .doc(req.params.id)
      .collection('votes')
      .doc(userId);
    const existingVote = await voteRef.get();

    if (existingVote.exists) {
      const previousProjectId = (existingVote.data()?.projectId as string) ?? '';
      if (previousProjectId === req.params.projectId) {
        return res.status(409).json({ error: 'Already voted for this project' });
      }
      const prevSubSnap = await db
        .collection('challenges')
        .doc(req.params.id)
        .collection('submissions')
        .where('projectId', '==', previousProjectId)
        .limit(1)
        .get();
      if (!prevSubSnap.empty) {
        await prevSubSnap.docs[0].ref.update({ votes: FieldValue.increment(-1) });
      }
    }

    const subSnap = await db
      .collection('challenges')
      .doc(req.params.id)
      .collection('submissions')
      .where('projectId', '==', req.params.projectId)
      .limit(1)
      .get();

    if (subSnap.empty) {
      return res.status(404).json({ error: 'Submission not found for this project' });
    }

    await subSnap.docs[0].ref.update({ votes: FieldValue.increment(1) });
    await voteRef.set({ projectId: req.params.projectId, votedAt: new Date().toISOString() });

    const updatedDoc = await subSnap.docs[0].ref.get();
    const totalVotes = (updatedDoc.data()?.votes as number) ?? 0;

    const submissionAuthorId = (subSnap.docs[0].data() as ChallengeSubmission).userId;
    if (submissionAuthorId && submissionAuthorId !== userId) {
      sendPushNotification(
        submissionAuthorId,
        { title: 'New Vote!', body: `Someone voted for your challenge submission` },
        {
          type: 'challenge_vote',
          challengeId: req.params.id,
          projectId: req.params.projectId,
          route: 'challenges',
          screen: 'challenges',
          action: 'open_challenges',
        },
        'challenges',
      ).catch(() => {});
    }

    const response: ChallengeVoteResponse = {
      voted: true,
      projectId: req.params.projectId,
      totalVotes,
    };
    return res.json(response);
  } catch (error) {
    logger.error('Challenge vote failed', error);
    return res.status(500).json({ error: errorMessage(error) });
  }
});

