export const weeklyChallenge = onSchedule(
  { schedule: 'every monday 00:00', region: defaults.region, timeZone: 'UTC' },
  async () => {
    logger.info('Running weekly challenge creator');

    const countSnap = await db.collection('challenges').count().get();
    const totalChallenges = countSnap.data().count;
    const template = CHALLENGE_TEMPLATES[totalChallenges % CHALLENGE_TEMPLATES.length];

    const now = new Date();
    const weekNumber = Math.ceil(totalChallenges + 1);
    const startDate = now.toISOString();
    const endDate = new Date(now.getTime() + 5 * 24 * 60 * 60 * 1000).toISOString();
    const votingEndDate = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString();

    const challengeId = uuidv4();
    const challenge: Challenge = {
      id: challengeId,
      title: `Week ${weekNumber}: ${template.title}`,
      description: template.description,
      type: template.type,
      startDate,
      endDate,
      votingEndDate,
      status: 'active',
      rules: template.rules,
      prizes: template.prizes,
      featuredProjectIds: [],
      winnerIds: [],
      submissionCount: 0,
      createdAt: startDate,
      updatedAt: startDate,
    };

    await db.collection('challenges').doc(challengeId).set(challenge);
    logger.info(`Created weekly challenge: ${challenge.title}`, { challengeId });

    try {
      await getMessaging().send({
        topic: 'challenges',
        notification: {
          title: 'New Weekly Challenge!',
          body: challenge.title,
        },
        data: {
          type: 'new_challenge',
          challengeId,
          route: 'challenges',
          screen: 'challenges',
          action: 'open_challenges',
        },
      });
    } catch (topicErr) {
      logger.warn('Failed to send challenge topic notification', { error: errorMessage(topicErr) });
    }
  },
);

// ──────────────────────────────────────────────
// Scheduled: Tally Votes & Award Winners (daily at 01:00 UTC)
// ──────────────────────────────────────────────

export const tallyChallengeVotes = onSchedule(
  { schedule: 'every day 01:00', region: defaults.region, timeZone: 'UTC' },
  async () => {
    logger.info('Running challenge vote tally');

    const votingSnap = await db
      .collection('challenges')
      .where('status', '==', 'voting')
      .get();

    for (const doc of votingSnap.docs) {
      const data = doc.data() as Record<string, unknown>;
      const challenge = normalizeChallenge(data, doc.id);

      if (challenge.status !== 'completed') continue;

      const subsSnap = await db
        .collection('challenges')
        .doc(doc.id)
        .collection('submissions')
        .orderBy('votes', 'desc')
        .limit(3)
        .get();

      const winnerIds: string[] = [];
      const featuredProjectIds: string[] = [];

      for (const subDoc of subsSnap.docs) {
        const sub = subDoc.data() as ChallengeSubmission;
        winnerIds.push(sub.userId);
        featuredProjectIds.push(sub.projectId);

        const userRef = db.collection('users').doc(sub.userId);
        const userDoc = await userRef.get();
        if (userDoc.exists) {
          const badges: string[] = (userDoc.data()?.badges as string[]) ?? [];
          if (!badges.includes('challenge_winner')) {
            await userRef.update({
              badges: FieldValue.arrayUnion('challenge_winner'),
              updatedAt: new Date().toISOString(),
            });
          }
        }
      }

      await doc.ref.update({
        status: 'completed',
        winnerIds,
        featuredProjectIds,
        updatedAt: new Date().toISOString(),
      });

      for (const winnerId of winnerIds) {
        sendPushNotification(
          winnerId,
          { title: 'Challenge Results!', body: `Congratulations! You won the challenge: ${challenge.title}` },
          {
            type: 'challenge_winner',
            challengeId: doc.id,
            route: 'challenges',
            screen: 'challenges',
            action: 'open_challenges',
          },
          'challenges',
        ).catch(() => {});
      }

      logger.info(`Tallied challenge ${doc.id}: winners=${winnerIds.join(',')}`, {
        challengeId: doc.id,
      });
    }
  },
);

