// ──────────────────────────────────────────────
// Scheduled: Roblox catalog trends warmup
// Runs every 25 min (cache TTL is 30 min, so 5 min headroom). Free 100% uptime
// alternative to a paid Apify-actor subscription. Per-category errors are
// swallowed — one Roblox 429 must not abort the whole run.
// ──────────────────────────────────────────────

// Phase G (session 219): warm BOTH cache-key sizes —
//   - limit=10 used by iOS (TrendingRobloxStrip default + Catalog sheet)
//   - limit=6  used by /api/content/generate showcase (Phase 0+A)
// Cache keys include limit, so warming only one would leave the other cold.
const WARMUP_CATEGORIES: CatalogCategory[] = ['Featured', 'Animations', 'Decals', 'Collectibles'];
const WARMUP_LIMITS = [10, 6];

export const warmupRobloxTrends = onSchedule(
  {
    schedule: 'every 25 minutes',
    region: defaults.region,
    timeZone: 'UTC',
    timeoutSeconds: 540,
    memory: '512MiB',
    secrets: secretParams,
  },
  async () => {
    logger.info('Scheduled: warming up Roblox catalog trends cache');
    const startedAt = Date.now();
    let success = 0;
    let failed = 0;
    const totalQueries = WARMUP_CATEGORIES.length * WARMUP_LIMITS.length;
    for (const category of WARMUP_CATEGORIES) {
      for (const limit of WARMUP_LIMITS) {
        try {
          const result = await fetchTrendingCatalog({ category, sort: 'Sales', period: 'PastWeek', limit });
          logger.info('warmup-roblox-trends category ok', {
            category, limit, source: result.source, items: result.items.length, cached: result.cached,
          });
          success += 1;
          // Phase F (session 228): persist hourly snapshot for timeseries velocity.
          // Idempotent within hour-bucket (overwrites). Failures swallowed inside.
          if (!result.cached) {
            const snap = await persistTrendsSnapshot(result, {
              category, sort: 'Sales', period: 'PastWeek', limit,
            });
            if (snap.persisted) {
              logger.info('warmup-roblox-trends snapshot persisted', { docId: snap.docId });
            }
          }
        } catch (err) {
          logger.warn('warmup-roblox-trends category failed', {
            category, limit, error: err instanceof Error ? err.message : String(err),
          });
          failed += 1;
        }
      }
    }
    // Phase B (session 226): warm Rolimons trending GAMES cache too. Two
    // limits — 20 (iOS Home strip default) and 50 (Catalog sheet / search).
    for (const gamesLimit of [20, 50]) {
      try {
        const r = await fetchTrendingGames(gamesLimit);
        logger.info('warmup-roblox-games ok', {
          limit: gamesLimit, source: r.source, games: r.games.length, cached: r.cached,
        });
        success += 1;
      } catch (err) {
        logger.warn('warmup-roblox-games failed', {
          limit: gamesLimit, error: err instanceof Error ? err.message : String(err),
        });
        failed += 1;
      }
    }
    logger.info('warmup-roblox-trends complete', {
      success, failed, total: totalQueries + 2, ms: Date.now() - startedAt,
    });
  },
);

/**
 * Admin HTTP endpoint: manually trigger a day of bot activity.
 * POST /api/admin/simulate-day
 * Useful for development and backfilling activity.
 */
/**
 * Admin HTTP endpoint: seed 100 bot users into Firestore.
 * POST /api/admin/seed-bots
 * Run this once after deployment to populate the bot pool.
 */
app.post('/api/admin/seed-bots', async (req, res) => {
  const token =
    (req.query.token as string | undefined) ??
    req.headers.authorization?.replace('Bearer ', '');

  if (!getAllowUnauthenticatedRequests() && !token) {
    res.status(401).json({ error: 'Unauthorized. Provide ?token= or Authorization header.' });
    return;
  }

  try {
    logger.info('Manual seed-bots triggered');
    const result = await seedSocialData();
    res.json({ success: true, ...result });
  } catch (err) {
    logger.error('seed-bots failed', err);
    res.status(500).json({ error: String(err) });
  }
});

