/**
 * Admin HTTP endpoint: rewrite DiceBear avatar URLs from /svg → /png.
 * Needed because iOS UIImage(data:) cannot decode SVG, so all bot avatars
 * fall back to letter placeholders. One-shot migration — safe to re-run.
 * POST /api/admin/migrate-avatars
 */
app.post('/api/admin/migrate-avatars', async (req, res) => {
  const token =
    (req.query.token as string | undefined) ??
    req.headers.authorization?.replace('Bearer ', '');

  if (!getAllowUnauthenticatedRequests() && !token) {
    res.status(401).json({ error: 'Unauthorized. Provide ?token= or Authorization header.' });
    return;
  }

  const rewriteUrl = (url: string | undefined | null): string | null => {
    if (!url || typeof url !== 'string') return null;
    if (!url.includes('api.dicebear.com/7.x/pixel-art/svg')) return null;
    let next = url.replace('/pixel-art/svg', '/pixel-art/png');
    if (!/[?&]size=/.test(next)) {
      next += (next.includes('?') ? '&' : '?') + 'size=128';
    }
    return next;
  };

  try {
    const db = getFirestore();
    let profilesUpdated = 0;
    let postsUpdated = 0;
    let commentsUpdated = 0;

    // --- socialProfiles ---
    const profilesSnap = await db.collection('socialProfiles').get();
    for (let i = 0; i < profilesSnap.docs.length; i += 400) {
      const batch = db.batch();
      let n = 0;
      for (const doc of profilesSnap.docs.slice(i, i + 400)) {
        const next = rewriteUrl(doc.get('avatarUrl'));
        if (next) {
          batch.update(doc.ref, { avatarUrl: next });
          n++;
        }
      }
      if (n > 0) await batch.commit();
      profilesUpdated += n;
    }

    // --- socialPosts (authorAvatarUrl) ---
    const postsSnap = await db.collection('socialPosts').get();
    for (let i = 0; i < postsSnap.docs.length; i += 400) {
      const batch = db.batch();
      let n = 0;
      for (const doc of postsSnap.docs.slice(i, i + 400)) {
        const next = rewriteUrl(doc.get('authorAvatarUrl'));
        if (next) {
          batch.update(doc.ref, { authorAvatarUrl: next });
          n++;
        }
      }
      if (n > 0) await batch.commit();
      postsUpdated += n;
    }

    // --- comments subcollection under each post ---
    for (const postDoc of postsSnap.docs) {
      const commentsSnap = await postDoc.ref.collection('comments').get();
      if (commentsSnap.empty) continue;
      for (let i = 0; i < commentsSnap.docs.length; i += 400) {
        const batch = db.batch();
        let n = 0;
        for (const doc of commentsSnap.docs.slice(i, i + 400)) {
          const next = rewriteUrl(doc.get('authorAvatarUrl'));
          if (next) {
            batch.update(doc.ref, { authorAvatarUrl: next });
            n++;
          }
        }
        if (n > 0) await batch.commit();
        commentsUpdated += n;
      }
    }

    logger.info('migrate-avatars complete', { profilesUpdated, postsUpdated, commentsUpdated });
    res.json({ success: true, profilesUpdated, postsUpdated, commentsUpdated });
  } catch (err) {
    logger.error('migrate-avatars failed', err);
    res.status(500).json({ error: String(err) });
  }
});
